-- Poems batch 226
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8c4e0946-5ba9-42aa-8883-cc784e030fcd','示本上座','釋心月','宋','宋诗','song-poetry','','[]','勿遊鱼魯刁刀市，莫逐千干十卜人。',32,'全唐诗/poet.song.208000.json','["勿遊鱼魯刁刀市，莫逐千干十卜人。", "他日有緣重會面，金毛獅子要嚬呻。"]'),
('58854ae5-027e-4c4f-b5b4-bacc12ac14f8','送李道士','釋心月','宋','宋诗','song-poetry','','[]','細探道德五千字，字字君家說底書。',32,'全唐诗/poet.song.208000.json','["細探道德五千字，字字君家說底書。", "要識玄之又玄旨，淡然清對了無餘。"]'),
('631a0def-efb6-416d-8b24-f15f4017dde7','送圭維那','釋心月','宋','宋诗','song-poetry','','[]','年來箇事带誵訛，十卜千干不較多。',32,'全唐诗/poet.song.208000.json','["年來箇事带誵訛，十卜千干不較多。", "狹路相逢略擡手，看伊眼腦是如何。"]'),
('7ddb2b57-1974-4f7c-b2b2-f3044bd5c245','送光典座','釋心月','宋','宋诗','song-poetry','','[]','辣辣辛辛一味禪，慣常豈在杓頭邊。',32,'全唐诗/poet.song.208000.json','["辣辣辛辛一味禪，慣常豈在杓頭邊。", "一千五百善知識，未出門時話已圓。"]'),
('ffa4a679-c5ea-4d0b-b689-e3cf86f53592','送真大師','釋心月','宋','宋诗','song-poetry','','[]','戴起還同放下時，好觀實際訪俱胝。',32,'全唐诗/poet.song.208000.json','["戴起還同放下時，好觀實際訪俱胝。", "至今五百年來下，一段風光付與誰。"]'),
('af873cfe-6271-465f-93a9-ceece2103bc4','送心浄頭','釋心月','宋','宋诗','song-poetry','','[]','處塵勞界住深禪，幾度悲心碎復圓。',32,'全唐诗/poet.song.208000.json','["處塵勞界住深禪，幾度悲心碎復圓。", "得失是非都放下，頭頭皆我舊山川。"]'),
('ca1c3298-1404-46af-994f-012acaec6e20','行者智江歸廬山乞頌','釋心月','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','庭前荒草正萋萋，却憶丹霞剗去時。',32,'全唐诗/poet.song.208000.json','["庭前荒草正萋萋，却憶丹霞剗去時。", "蓮社峰高相見了，回來却把聖僧騎。"]'),
('a2be8191-5ced-4c27-8238-430c5c732cbb','添藏經施主水陸陞座說偈','釋心月','宋','宋诗','song-poetry','','[]','大悲心上流出底，呼爲切脚若爲評。',64,'全唐诗/poet.song.208000.json','["大悲心上流出底，呼爲切脚若爲評。", "不知切脚什麽字，寫不成兮呼不成。", "依依稀稀如半月，髣髣髴髴若三星。", "分付老昭諸善士，生生世世壽康寧。"]'),
('ed407aa1-96d2-403c-ad76-6c093cd3d1bd','容大師水陸陞座說偈','釋心月','宋','宋诗','song-poetry','','[]','末山一境不露頂，直下全超五障身。',64,'全唐诗/poet.song.208000.json','["末山一境不露頂，直下全超五障身。", "佛國無邊皆自己，臺山大會付何人。", "苾蒭草碧枝枝秀，菡萏花紅葉葉新。", "外祖深恩只者是，一菴和氣暖於春。"]'),
('db5280a9-adf9-433a-99c3-4f4247df681e','如行新戒落髮升座','釋心月','宋','宋诗','song-poetry','','[]','患累資生無有涯，選官選佛學丹霞。',64,'全唐诗/poet.song.208000.json','["患累資生無有涯，選官選佛學丹霞。", "須知髮剗殿前草，不礙萱開堂北花。", "萬法從心心是正，一心逐物物皆邪。", "夜窗寂寂青松下，究徹根源始到家。"]'),
('5f8408e9-70b5-4534-a634-aec872a538a1','勸請首座掛牌上堂','釋心月','宋','宋诗','song-poetry','','[]','三春去向那邊去，九夏來從屋力來。',65,'全唐诗/poet.song.208000.json','["三春去向那邊去，九夏來從屋力來。", "一喝兩頭俱坐斷，人天眼目與誰開。", "烏飛兔走，地轉天回，時有清風匝九垓。", "寒山子滿頭灰，引得豐干笑滿腮。"]'),
('7a2254c1-882f-4932-9587-d406a12317ee','偈','釋心月','宋','宋诗','song-poetry','','[]','善惡不思，名爲頂句。',58,'全唐诗/poet.song.208000.json','["善惡不思，名爲頂句。", "內外絕依，名爲得住。", "時時寂寂惺惺，時時退步薦取。", "如是三十年，覓之總無處。", "覓無處，贏得雙眉時陡聚。"]'),
('675338cc-2ae1-415e-a7ee-f0289703dc95','頌古三首  其一','釋心月','宋','宋诗','song-poetry','','[]','日永風清，雷奔電卷。',36,'全唐诗/poet.song.208000.json','["日永風清，雷奔電卷。", "無位真人，略通一線。", "急須著眼看仙人，莫看仙人手中扇。"]'),
('85d5e11f-2022-4dd6-87a4-31c7ecc19b11','頌古三首  其二','釋心月','宋','宋诗','song-poetry','','[]','百年將底作津梁，直指心田是道場。',36,'全唐诗/poet.song.208000.json','["百年將底作津梁，直指心田是道場。", "八萬四千安樂法，只於此處（指胸）可承當。"]'),
('749a05b0-4b8b-4a9e-a967-2dda6e979da3','頌古三首  其三','釋心月','宋','宋诗','song-poetry','','[]','沒便宜處討便宜，無位真人小廝兒。',32,'全唐诗/poet.song.208000.json','["沒便宜處討便宜，無位真人小廝兒。", "如是去來如是住，無時不是在家時。"]'),
('cebe5330-f4ae-4bb5-808e-b9be04d3788b','出山相贊','釋心月','宋','宋诗','song-poetry','','[]','棄却金輪尊貴人，要來平地討艱辛。',32,'全唐诗/poet.song.208000.json','["棄却金輪尊貴人，要來平地討艱辛。", "如斯面目塵埃甚，更說優曇別是春。"]'),
('e7ed38c4-b13c-4285-b3e5-d2ff6bcc81e2','草衣文殊贊','釋心月','宋','宋诗','song-poetry','','[]','披草衣，執具書。',32,'全唐诗/poet.song.208000.json','["披草衣，執具書。", "面不洗，頭不梳。", "是文殊，非文殊。", "擬議臺山路轉迂。"]'),
('e3c9111a-6cc8-48c5-ba78-3ef200c33811','馬郎婦贊','釋心月','宋','宋诗','song-poetry','','[]','願海散香風，花披菡萏紅。',24,'全唐诗/poet.song.208000.json','["願海散香風，花披菡萏紅。", "錦鱗方上釣，金鎖已騰空。"]'),
('664c48da-3086-48ac-a128-e82da6ec6d53','自在觀音贊','釋心月','宋','宋诗','song-poetry','','[]','日高花影重，風暖鳥聲碎。',40,'全唐诗/poet.song.208000.json','["日高花影重，風暖鳥聲碎。", "在在圓通門，門門觀自在。", "寶陀峰頂較些些，片月分輝照滄海。"]'),
('e43396f2-7762-4ec5-8a69-0b46ddd4a195','泛蓮觀音贊','釋心月','宋','宋诗','song-poetry','','[]','一葉蓮舟泛渺瀰，誦觀音也戴阿彌。',32,'全唐诗/poet.song.208000.json','["一葉蓮舟泛渺瀰，誦觀音也戴阿彌。", "希奇妙相毫端上，五濁衆生知未知。"]'),
('cfe33f7a-f167-4447-8ba1-c3d4e5e621e4','藕絲觀音贊','釋心月','宋','宋诗','song-poetry','','[]','頂戴阿彌，不假花冠之纍纍。',68,'全唐诗/poet.song.208000.json','["頂戴阿彌，不假花冠之纍纍。", "肩披藕絲，不必瓔珞之垂垂。", "孤然不倚，儼然若思。", "我於一十九類三十二應身中次第觀之，而無如是抱膝安閑大自在之風規。"]'),
('6815b8d2-77f2-4b18-afac-8f4720df40dc','布袋贊','釋心月','宋','宋诗','song-poetry','','[]','矬而肥，肥而癡。',34,'全唐诗/poet.song.208000.json','["矬而肥，肥而癡。", "肩駝背負，或徐或馳。", "回頭處，微笑時，此意明明說向誰。"]'),
('febf56a8-8709-4c5a-b1ff-3ee735035487','達磨祖師贊','釋心月','宋','宋诗','song-poetry','','[]','跨水行人語不符，絕江足踏一莖蘆。',32,'全唐诗/poet.song.208000.json','["跨水行人語不符，絕江足踏一莖蘆。", "此時獨自棲棲去，今日人將入畫圖。"]'),
('6ffcc22f-d7e6-4254-be1f-5d407a0784d2','小師正知畫師頂相請贊','釋心月','宋','宋诗','song-poetry','','[]','高厚同源，萬殊一體。',50,'全唐诗/poet.song.208000.json','["高厚同源，萬殊一體。", "卓爾何來，湛然非止。", "覽蜀天雲，挹龍淵水。", "際會如斯，孰窮所以。", "正知知之，不出乎是。"]'),
('e2a8be1e-4d00-4016-b3ce-a3af6ae3e49c','頌古二十一首  其一','釋心月','宋','宋诗','song-poetry','','[]','兄難兄，弟難弟。',32,'全唐诗/poet.song.208000.json','["兄難兄，弟難弟。", "馬祖真，只這是。", "撼動西江十八灘，水面無風波自起。"]'),
('01b9d46e-7773-441d-9448-2ff4547e41aa','頌古二十一首  其二','釋心月','宋','宋诗','song-poetry','','[]','各呈見解，互逞機鋒。',58,'全唐诗/poet.song.208000.json','["各呈見解，互逞機鋒。", "石火莫及，電光罔通。", "拋下拄杖而立，不同草草。", "拈起拄杖便行，亦豈匆匆。", "者裏著得隻眼，許你親見龐公。"]'),
('3bf381cc-9e14-42e4-b20f-251b9ee5372f','頌古二十一首  其三','釋心月','宋','宋诗','song-poetry','','[]','昨日與今日，同中却不同。',48,'全唐诗/poet.song.208000.json','["昨日與今日，同中却不同。", "獰龍攪滄海，俊鶻摩青空。", "宗眼明如日，機輪疾似風。", "丹霞回首處，遍界覓無蹤。"]'),
('4da500b8-6cf9-4cc3-a7e9-be150dc3ed84','頌古二十一首  其四','釋心月','宋','宋诗','song-poetry','','[]','第一句，言不及。',62,'全唐诗/poet.song.208000.json','["第一句，言不及。", "見利忘錐，何得何失。", "拈起放下，翹足而立。", "文殊維摩，鎗箭交擊。", "果不可當，一掌推出。", "縱是舜若多神，額頭也須汗出。"]'),
('a505d3b8-5bf1-451c-86fd-0d12f625f531','頌古二十一首  其五','釋心月','宋','宋诗','song-poetry','','[]','普濟把定，被龐公痛處一錐。',53,'全唐诗/poet.song.208000.json','["普濟把定，被龐公痛處一錐。", "直得左轉右側，前依後隨。", "笊籬提起處，相呼作舞時。", "若言依樣畫貓兒，定把黄金鑄子期。"]'),
('6f985932-21ea-46b7-a6c0-0c40968bb8b3','頌古二十一首  其六','釋心月','宋','宋诗','song-poetry','','[]','識得子丑寅卯句，應須繼紹此門風。',32,'全唐诗/poet.song.208000.json','["識得子丑寅卯句，應須繼紹此門風。", "如王仗劍當堂坐，佛魔俱拂一時空。"]'),
('b6ef7d0f-a2c4-47b5-a62b-67751e4f3da2','頌古二十一首  其七','釋心月','宋','宋诗','song-poetry','','[]','宗門中令嗣，合眼坐禪處。',48,'全唐诗/poet.song.208000.json','["宗門中令嗣，合眼坐禪處。", "平地打毬子，急須著眼覷。", "兩挑挑得上，三築築不住。", "築得住依前，輥向毬門去。"]'),
('ccd67727-c424-4010-9f4f-49a7b067a69f','頌古二十一首  其八','釋心月','宋','宋诗','song-poetry','','[]','野火炎炎何處起，紫烟紅焰便燒人。',32,'全唐诗/poet.song.208000.json','["野火炎炎何處起，紫烟紅焰便燒人。", "須知坐卧經行裏，見得無殊用得親。"]'),
('a04107a4-2bac-4043-a2b8-376d3221648f','頌古二十一首  其九','釋心月','宋','宋诗','song-poetry','','[]','前溪綠漲雨初晴，浮笠波心掌樣平。',32,'全唐诗/poet.song.208000.json','["前溪綠漲雨初晴，浮笠波心掌樣平。", "伎倆由來祇如此，放教急急奔前程。"]'),
('311304ca-1ba3-4b00-8014-977f834e1232','頌古二十一首  其一○','釋心月','宋','宋诗','song-poetry','','[]','也大奇，也大奇，卷舒出沒看全機。',32,'全唐诗/poet.song.208000.json','["也大奇，也大奇，卷舒出沒看全機。", "若非鑑物張華眼，未免隨人說是非。"]'),
('4c244c7e-acba-4b44-9e66-ad22a139f265','頌古二十一首  其一一','釋心月','宋','宋诗','song-poetry','','[]','聖量凡情浄盡時，轉身無路事還非。',32,'全唐诗/poet.song.208000.json','["聖量凡情浄盡時，轉身無路事還非。", "屋簷下過粟畬裏，馬腹馿胎一道歸。"]'),
('4a8495fd-972e-4ab9-956f-0058a46d3221','頌古二十一首  其一二','釋心月','宋','宋诗','song-poetry','','[]','自家冷暖自家知，祖意西來更問誰。',32,'全唐诗/poet.song.208000.json','["自家冷暖自家知，祖意西來更問誰。", "全體承當全體是，須彌頂上戴須彌。"]'),
('43bb3715-1f8a-4730-8850-0954be85ed1f','頌古二十一首  其一三','釋心月','宋','宋诗','song-poetry','','[]','不壞身正是，正是不壞身。',24,'全唐诗/poet.song.208000.json','["不壞身正是，正是不壞身。", "適來曲多少，扭得鼻頭辛。"]'),
('3cfda37a-4ec1-4e16-9a77-e8cb956723ed','頌古二十一首  其一四','釋心月','宋','宋诗','song-poetry','','[]','巨岳何曾乏寸土，演若迷頭狂未回。',32,'全唐诗/poet.song.208000.json','["巨岳何曾乏寸土，演若迷頭狂未回。", "參尋喜有得力句，突曉途中眼未開。"]'),
('ae991eb8-f504-4a1a-9318-986ca95d75ae','頌古二十一首  其一五','釋心月','宋','宋诗','song-poetry','','[]','最好韶山境，烟籠翠色輕。',24,'全唐诗/poet.song.208000.json','["最好韶山境，烟籠翠色輕。", "欲描描未就，猿鳥一聲聲。"]'),
('dc44a4dd-be5d-4841-aedc-242871ff7922','頌古二十一首  其一六','釋心月','宋','宋诗','song-poetry','','[]','鏡清湖心拋一餌，錦鱗躍浪上鈎來。',32,'全唐诗/poet.song.208000.json','["鏡清湖心拋一餌，錦鱗躍浪上鈎來。", "幾乎掣斷竿頭線，引得傍觀下釣臺。"]'),
('98b0bc50-c8c7-44f7-b825-deff346fa128','頌古二十一首  其一七','釋心月','宋','宋诗','song-poetry','','[]','國師樣子太慈悲，入草何如出草時。',32,'全唐诗/poet.song.208000.json','["國師樣子太慈悲，入草何如出草時。", "射透九重聖箭子，依前特地隔天涯。"]'),
('8d4ec5f5-b47d-41c3-bcf6-fabc75701add','頌古二十一首  其一八','釋心月','宋','宋诗','song-poetry','','[]','奇特老尊宿，大無慚愧人。',24,'全唐诗/poet.song.208000.json','["奇特老尊宿，大無慚愧人。", "盤陀石上藕，喜見一番新。"]'),
('4a630831-5502-411b-ac2d-f57ab05d50bc','頌古二十一首  其一九','釋心月','宋','宋诗','song-poetry','','[]','渾崙拈起好風規，石火明明已較遲。',32,'全唐诗/poet.song.208000.json','["渾崙拈起好風規，石火明明已較遲。", "不落金峰窠窟裏，會須赤手討便宜。"]'),
('1445f8d2-9d82-4400-812a-61f6f489fa45','頌古二十一首  其二○','釋心月','宋','宋诗','song-poetry','','[]','是身土木無知漢，忍痛聲中一皺眉。',32,'全唐诗/poet.song.208000.json','["是身土木無知漢，忍痛聲中一皺眉。", "好是南山射石虎，縱饒沒羽亦徒爲。"]'),
('ec699525-236d-4847-800c-ea5d36d95d8a','頌古二十一首  其二一','釋心月','宋','宋诗','song-poetry','','[]','龍起滄海，虎出林端。',20,'全唐诗/poet.song.208000.json','["龍起滄海，虎出林端。", "直下來也，急著眼看。"]'),
('c9bc1c8f-ba7e-4a74-a259-0f1a9c3708d9','黄鶴樓歌','周弼','宋','宋诗','song-poetry','','[]','城上危樓高縹緲，城下澄江復相繞。',128,'全唐诗/poet.song.208000.json','["城上危樓高縹緲，城下澄江復相繞。", "有時漾影入中流，俯看游魚仰飛鳥。", "近樓多少未行舟，滿江落花灑汀洲。", "人同江狎不怕浪，登樓對酒彈箜篌。", "大別山頭白雲起，金口渡邊雨如洗。", "半鈎新月上孤城，還照高樓與江水。", "晴江依舊瀉潯陽，黄鶴無由歸故鄉。", "一聲玉笛起何處，燕撲闌干花影長。"]'),
('a27dd3ab-20b8-4983-9d56-f71af876eb36','韜光庵','周弼','宋','宋诗','song-poetry','','[]','谷鳥與我言，怨殺白太傅。',156,'全唐诗/poet.song.208000.json','["谷鳥與我言，怨殺白太傅。", "借問何以然，携却山僧去。", "山僧未去時，前盤一尾蛇，後踞一頭虎，吸雲嘯風遶窗戶。", "山僧已去了，鶴來踏翻藤。", "猿到拗折樹，亂篠枯柴塞行路。", "抑將廬于嵩高之陽，溫洛之滸，諸天散花復呵護。", "抑將慕羶逐臭，亡魂喪魄，委枯骸於北邙之狐兔。", "荒臺兮尚存，破屋兮如故，惟有山僧不知處。", "世間萬事誰始終，極目寒江起煙霧。"]'),
('25aa3b5f-bae7-4c44-864e-8ba93f0e4cbc','牡丹','周弼','宋','宋诗','song-poetry','','[]','江南牡丹凡有幾，德安打頭歙爲二。',256,'全唐诗/poet.song.208000.json','["江南牡丹凡有幾，德安打頭歙爲二。", "金陵舊物間有之，池陽吳郡皆居次。", "地近京畿種偏好，鄂城栽接不草草。", "舂土篩泥繞畫欄，石甃方壇浄如掃。", "當頭第一带鞓紅，膩紫嬌黄別作叢。", "盤盂擎出最迎日，碧玉萬片藏春風。", "寶葉絲絲带縷金，錦斑酒暈間攢心。", "翻騰梔茜亂朱粉，樣各數名分淺深。", "低樹猶高五六尺，花重剛枝反無力。", "迥出層陰轉耐看，始悟年深有真色。", "晚添細雪來相簇，露醒香魂冷方浴。", "倚柱黄昏眼倍明，頓覺夜闌須秉燭。", "洛水芳林應更多，不禁飛雨洗銅駝。", "酥煎送酒有人在，草沒故園無柰何。", "莫對餘春起嘆嗟，最難保守是繁華。", "君看南渡百年內，看到子孫能幾家。"]'),
('3d5582c3-c75a-43af-8e49-634f99a7676c','戴式之垂訪村居','周弼','宋','宋诗','song-poetry','','[]','故人手持一緘書，扁舟清晨造我廬。',395,'全唐诗/poet.song.208000.json','["故人手持一緘書，扁舟清晨造我廬。", "爲問舟從何方來，欲應未應先長吁。", "長安平旦朱門開，曳裾靸履喧春雷。", "獨有詩人貨難售，朔雪寒風常滿袖。", "孤館青燈不自聊，短帽鶉衣競相就。", "獬豸峨冠豈無事，不觸姦邪觸詩士。", "雖當聖世尚寬容，滔滔寧免言爲諱。", "軒瑟齊竽本難遇，長編巨軸添憂慮。", "松菊荒蕪歸計遲，欲向何門誦佳句。", "君不見古者防川不禁口，里諺村謠無不有。", "美刺箴規三百篇，刪取皆經聖人手。", "漢魏著述充層雲，采擷花草香紛紛。", "其間國政最親切，世許少陵能愛君。", "交衢謗木求胥誨，盛若勛華猶不改。", "風雅遺音儻尚存，篇篇遒鐸皆應採。", "小人幾度邪侵正，何嘗斷隔無歌詠。", "風雨蕭蕭雞自鳴，誰顧寒莎響蛙黽。", "但恐君詩未工耳，工則奚愁强疵毀。", "益藉譏評達九重，送起聲名赤霄裏。", "况於時事無交涉，仿郊寒山題木葉。", "千齡得失寸心知，笑爾隨群走干謁。", "請君頭上巾，爲君抖却岐路塵。", "解君身上衣，爲君拂去京洛緇，三濯三洗清泠池。", "一日失機械，二日忘是非，三日天籟呼吸吹。"]'),
('94de88f1-d78e-4f28-b7fe-8420c17f24f6','將適毗陵道中遇居簡上人','周弼','宋','宋诗','song-poetry','','[]','姑蘇觀下逢居簡，帽子欹斜衣懶散。',160,'全唐诗/poet.song.208000.json','["姑蘇觀下逢居簡，帽子欹斜衣懶散。", "自言契闊漫東西，雖老猶能青白眼。", "知音不在禪床久，抱刺懷書謹奔走。", "反舌無聲亂草間，回首盡成獅子吼。", "荒蕪野寺孤城外，赤葉黄蘆日相對。", "午睡雙鳩喚欲醒，起傍生臺炙肩背。", "弄筆濡毫總蕭索，尚餘酒量添於昨。", "語盡橫塘笛未終，東風滿面楊花落。", "匆匆解纜攙程去，從此相期更何處。", "一碗官酤般若湯，把手同看獨孤樹。"]'),
('de4371f7-9346-429b-b323-1148dbf58b25','鄱陽湖','周弼','宋','宋诗','song-poetry','','[]','鄱陽湖浸東南境，有人曾量三十六萬頃。',144,'全唐诗/poet.song.208000.json','["鄱陽湖浸東南境，有人曾量三十六萬頃。", "我昔乘槎渤澥間，眇視天溟坎蛙井。", "浪何爲而起於青雲之底，日何爲而碎於泥沙之裏。", "太極初分一物無，天水相包若雞子。", "揚瀾可供李白青州杓，彭蠡付與盧敖洗龜殻。", "斗大孤山沒處藏，斸取來搘鼎鐺脚。", "胸中八九吞雲夢，似此蹄涔亦何用。", "安得快意大荒之東東復東，指麾魚鼈騎蒼龍。"]'),
('3c643130-2b0b-495b-a4a0-cf3756ea0a1b','靈巖上方','周弼','宋','宋诗','song-poetry','','[]','嵯峨樓觀青山頭，昔曾避暑離宮遊。',160,'全唐诗/poet.song.208000.json','["嵯峨樓觀青山頭，昔曾避暑離宮遊。", "吳王旌旆墮冥漠，至今古木涵清秋。", "誰聽白紵歌聲接，細撲飛塵石榴葉。", "銀燭吹灰別淚殘，夜半虛廊響行屧。", "美人何處凝嬌魂，五色定化蝴蝶翻。", "幾人深閨有餘怨，當晝巨櫟號驚猿。", "千年惟見春風在，綠草雖存顔色改。", "寂寞欄干繞斷腸，滿徑寒香不堪採。", "朝雲爲我光徘徊，須臾徑入姑蘇臺。", "遺蹤滅跡竟難望，葉落空林歸鳥哀。"]'),
('a39b86aa-011e-475c-baf5-bbaa287a1605','菰菜','周弼','宋','宋诗','song-poetry','','[]','江邊野灘多老菰，抽心作穗秋滿湖。',160,'全唐诗/poet.song.208000.json','["江邊野灘多老菰，抽心作穗秋滿湖。", "拂開細穀芒敷舒，中有一米連三稃。", "剖之粒粒皆尖小，整齊遠過占城稻。", "不煩舂簸即晨炊，更勝青精顔色好。", "尋常艱得此欣逢，默計五升當百叢。", "雨多水長倍加益，十里定收三十鍾。", "野人獲之亦自足，何用虛靡太倉粟。", "連日秋風思故鄉，况復家田有茅屋。", "墜網重腮鱸已鮮，蓴絲牽葉又流涎。", "急歸收穫蘋溪畔，細撥蘆花撐釣船。"]'),
('86bc4f57-d740-4eac-a059-30f5733628b6','海棠','周弼','宋','宋诗','song-poetry','','[]','海棠最佳須老叢，遠及百年花始紅。',144,'全唐诗/poet.song.208000.json','["海棠最佳須老叢，遠及百年花始紅。", "歷看名葩此爲盛，剛柯硬葉交相映。", "倚石攢青二三丈，雨膏倒吸胭脂上。", "仿佛璇霄發曙光，細族蓬萊綉旗仗。", "露欲收珠色轉深，香玉萬顆藏春陰。", "輕風欲透紫絲障，一片朝霞傾入林。", "鳳城多少栽花處，低嫩俱無可觀樹。", "相對令人憶故山，年年雕萼掃朱欄。", "只今惟有溪童在，應放高枝棲白鷴。"]'),
('fd2d0cab-2096-4823-8083-1d08022d51fb','吳王試劍石','周弼','宋','宋诗','song-poetry','','[]','吳王鑄劍成，自謂古難比。',68,'全唐诗/poet.song.208000.json','["吳王鑄劍成，自謂古難比。", "試之高山巔，石裂斷橫理。", "那無昔時人，相逢干將里。", "故宮宮中白日長，春風野田百草香。", "有誰慷慨不平事，被褐踏花推酒缸。"]'),
('f17f7c0d-6694-4cb0-87bb-f6ce96bbb1fd','煙波亭避暑','周弼','宋','宋诗','song-poetry','','[]','澄江橫匹練，月洗黄羅扇。',128,'全唐诗/poet.song.208000.json','["澄江橫匹練，月洗黄羅扇。", "捲盡白雲衣，常星撒沙見。", "天低欲就人，夜色凝深淀。", "欻吸動微光，時絣斗間線。", "凉亭逼曠野，軒楹敞三面。", "萬象悉鋪陳，隨機互遷變。", "十歲逃虛空，得此方一遍。", "相對坐談玄，終宵亦無倦。", "只恐駸駸催曉箭，湧上東方老銅片。", "須著干求大帝君，莫使陽烏眼睛轉。"]'),
('e0660881-e60e-47df-9b35-8631de16c370','禹穴','周弼','宋','宋诗','song-poetry','','[]','若有藏瘞空山中，誰人反閉玉笥峰。',96,'全唐诗/poet.song.208000.json','["若有藏瘞空山中，誰人反閉玉笥峰。", "虎潈不得不啟封，立石繚之應萬重。", "不知靈變從何發，爆然夜半橫分裂。", "但留一線與人窺，未放白雲全漏泄。", "古木蒼藤閉莫開，穴中惟聽走風雷。", "神仙必有便門出，得見飈輪自往來。"]'),
('755a2175-e9a7-402b-a990-b58e96e2ebf7','題葛稚川移家圖','周弼','宋','宋诗','song-poetry','','[]','稚川移家入空谷，手招白雲守茅屋。',128,'全唐诗/poet.song.208000.json','["稚川移家入空谷，手招白雲守茅屋。", "惟恐人窺鍊藥鑪，鎖斷青巒瀉垂瀑。", "只留一徑通飛鳥，其間想透三仙島。", "野童猶摘鳳文梨，村老閑鋤燕胎草。", "人將外物爲真物，反笑山棲衰草窟。", "玉臼丹成兔欲眠，蚯蚓黄蒿幾鑽骨。", "此去世間應不遠，尚存猶可分苔蘚。", "兩幅生綃若可憑，先寄胡麻與雞犬。"]'),
('0a88d889-5463-42be-9001-237059747b05','春濃曲','周弼','宋','宋诗','song-poetry','','[]','雨膏蒸土蘭芽熱，粉魂淡艷凝緗纈。',131,'全唐诗/poet.song.208000.json','["雨膏蒸土蘭芽熱，粉魂淡艷凝緗纈。", "柳條無力受東風，桃葉春江弄花月。", "枕函墜髮昏眠重，綺帳驚寒替花恐。", "屏瑣蟲棲化粉蛾，簾甲蜂鑽抱殘蛹。", "麥門冬長柔堪結，桐輪輾盡棠梨雪。", "門掩車箱銅較閑，瓶敲井榦青絲絕。", "君不見楚王宮中樂酣宴，嫌怕旁人說春晚。", "玉釵埋遍細腰人，章華臺上蒼苔滿。"]'),
('570a9b25-2bc1-4fbd-9329-5cf96e2d6ad7','陸羽泉','周弼','宋','宋诗','song-poetry','','[]','擬酌松根泉，先酹松下土。',48,'全唐诗/poet.song.208000.json','["擬酌松根泉，先酹松下土。", "甌犧副都籃，拾薪自煎煮。", "一盃復一盃，併酌連四五。", "寄謝山中人，腹痛不累汝。"]'),
('2179feec-5aa5-46c5-babd-a49717004509','寓宿黄觀復書堂晨至海棠花下走筆呈蘇召叟','周弼','宋','宋诗','song-poetry','','[]','春風忽來花滿樹，海棠最多繞欄吐。',128,'全唐诗/poet.song.208000.json','["春風忽來花滿樹，海棠最多繞欄吐。", "客愁纔動不復安，兩脚春泥踏春雨。", "高枝背面辭曉喧，低枝濕透揮未乾。", "胭脂深重粉亦殷，顔色滑膩脂肉寒。", "五雲忽卷晨粧畢，曉來姿態俱已失。", "悔不敲門請君出，喫酒忍饑看半日。", "疾呼盃酌傾已遲，但驚野雪掃還飛。", "可能就賜醉眠者，爛嚼落花聽鳥啼。"]'),
('8d5c786a-642b-4cff-8928-4df4193938b7','建寧浦城李頻行祠','周弼','宋','宋诗','song-poetry','','[]','建安梨嶽老梨木，刻作唐朝建州牧。',196,'全唐诗/poet.song.208000.json','["建安梨嶽老梨木，刻作唐朝建州牧。", "香爐忽動吹寒灰，浦城環翠陰風來。", "嶺頭頑石盡能走，澗下奔泉皆倒回。", "猿猱啼兮鬼嘯野，六玄虬兮四驪馬。", "想須吟遶碧草亭，舉手高翻白雲寫。", "峰爲文通名夢筆，楊公書堂曾散帙。", "麗月鮮霞付與誰，煙墅有人還築室。", "田父何所祈，贈爾青麰黑桑椹。", "里儒何所求，贈爾黄糧布囊枕。", "萬歲兮千秋，既往兮復留。", "抽蘭心，拆椒口。", "簸南箕，挹北斗。", "不假竹枝歌，何須折楊柳。", "只用秦原妙絕詞，傳入神絃薦春酒。"]'),
('53a85f06-6eb0-4c6f-829d-c0a6491c982d','五雲門外小亭','周弼','宋','宋诗','song-poetry','','[]','醉中別高峰，揮手謝平野。',48,'全唐诗/poet.song.208000.json','["醉中別高峰，揮手謝平野。", "百里伴啼猿，一官騎惡馬。", "飛花墮城隅，槁葉積亭下。", "從教踐踏去，會有相逢者。"]'),
('a87d9b4d-5aa6-4139-81d1-cf968c3c510f','夏日泛祕湖','周弼','宋','宋诗','song-poetry','','[]','朝來泛舟花滿湖，亭午返棹風相呼。',64,'全唐诗/poet.song.208000.json','["朝來泛舟花滿湖，亭午返棹風相呼。", "已收波浪入菱芡，晚開雲日媚菰蒲。", "羣飛鼓翼數沙雁，一去沒頭雙野鳬。", "少留霽色定堪玩，可惜歸程時已晡。"]'),
('e6c2920c-6297-4a68-ae07-46418fbf59f5','送覺新上人還越','周弼','宋','宋诗','song-poetry','','[]','古越多精藍，名僧遞相接。',48,'全唐诗/poet.song.208000.json','["古越多精藍，名僧遞相接。", "青林瓶盂聚，丹壑樓觀疊。", "今乘秋濤便，莫待寒雨涉。", "何處聞鳴蛩，虛廊掃黄葉。"]'),
('bba7b042-2c2f-4f3a-ad80-0372d9a35faa','琵琶亭','周弼','宋','宋诗','song-poetry','','[]','蕭蕭楓林青，雜出間椅檟。',120,'全唐诗/poet.song.208000.json','["蕭蕭楓林青，雜出間椅檟。", "尚思送行舟，繫此木葉下。", "雲開星垂山，水蕩月在野。", "江空夜棖棖，淚復誰滿把。", "汀洲泥沙換，葭葦顔色假。", "變遷斐然殊，感慨益以寡。", "黄煙飛高桅，絳雪當道灑。", "餘春去不盡，併放湓浦瀉。", "豈無夜深彈，寂寞少聽者。", "尚有沙灘人，時時說司馬。"]'),
('63f32af6-3a44-4bfb-ad24-706daa61dfe8','石鍾寺','周弼','宋','宋诗','song-poetry','','[]','山前削成面，山後不露骨。',192,'全唐诗/poet.song.208000.json','["山前削成面，山後不露骨。", "何人戀巢居，結屋寄突兀。", "多風鎖寒殿，頻雨閉石窟。", "筍透獅子傾，草蔽鴟吻沒。", "髑髏串胡神，纓絡纏古佛。", "熹燈影摧殘，槁柏香蓬馞。", "丹葉夏猶在，綠樹暑未發。", "坳徑鳴秋蛩，閑階起蒼鶻。", "僧衣莓苔侵，齋鉢野菜掘。", "梵庋止數卷，矧能備巾拂。", "奔波道塗間，體倦神屢竭。", "大險阨在前，醉夢魂恍惚。", "信陋獲安處，不勝塵土汩。", "經房晚棲禪，殆亦未易忽。", "鐵鳳終日叫，心頗惡此物。", "欲去欲住間，征帆已超越。"]'),
('6c31b44a-abd0-4a94-bd50-7a6c97f2a68b','喜晴','周弼','宋','宋诗','song-poetry','','[]','久客無別望，出門惟快晴。',192,'全唐诗/poet.song.208000.json','["久客無別望，出門惟快晴。", "茅店局促卧，村靜不打更。", "淅瀝漸有間，四簷稍收聲。", "俯身問僮僕，貪睡語輒驚。", "耳邊嘈囋動，鄰房先戒行。", "拂拭弄包裹，人健脚亦輕。", "溪舂黄糧響，窗掃巨竹傾。", "山路少泥土，意想砂礫平。", "捨夢棄衾枕，披衣散縱橫。", "屈指計道里，陡覺神思清。", "菜老復命煮，小鮮豈足烹。", "旅飯任麤糲，苞苴且難成。", "值雨及雷雹，一阻三宿程。", "南北互有適，後先何必爭。", "東方曉色至，隠隠天漸明。", "分手出門去，相引行水坑。"]'),
('d2d7b624-7de2-47da-8632-f8b5b678961e','櫻桃花','周弼','宋','宋诗','song-poetry','','[]','櫻桃未開花遶枝，櫻桃已開紅滿溪。',64,'全唐诗/poet.song.208000.json','["櫻桃未開花遶枝，櫻桃已開紅滿溪。", "花開幾朝今始見，人折人攀那得知。", "黄鸝飛來問誰主，對面相看隔牆語。", "今日鎖魂事可明，昨夜東風過雲雨。"]'),
('4b205eff-2c02-4d1d-b9c8-1763a9518f06','豐年行','周弼','宋','宋诗','song-poetry','','[]','長田一畝三石收，截茅作囤遮水牛。',80,'全唐诗/poet.song.208000.json','["長田一畝三石收，截茅作囤遮水牛。", "馴雞塞籠彘牢滿，大兒看親女上頭。", "里胥關門罷輸送，晴烏窺簷鼠沿棟。", "瓦盆瓷缶息老身，還將孫子看迎神。", "廟前擘紙青竹爆，餳糕粉魚夜祠竈。"]'),
('49213de1-6d75-4fa0-b376-a07166e31a14','冬賽行','周弼','宋','宋诗','song-poetry','','[]','大巫舞袍奉酒尊，小巫湔裙進盤彘。',112,'全唐诗/poet.song.208000.json','["大巫舞袍奉酒尊，小巫湔裙進盤彘。", "野風吹樹龍馬歸，瓦爐柏根香滿地。", "白衣老鬚撚向前，叉手大膽不敢言。", "去年田家五分熟，更饒三分百事足。", "大繭千棚絲滿窠，栗犢兩握角出肉。", "土臺澆酒再拜辭，紙錢灰撲遶木枝。", "神語順從杯教吉，鼓笛薨薨打三日。"]'),
('8dff7f79-a9cb-4486-83a3-e0ca114af15c','湘東苑','周弼','宋','宋诗','song-poetry','','[]','湘東王好開芳甸，亭臺環繞朱欄遍。',130,'全唐诗/poet.song.208000.json','["湘東王好開芳甸，亭臺環繞朱欄遍。", "就中應教誰最多，庾信江淹日歡宴。", "七十里圍高木柵，花柳燒殘少顔色。", "取次華林建鄴邊，奚不移歸帝王宅。", "曾經行處蘋蕪漫，頼此名存悉歆羨。", "安知飛來不是舊時鶑，舞去都非昔年燕。", "風擘殘桃過短牆，更無人管任斜陽。", "惜春猶有傷心者，認作徐娘半面粧。"]'),
('f0642fdf-6edd-45ad-be6f-0271d37df800','仲宣樓','周弼','宋','宋诗','song-poetry','','[]','仲宣徙倚思歸後，又復誰傳獨步名。',96,'全唐诗/poet.song.208000.json','["仲宣徙倚思歸後，又復誰傳獨步名。", "自昔城闉雖尚在，至今波浪未嘗平。", "半規赤日沈荒渚，一縷黄煙起廢城。", "梅落碎花催塞色，葭橫響葉弄邊聲。", "驚寒牧馬頻回顧，趁暖賓鴻漸北征。", "况乃有懷傷歲暮，登樓那不動鄉情。"]'),
('24bf9bfd-da7e-49d1-9fa8-b00b4b9bf813','金壇觀','周弼','宋','宋诗','song-poetry','','[]','金壇深僻觀，鍾磬少人聞。',48,'全唐诗/poet.song.208000.json','["金壇深僻觀，鍾磬少人聞。", "山果猿偷墮，庭莎鹿卧分。", "木高猶带雪，石冷不生雲。", "正爇黄連炷，相從拜老君。"]'),
('70cb3c83-45d5-45f2-b016-57ab05d63ed9','晚登黄鶴樓','周弼','宋','宋诗','song-poetry','','[]','戚戚登臨地，淒淒欲暮天。',48,'全唐诗/poet.song.208000.json','["戚戚登臨地，淒淒欲暮天。", "相看數株柳，不聽一聲蟬。", "山冷雲生絮，江空月上弦。", "無緣捨塵事，閑對白鷗眠。"]'),
('051bbff5-95b4-4e06-935f-472af8855985','施潭','周弼','宋','宋诗','song-poetry','','[]','歸程風强阻，春色有如無。',48,'全唐诗/poet.song.208000.json','["歸程風强阻，春色有如無。", "上水千帆健，中流一矴孤。", "雨衝尋屋燕，雲背立檣烏。", "盡說明朝順，江行舊有圖。"]'),
('bb6adf28-6028-48a9-ae78-21b462ee91b8','山行','周弼','宋','宋诗','song-poetry','','[]','盡日群山裏，知行第幾重。',48,'全唐诗/poet.song.208000.json','["盡日群山裏，知行第幾重。", "竹深春寺磬，灘急午溪舂。", "殘旭猶雙塔，晴雲只半峰。", "豈無仙隠者，恨不少從容。"]'),
('cac24f21-bc06-40a1-8af4-9dcfe0150d89','野橋','周弼','宋','宋诗','song-poetry','','[]','日暮野橋邊，都歸醉客船。',48,'全唐诗/poet.song.208000.json','["日暮野橋邊，都歸醉客船。", "數竿沙際日，一片水中天。", "影落衝煙鳥，聲移带雨蟬。", "殆非人境得，江月又初圓。"]'),
('39bdfd7b-d3b6-4eec-be9f-9190d5e920d1','送姚希聲令弟歸剡中','周弼','宋','宋诗','song-poetry','','[]','客程何太急，歲月半途分。',48,'全唐诗/poet.song.208000.json','["客程何太急，歲月半途分。", "想暫歸天姥，還來伴使君。", "曉吟千嶂雪，春思一江雲。", "若再經過此，囊詩可得聞。"]'),
('21313b65-419c-43dc-b1b7-6c280dfa2d85','秋屏','周弼','宋','宋诗','song-poetry','','[]','好山多變態，排列在簷楹。',48,'全唐诗/poet.song.208000.json','["好山多變態，排列在簷楹。", "平熨澄江練，橫鋪列嶂屏。", "石煙寒遶寺，山雨暗離汀。", "有意携溪枕，眠看直到醒。"]'),
('5157a59d-926b-4c7b-ada5-f0ce569f75fc','同李雪林飲山村','周弼','宋','宋诗','song-poetry','','[]','本來無飲興，偶此到溪灘。',48,'全唐诗/poet.song.208000.json','["本來無飲興，偶此到溪灘。", "屋角懸雙瓠，船頭繫一竿。", "塔高風便響，橋峻雨隨乾。", "莫怕城門閉，行歸亦不難。"]'),
('f19068ea-c938-49b7-a8be-c37716c49dfc','送惟德上人還黿溪','周弼','宋','宋诗','song-poetry','','[]','爲愛林間寺，幽閑少是非。',48,'全唐诗/poet.song.208000.json','["爲愛林間寺，幽閑少是非。", "因拋蓽門業，來著稻田衣。", "石蕨衝雲細，山蔬膩雨肥。", "禪居安穩後，更莫啟柴扉。"]'),
('32e0a5db-fa66-465b-af2b-fa0177a3630f','甲申歲解官歸故居有以書相問者','周弼','宋','宋诗','song-poetry','','[]','近憑筇竹杖，處處作生涯。',48,'全唐诗/poet.song.208000.json','["近憑筇竹杖，處處作生涯。", "獨採傍溪藥，自看臨水花。", "愛雲因北望，對日任西斜。", "惟有雙蝴蝶，相隨直到家。"]'),
('663f1fb3-0a80-4140-a5bf-399967782016','送惠嵩上人住西山蘭若','周弼','宋','宋诗','song-poetry','','[]','孤雲無定迹，又入亂山居。',48,'全唐诗/poet.song.208000.json','["孤雲無定迹，又入亂山居。", "既息禪機穩，從教世網疏。", "曉香巖屋像，寒呪石潭魚。", "待我尋詩境，看君坐隠廬。"]'),
('424c0b8a-67b8-4d61-a786-b18ea2c9b2ba','石塘','周弼','宋','宋诗','song-poetry','','[]','水陸盡經過，地暄晴更和。',48,'全唐诗/poet.song.208000.json','["水陸盡經過，地暄晴更和。", "鳥聲臨水近，人影向橋多。", "細雪傾殘橘，輕冰脆立荷。", "少爲鹽米計，聽徹竹枝歌。"]'),
('6ebc8814-c52c-4b4a-9fb3-0f02260f6ea6','病起幽園檢校','周弼','宋','宋诗','song-poetry','','[]','病起無情緒，池邊日幾回。',48,'全唐诗/poet.song.208000.json','["病起無情緒，池邊日幾回。", "蟲聲低覆草，螺殻細生苔。", "暑退蘆將變，秋殘蓼續開。", "久消環繞迹，全若未嘗來。"]'),
('f6547506-f3c0-4177-846f-2f8f7448b598','雙林寺','周弼','宋','宋诗','song-poetry','','[]','杳杳雙林路，林深不易登。',48,'全唐诗/poet.song.208000.json','["杳杳雙林路，林深不易登。", "寺幽憐宿鳥，地僻喜閑僧。", "靜徹垂梁板，寒銷背壁燈。", "水邊人忽笑，猿落過溪藤。"]'),
('3d338701-bd0d-41b2-86a2-ef504ec0f74a','送僧歸舊隠','周弼','宋','宋诗','song-poetry','','[]','自言歸去後，只在故山邊。',48,'全唐诗/poet.song.208000.json','["自言歸去後，只在故山邊。", "紗帽臨溪盥，銅瓶傍水禪。", "晝閑松塔雨，春盡草堂煙。", "何故相拋捨，沉浮逐世緣。"]'),
('5557715a-c9d7-4a68-bfd5-6df6c2be3c24','冰清堂偶成','周弼','宋','宋诗','song-poetry','','[]','數盃恬淡酒，相就等閑傾。',48,'全唐诗/poet.song.208000.json','["數盃恬淡酒，相就等閑傾。", "得失徒多感，行藏任獨清。", "晝閑風有味，春盡雨無聲。", "但惜新栽柳，相呼欠一鶑。"]'),
('a3459e86-8038-4a75-be15-20915daab19e','酬李達可','周弼','宋','宋诗','song-poetry','','[]','歸心終自遂，何必戀虛聲。',48,'全唐诗/poet.song.208000.json','["歸心終自遂，何必戀虛聲。", "轉覺青衫惡，誰憐白髮生。", "掃花山石瘦，洗藥野泉清。", "應有忘機者，時來伴我行。"]'),
('f1c3a089-0fe4-4b9a-9d48-b50a24955923','寄杜北山','周弼','宋','宋诗','song-poetry','','[]','一曲小湖濱，幽居不厭貧。',48,'全唐诗/poet.song.208000.json','["一曲小湖濱，幽居不厭貧。", "坐容禪子憩，家就麯生鄰。", "簷竹侵燈衆，籬花落竈頻。", "幾時吟得句，寄與豫章人。"]'),
('eb549be4-caff-4d61-9426-4aea75c56198','寄鶴林智福上人','周弼','宋','宋诗','song-poetry','','[]','深山高頂寺，黄鶴舊曾留。',48,'全唐诗/poet.song.208000.json','["深山高頂寺，黄鶴舊曾留。", "鶴去無蹤跡，山僧幾白頭。", "鳥閑齋鼓靜，猿嘯佛燈幽。", "宿約何時踐，題詩向瀑流。"]'),
('14ad713b-52a9-4945-b645-0f42e846175c','幽居漫成  其一','周弼','宋','宋诗','song-poetry','','[]','便入空山住，休慵漢省書。',48,'全唐诗/poet.song.208000.json','["便入空山住，休慵漢省書。", "薄雲翻藥畚，斜日送柴車。", "遠業松花膩，生涯薤葉疏。", "抱琴誰共聽，一尾石間魚。"]'),
('829acb50-3b2e-4f1f-bd72-63c368b4219d','幽居漫成  其二','周弼','宋','宋诗','song-poetry','','[]','乍歸無定業，蕭索带村居。',48,'全唐诗/poet.song.208000.json','["乍歸無定業，蕭索带村居。", "神樹當中朽，人家著外疏。", "藻痕千漂絮，花影一床書。", "何必爲真隠，相安便有餘。"]'),
('10945b8d-6429-4766-9e10-5395a0e8bd31','鹿苑寺','周弼','宋','宋诗','song-poetry','','[]','分半作民棲，猶藏一曲溪。',48,'全唐诗/poet.song.208000.json','["分半作民棲，猶藏一曲溪。", "鵲窺蓮葉座，僧占菜花畦。", "白蠹魚銷粉，青乾獸剝泥。", "幸留唐刻在，相伴峻廊題。"]'),
('f708b764-a596-42b2-a4f6-8c2be42015dc','馬要寺','周弼','宋','宋诗','song-poetry','','[]','水國何年寺，蕭條野渡邊。',48,'全唐诗/poet.song.208000.json','["水國何年寺，蕭條野渡邊。", "僧驅田雀倦，神抱海犀眠。", "細網垂秋屋，殘燈泊暝船。", "數家枯柳下，猶有舊人煙。"]'),
('0b53c6eb-8fc1-4b5d-b7c1-5f7d95499a67','野賽','周弼','宋','宋诗','song-poetry','','[]','客心懷避忌，地險自多神。',48,'全唐诗/poet.song.208000.json','["客心懷避忌，地險自多神。", "楓葉藏山魅，松根抱石人。", "鶻翻蒼黑翅，魚曝赤斑鱗。", "未必知風候，惟聞酹酒頻。"]'),
('af1d0474-3e74-4b9c-bb1a-c94d070742ca','題逸人壁','周弼','宋','宋诗','song-poetry','','[]','深僻人稀到，天然野意成。',48,'全唐诗/poet.song.208000.json','["深僻人稀到，天然野意成。", "荷衝崩岸出，草入廢泉生。", "曝朮充山貨，抽茶當地征。", "未須尋伴侶，時有自來鶑。"]'),
('c130ee43-20e3-4498-87c7-957ec1bc9369','送蔣雲啟之湘中','周弼','宋','宋诗','song-poetry','','[]','出門歧路分，願往不辭勤。',48,'全唐诗/poet.song.208000.json','["出門歧路分，願往不辭勤。", "螢影侵湘月，蟬聲隔楚雲。", "頻燒霜後籜，多飯雨中蕡。", "若過黄陵廟，椒漿奠小君。"]'),
('0c7318c3-9d3f-4c02-8f62-e9a8eedc198a','送僧妙通遊平江萬壽','周弼','宋','宋诗','song-poetry','','[]','故鄉離幾日，何處躡秋陵。',48,'全唐诗/poet.song.208000.json','["故鄉離幾日，何處躡秋陵。", "梵葉床頭樹，唐衣壁面僧。", "雨花粘舊錫，風籜掃寒簦。", "新偈期相寄，呵彈破小乘。"]'),
('89dac97d-ecb3-4af9-a118-ee5405fa2a04','酬杜八同宿西山蘭若','周弼','宋','宋诗','song-poetry','','[]','西山龍井路，俱有舊行蹤。',48,'全唐诗/poet.song.208000.json','["西山龍井路，俱有舊行蹤。", "待得城中暇，重期石上逢。", "冷霜粘破屐，落月带殘鍾。", "擬踐相鄰約，煩君買一峰。"]'),
('4fce37e5-7d2b-4604-838b-2cecf2496e63','菩提廢寺','周弼','宋','宋诗','song-poetry','','[]','野寺孤僧住，當春亦掩扉。',48,'全唐诗/poet.song.208000.json','["野寺孤僧住，當春亦掩扉。", "曉鍾三板去，昏杵一盂歸。", "古屋垂山榧，幽窗養石韋。", "未容行客憩，荒樹雨鳩飛。"]'),
('40508b5b-d4e4-4c82-817b-9d48be75ee52','天申宮蘇文忠畫像','周弼','宋','宋诗','song-poetry','','[]','大澤沾荒裔，靈山識老臣。',48,'全唐诗/poet.song.208000.json','["大澤沾荒裔，靈山識老臣。", "微茫雲外跡，衰病瘴中身。", "濕草寒碑夕，晴花午殿春。", "高簷風雨斷，猶避六丁神。"]'),
('e287ab18-182d-4426-8576-68467ba829ca','誓節渡','周弼','宋','宋诗','song-poetry','','[]','仿佛經行地，還尋古渡邊。',48,'全唐诗/poet.song.208000.json','["仿佛經行地，還尋古渡邊。", "山禽多白練，溪藥間黄連。", "漠漠將晴雨，迢迢欲暝煙。", "恍然驚夢醒，二十有三年。"]'),
('eaccde59-f5db-476b-a558-4060bf46398f','白羊','周弼','宋','宋诗','song-poetry','','[]','路隔一重溪，山深客易危。',48,'全唐诗/poet.song.208000.json','["路隔一重溪，山深客易危。", "驛亭惟有額，官堠盡無碑。", "竹掛黄身虺，林香白面狸。", "得船爭欲渡，先奔槿花籬。"]'),
('ad936b85-2112-46f8-82cc-fcb56f97485c','送人遊邊','周弼','宋','宋诗','song-poetry','','[]','平世絕邊籌，憐君古塞遊。',48,'全唐诗/poet.song.208000.json','["平世絕邊籌，憐君古塞遊。", "誰聽蒯緱劍，虛弊黑貂裘。", "宵柝鳴荒戍，寒烽起廢樓。", "到應先吊古，慟哭峴山頭。"]'),
('ce5afe4f-cd46-4716-a091-44f14d69c06b','春暮登黄鶴樓','周弼','宋','宋诗','song-poetry','','[]','欲盡殘春酒，登臨事已違。',48,'全唐诗/poet.song.208000.json','["欲盡殘春酒，登臨事已違。", "聽殘懷舊笛，添盡禦寒衣。", "鳥向青山沒，人來赤壁稀。", "最憐城側樹，無可作花飛。"]'),
('b181e4b5-d2d6-4c06-bb1c-e7591d6e1005','爲僧曇芳賦草堂','周弼','宋','宋诗','song-poetry','','[]','把詩從我者，多是剡中僧。',48,'全唐诗/poet.song.208000.json','["把詩從我者，多是剡中僧。", "結屋何山塢，當門幾樹藤。", "地寒常带雪，溪峻不留冰。", "贈爾新吟去，歸題木葉層。"]'),
('d4bfff69-6848-4c14-9029-31101c7f3ee3','江臯送別','周弼','宋','宋诗','song-poetry','','[]','把酒對汀洲，相看發去舟。',48,'全唐诗/poet.song.208000.json','["把酒對汀洲，相看發去舟。", "迎風一分手，驚浪幾翻頭。", "燭暗花消淚，楓寒葉弄愁。", "恐猶回首望，終夕凭高樓。"]'),
('3531c6c9-aa38-4332-b745-488452d635b6','送胡宗原還台山','周弼','宋','宋诗','song-poetry','','[]','故里杉松表，歸程筍薤初。',48,'全唐诗/poet.song.208000.json','["故里杉松表，歸程筍薤初。", "盃多常失飯，囊罄只留書。", "海墨收秦棄，山糧拾禹餘。", "古來仙隠者，多在赤城居。"]'),
('2e41c296-de6f-4057-9ce1-fa5ebd398cb0','千金寺','周弼','宋','宋诗','song-poetry','','[]','十載他鄉別，春歸逐浪層。',48,'全唐诗/poet.song.208000.json','["十載他鄉別，春歸逐浪層。", "晚晴沙市鼓，夜雨石橋燈。", "帆仄摧乾葦，衣寒脆薄繒。", "舊時來往寺，惆悵不逢僧。"]'),
('ed08aa15-62ef-4095-b2ab-af429c6149f2','留別唐棲雲泉上人','周弼','宋','宋诗','song-poetry','','[]','水宿唐棲寺，何緣更浹旬。',48,'全唐诗/poet.song.208000.json','["水宿唐棲寺，何緣更浹旬。", "千山今日路，三歲異鄉人。", "小殿眠身佛，空廊折臂神。", "歸時重作禮，又拂一番塵。"]'),
('e2f49cfe-cc50-4c73-8d8b-471ef7ac4420','天章寺前小樓','周弼','宋','宋诗','song-poetry','','[]','客懷依古寺，曲水茂林邊。',48,'全唐诗/poet.song.208000.json','["客懷依古寺，曲水茂林邊。", "俯聽磵鳴石，靜看山出煙。", "傍花清晚漱，對竹冷春眠。", "深羨溪僧樂，幽居動歲年。"]'),
('e9fb0375-5b99-418a-92b0-6858f2c078a4','野望','周弼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春日晚荒荒，平沙極渺茫。',48,'全唐诗/poet.song.208000.json','["春日晚荒荒，平沙極渺茫。", "樓欹三面水，城卧數條崗。", "白草吳京甸，黄桑楚戰場。", "長江俱不問，一片瀉斜陽。"]'),
('8f55e3f2-e4e9-4329-866e-7a0bb2833317','楓橋寒山寺','周弼','宋','宋诗','song-poetry','','[]','江楓吟詠工，幽寺冷遺蹤。',48,'全唐诗/poet.song.208000.json','["江楓吟詠工，幽寺冷遺蹤。", "不改前朝路，猶聞半夜鍾。", "地凉汀月皎，村迥水煙濃。", "試問誰曾見，惟應獨有松。"]'),
('4311bf1d-2387-4302-a6f4-24df6cc8190a','送黄同甫','周弼','宋','宋诗','song-poetry','','[]','人生各有安，出易欲歸難。',48,'全唐诗/poet.song.208000.json','["人生各有安，出易欲歸難。", "古道春泥重，孤城暮雪寒。", "酒鋒精似將，詩業遠於官。", "野穀如堪飽，從君借鶡冠。"]'),
('332f7a8b-e100-4295-8a35-dce9fa969b3d','應潭','周弼','宋','宋诗','song-poetry','','[]','村崦遞相遮，分居兩岸沙。',48,'全唐诗/poet.song.208000.json','["村崦遞相遮，分居兩岸沙。", "地征兼橘柚，土物半桑麻。", "水白來如虹，山黄去若蛇。", "往年曾泊此，叢竹數人家。"]'),
('a3f8a01f-0ec7-4391-b580-fc621f68c8a9','招鄭服之','周弼','宋','宋诗','song-poetry','','[]','歸心同一路，况復在新年。',48,'全唐诗/poet.song.208000.json','["歸心同一路，况復在新年。", "夢著登山屐，閑隨渡水船。", "宿蒿迷舊隴，春葑起閑田。", "醉卧天池上，知君在我先。"]'),
('fbaa1229-5218-40d6-a8e3-17830c7212ab','靈竺寺','周弼','宋','宋诗','song-poetry','','[]','不因純孝者，古寺若爲安。',48,'全唐诗/poet.song.208000.json','["不因純孝者，古寺若爲安。", "壁彩蝸遊遍，爐香鼠踏殘。", "鍾聲嘶破梃，旛影颭危竿。", "尚恐冬生笋，時來竹外看。"]'),
('0d6936ef-f1e1-49b6-95ff-a5efe454e096','齊安早眺  其一','周弼','宋','宋诗','song-poetry','','[]','昔日干戈地，凄凉古塞情。',48,'全唐诗/poet.song.208000.json','["昔日干戈地，凄凉古塞情。", "軍同民雜戍，州與縣分城。", "野曠孤鴻絕，沙寒一騎行。", "十年生息後，人尚怯論兵。"]'),
('3cd193f7-8d74-43d6-b382-bcd27025383e','齊安早眺  其二','周弼','宋','宋诗','song-poetry','','[]','陰陰城壘靜，極望不飛塵。',48,'全唐诗/poet.song.208000.json','["陰陰城壘靜，極望不飛塵。", "草色橫江暮，鶑聲出塞春。", "清時應洗甲，來歲又逢辛。", "惆悵經過處，都非往昔人。"]'),
('6ff0f268-a327-40de-97de-e5b539faf6e4','村市','周弼','宋','宋诗','song-poetry','','[]','細簇人家住，中分破石崖。',48,'全唐诗/poet.song.208000.json','["細簇人家住，中分破石崖。", "竹門開店屋，草市夾橋街。", "水別東流漢，山橫北過淮。", "並船頻借問，同買出江柴。"]'),
('f029cf6e-7118-40ed-9bfe-e09cecbd007e','贈僧仲寶月溪','周弼','宋','宋诗','song-poetry','','[]','幽棲深絕地，靜夜獨宜僧。',48,'全唐诗/poet.song.208000.json','["幽棲深絕地，靜夜獨宜僧。", "上下兩輪玉，中間一片冰。", "影收懸罟索，光息過船燈。", "獨坐觀心了，無由更小乘。"]'),
('ae16b81b-177b-4690-8e77-8713e5ada717','題夏肯父曉山圖','周弼','宋','宋诗','song-poetry','','[]','旦旦自天成，中全一氣清。',48,'全唐诗/poet.song.208000.json','["旦旦自天成，中全一氣清。", "漸分平與峻，俄轉晦爲明。", "竹閟鋪沙影，松涵出谷聲。", "機心都不動，穩看日初生。"]'),
('d8766ff9-eff7-4ee6-8b35-398bef0399a5','孫季蕃故居','周弼','宋','宋诗','song-poetry','','[]','笑語失詼諧，人誰不愴懷。',48,'全唐诗/poet.song.208000.json','["笑語失詼諧，人誰不愴懷。", "夢殘秋雨寺，魂散夕陽街。", "缺竈粘煎藥，乾爐積燎柴。", "風流何必葬，便擁菊花埋。"]'),
('ddc59235-dbf7-463f-9652-38581edc4230','趙東麓歸自房陵','周弼','宋','宋诗','song-poetry','','[]','一年辛苦後，收聚若爲豐。',48,'全唐诗/poet.song.208000.json','["一年辛苦後，收聚若爲豐。", "攝職全無吏，携家僅有童。", "乳舂花下管，漆溜葉間筒。", "自此嬉遊地，應須且浙中。"]'),
('bcdd1c3e-dc24-4a4e-a864-63f0fb683808','吳山仁王寺','周弼','宋','宋诗','song-poetry','','[]','山寺憑高夕未昏，上皇曾此定乾坤。',64,'全唐诗/poet.song.208000.json','["山寺憑高夕未昏，上皇曾此定乾坤。", "甌閩散驛緣江島，龕赭收潮入海門。", "細雨亂花唐輦道，淡煙疏柳漢營屯。", "何時汴水東流畔，君返宸居臣故園。"]'),
('fcad8d95-7e6c-4a09-9ed1-7d830410aaa9','庾樓','周弼','宋','宋诗','song-poetry','','[]','欲望江山夜轉真，胡床曾此對嘉賓。',64,'全唐诗/poet.song.208000.json','["欲望江山夜轉真，胡床曾此對嘉賓。", "傷心皓月長流水，回首清風不見人。", "花落雉樓橫角暮，草生鷗渚破船春。", "歸程豈暇頻登覽，分付羈愁與白蘋。"]'),
('1c354928-421f-48e6-8bbd-4e738083d917','題豫章臺','周弼','宋','宋诗','song-poetry','','[]','何日遺蹤鎖斷崗，更誰曾望舊臺荒。',64,'全唐诗/poet.song.208000.json','["何日遺蹤鎖斷崗，更誰曾望舊臺荒。", "百年南渡頻秋雨，一片西山幾夕陽。", "石礙老松欹徑險，岸隨乾葦出江長。", "斗間可是無佳氣，又見飛烏繞去檣。"]'),
('1463a2f4-1445-47ec-a9b5-220aaad09765','題滕王閣','周弼','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','高閣巍峨接水濱，興亡纔問便傷神。',64,'全唐诗/poet.song.208000.json','["高閣巍峨接水濱，興亡纔問便傷神。", "鳴鸞東閣知何處，跨鶴西山別有人。", "柳映落霞江渚暮，草鋪斜日野田春。", "羣鷗亦厭多悲感，偏與忘機客最親。"]'),
('ad129e83-db4b-4712-aec1-22698a81c78d','送友人持節嶺南','周弼','宋','宋诗','song-poetry','','[]','吳雲迢遞楚雲鮮，從此南征路幾千。',64,'全唐诗/poet.song.208000.json','["吳雲迢遞楚雲鮮，從此南征路幾千。", "漢使五羊登嶺日，魯經三豕渡河年。", "榕穿白草飛蠻雨，椒落黄芽起瘴煙。", "待及戍瓜多載石，定無番貨入歸船。"]'),
('f7823aa9-7169-429d-b2a4-c9d097a1a3cc','贈唐棲寺僧','周弼','宋','宋诗','song-poetry','','[]','山門寂寞唐棲寺，別去閑居又一年。',64,'全唐诗/poet.song.208000.json','["山門寂寞唐棲寺，別去閑居又一年。", "草暗暮田羣雁遠，花明春院一僧禪。", "雲房夕磬浮清雨，水殿寒燈宿細煙。", "作得詩成無寄處，幾回遥認隔溪船。"]'),
('ee3a9134-5c69-4f24-8db5-07b90395c625','連珠','周弼','宋','宋诗','song-poetry','','[]','遠望披裘日幾回，可堪江上暮寒催。',64,'全唐诗/poet.song.208000.json','["遠望披裘日幾回，可堪江上暮寒催。", "雲飛曠野迎風斷，雪洒長灘夾雨來。", "馬踏野橋嘶破板，鳥迷村路立高桅。", "暫須移向疏籬泊，遷就驚春一樹梅。"]'),
('75633154-df91-4670-b9b2-bb0d0240f504','行吟','周弼','宋','宋诗','song-poetry','','[]','獨行沙岸不相携，準擬沿溪更渡溪。',64,'全唐诗/poet.song.208000.json','["獨行沙岸不相携，準擬沿溪更渡溪。", "藥蔓交加蟲上下，柳花撩亂蝶高低。", "杖頭曉伴春雲石，屐齒晴翻夜雨泥。", "詩就隨山爲人寫，等閑抽盡錦中題。"]'),
('4bd11788-5ba6-4795-9c31-afc548a2fa73','秀野','周弼','宋','宋诗','song-poetry','','[]','小作幽園傍宅開，只須數畝占樓臺。',64,'全唐诗/poet.song.208000.json','["小作幽園傍宅開，只須數畝占樓臺。", "石移林屋秋雲至，水带松江暮雨來。", "徑草散香迎過屐，砌花分影蔭流盃。", "人家園圃應無數，不似君能日幾回。"]'),
('0a4f4237-1270-4339-bdef-ed12f1f21767','孫伯符墓下','周弼','宋','宋诗','song-poetry','','[]','梧葉蕭蕭墓草長，夢魂曾斷九回腸。',64,'全唐诗/poet.song.208000.json','["梧葉蕭蕭墓草長，夢魂曾斷九回腸。", "空聞絳帕離章水，誰見黄旗入洛陽。", "鴉噪暮園江阪迥，龍盤春戍石城荒。", "赤烏不識桑田變，猶自悽悽守白楊。"]'),
('027c6e13-47e7-4357-acc4-ab6569d3f782','天津橋','周弼','宋','宋诗','song-poetry','','[]','裊裊朱欄倚細波，綠雲相對閟嵯峨。',64,'全唐诗/poet.song.208000.json','["裊裊朱欄倚細波，綠雲相對閟嵯峨。", "中天車駕曾擒虜，何日樓船定入河。", "霽柳午陰隨岸遠，露桃春色過牆多。", "黄旗適應東南運，已辦簫鐃幾曲歌。"]'),
('1c5f6ffe-ed7b-45f6-bfe7-4d74775c42ab','雨花臺','周弼','宋','宋诗','song-poetry','','[]','細蘚柔莎瑣舊堆，昔年曾見異僧回。',64,'全唐诗/poet.song.208000.json','["細蘚柔莎瑣舊堆，昔年曾見異僧回。", "如何天上飛靈雨，不爲人間洗劫灰。", "江接潮頭諸脉應，地連崗勢一支來。", "只今不假虛無事，別是春風歌舞臺。"]'),
('37561d12-6f47-4144-b9ca-c721cd0cd5f5','鳳凰臺','周弼','宋','宋诗','song-poetry','','[]','一徑逶迤草自芳，何爲不復更翺翔。',64,'全唐诗/poet.song.208000.json','["一徑逶迤草自芳，何爲不復更翺翔。", "應須舊國還宣武，別有高臺在建章。", "白鷺背花尋塔路，赤烏衝柳集宮牆。", "中興不比偏安事，且對梧桐薦羽觴。"]'),
('2c647074-c9b9-42c7-b0c5-9cc28d5d0d62','烏衣巷','周弼','宋','宋诗','song-poetry','','[]','日落凭欄感慨頻，長干橋畔冷殘春。',64,'全唐诗/poet.song.208000.json','["日落凭欄感慨頻，長干橋畔冷殘春。", "桑田蕪沒徒多事，蘭玉叢生更幾人。", "風暖影翻花外燕，雨多痕蝕草間麟。", "堪嗟羣從成功後，不及鍾山一尉神。"]'),
('26efa4e4-6ce3-4383-8f49-206ee8985c7f','石頭城','周弼','宋','宋诗','song-poetry','','[]','點點凝煙望未收，六朝遺迹遍荒丘。',64,'全唐诗/poet.song.208000.json','["點點凝煙望未收，六朝遺迹遍荒丘。", "自從絳闕雄江面，誰把朱泥染石頭。", "崗斷曉榛雙阜虎，岸長春草一灘鷗。", "諸公多少新亭恨，不是知心莫上樓。"]'),
('caa12e1d-93b2-4249-9e17-e81ce4d7ecb0','浮遠','周弼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','橫障瀰漫恃此丘，長江東騖轉湍流。',64,'全唐诗/poet.song.208000.json','["橫障瀰漫恃此丘，長江東騖轉湍流。", "波間去海無多里，沙際鋪淮輒數州。", "風勢起花山郭暗，潮聲侵樹野田浮。", "無由望徹蒼茫外，回首斜陽總是愁。"]'),
('8be82ae1-5b10-429d-a6d7-a5bcc79b8a0d','送趙山臺赴江陰','周弼','宋','宋诗','song-poetry','','[]','匆匆何事解朝衣，甫爲君王領一麾。',64,'全唐诗/poet.song.208000.json','["匆匆何事解朝衣，甫爲君王領一麾。", "歷考近來成故事，就遷長是未多時。", "寒更夜徹防淮柝，曉舶晴翻出海旗。", "不久赤蹄應已到，只須略賦練江詩。"]'),
('e7ac4053-6773-4a03-b1d4-c4559ff0c5a4','岳陽樓','周弼','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','憑高望盡寂寥天，與我閑情共渺然。',64,'全唐诗/poet.song.208000.json','["憑高望盡寂寥天，與我閑情共渺然。", "平展暮雲三百里，積停春水二千年。", "沙洲橫渡荆江雨，石塔遥分岳麓煙。", "老我未聞飛劍術，想須今度遇回仙。"]'),
('3a1a7f9c-6c8d-41ea-8068-81e90a0ea87f','西湖竹閣寺','周弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','精舍蕭疏近水凉，分明一徑綠沉槍。',64,'全唐诗/poet.song.208000.json','["精舍蕭疏近水凉，分明一徑綠沉槍。", "就移山近湖皆隠，放出樓高寺倒藏。", "春透露梢齊曲檻，曉翻風籜過脩牆。", "長堤花盡人稀少，來聽蟬聲伴夕陽。"]'),
('8cb62542-9cfb-448e-b43d-88f2936e8085','採香徑','周弼','宋','宋诗','song-poetry','','[]','繒甲如荼護此臺，玉顔憔悴錦帆來。',64,'全唐诗/poet.song.208000.json','["繒甲如荼護此臺，玉顔憔悴錦帆來。", "一蹊香草無蜂過，千里空葭有雁回。", "響屧蘚埋丹鳳迹，縷衣花變粉蛾灰。", "誰知子夜歌殘日，樹滿西山似綠苔。"]'),
('dfd5543b-f646-4a93-b30e-0fd17df2b509','七里瀨','周弼','宋','宋诗','song-poetry','','[]','瞬息沿流七里遥，感時回纜木蘭橈。',64,'全唐诗/poet.song.208000.json','["瞬息沿流七里遥，感時回纜木蘭橈。", "高臺未變陵兼谷，故國頻更市與朝。", "風散亂雲通去驛，雨消殘雪助歸潮。", "漁翁近亦無前輩，一箇青銅不肯饒。"]'),
('f23ad2c0-3cb1-4a75-8e3c-223777eaa9bc','南樓懷古五首  其一','周弼','宋','宋诗','song-poetry','','[]','昔人有意久經營，極望寒蕪遠更平。',64,'全唐诗/poet.song.208000.json','["昔人有意久經營，極望寒蕪遠更平。", "三國旆旌羣鵲散，六朝樓閣一鳩鳴。", "雪消晴嶂沉孤壘，風打寒潮入廢城。", "多少怨魂銷不盡，草根燒斷又還生。"]'),
('d0d270de-de7c-4385-8eb4-15f22091f0e9','南樓懷古五首  其二','周弼','宋','宋诗','song-poetry','','[]','事久銷沉只等閑，好將深意遞相參。',64,'全唐诗/poet.song.208000.json','["事久銷沉只等閑，好將深意遞相參。", "舳艫宵遁誰思忖，裙屐春游自笑談。", "西日瘴回迷漢沔，北風波逆上江潭。", "隔城方唱招魂引，一拍殷勤至再三。"]'),
('d21a0141-25e6-40dc-81e6-fb980f5d4bc8','南樓懷古五首  其三','周弼','宋','宋诗','song-poetry','','[]','茫茫迂曲度平川，何處孤村近水邊。',64,'全唐诗/poet.song.208000.json','["茫茫迂曲度平川，何處孤村近水邊。", "煙護劉琮殘壁壘，雨沉黄祖舊樓船。", "寒沙細擁菰蘆地，破隴斜耕苜蓿田。", "見說去年秋潦後，更無茅屋起炊煙。"]'),
('4e3e70e4-1a81-450f-9afc-ba6908b9d6c8','南樓懷古五首  其四','周弼','宋','宋诗','song-poetry','','[]','幸際清時息五兵，舌頑無處說縱橫。',64,'全唐诗/poet.song.208000.json','["幸際清時息五兵，舌頑無處說縱橫。", "蟻封一夢難分別，蝸角千年强鬭爭。", "丹壁郵亭新蜀道，白樓烽戍古邾城。", "自知夜半徒興舞，移遠寒鷄不使鳴。"]'),
('4e222da8-b0e4-4f31-afab-7ac5e105fc07','南樓懷古五首  其五','周弼','宋','宋诗','song-poetry','','[]','夕陽光退杳難憑，欲問江鷗只怨憎。',64,'全唐诗/poet.song.208000.json','["夕陽光退杳難憑，欲問江鷗只怨憎。", "得意舉帆燒北岸，傷心流楳鎖西陵。", "雪消蜀貨千檣下，風順吳鹽萬斛增。", "且趁一樽相暖熱，自非乘醉莫來登。"]'),
('8d6784d9-0786-45d9-b799-1c5ad6eefd09','山居春晚','周弼','宋','宋诗','song-poetry','','[]','索居牢落動關心，但覺匆匆歲月侵。',64,'全唐诗/poet.song.208000.json','["索居牢落動關心，但覺匆匆歲月侵。", "無夢不因憐晝靜，有懷多是惜春深。", "草香稚蝶銷胡粉，花落蠻鶑變楚金。", "最是不禁芳樹色，能消幾日又成陰。"]'),
('e20326ed-f08e-433d-92b1-be962c1df590','庭下枯梅有感','周弼','宋','宋诗','song-poetry','','[]','庭下同栽兩樹梅，一株摇落一株開。',64,'全唐诗/poet.song.208000.json','["庭下同栽兩樹梅，一株摇落一株開。", "無緣春色相虧曲，有分晴光亦往來。", "雪打枯枝愁漢驛，雨翻雕萼夢荆臺。", "綺窗不斷橫斜影，猶有東風管碧苔。"]'),
('0e6a9a35-f88c-4fe8-8073-a0ce17e9b2aa','會稽山','周弼','宋','宋诗','song-poetry','','[]','衣冠從昔化文身，峻嶽當天自有神。',64,'全唐诗/poet.song.208000.json','["衣冠從昔化文身，峻嶽當天自有神。", "秦帝刻碑三十載，越王棲甲五千人。", "江連雲氣分南紀，海接星河近北辰。", "必竟興亡誰可料，但聞陵谷變飛塵。"]'),
('b2f56bbe-e9fe-4c8f-addc-0f21fcfd3391','甫里觀','周弼','宋','宋诗','song-poetry','','[]','天隨清調何人繼，幸有荒村故宅存。',64,'全唐诗/poet.song.208000.json','["天隨清調何人繼，幸有荒村故宅存。", "橘上蠹蟲應屢變，草間眠鴨尚能言。", "池亭暮雪兼風起，籬落春潮带雨渾。", "人啖菊苗終竟別，屠沽猶自不登門。"]'),
('55b90ed9-3909-400a-a184-04194219de35','陳武帝釣臺','周弼','宋','宋诗','song-poetry','','[]','路纔容馬盡荒茅，誰識仙人舊釣鼇。',64,'全唐诗/poet.song.208000.json','["路纔容馬盡荒茅，誰識仙人舊釣鼇。", "流水不隨船影斷，亂山猶带彈痕高。", "春煙粉黑重生葑，暮雨灰紅半拆桃。", "今日故宮何處問，東風應長對江濤。"]'),
('fd0c6430-1f11-4308-bbe0-c9a0f0a45b89','贈雪林李和甫','周弼','宋','宋诗','song-poetry','','[]','忽地相逢便解顔，况兼終日看青山。',64,'全唐诗/poet.song.208000.json','["忽地相逢便解顔，况兼終日看青山。", "精神摘柳哦詩際，標度尋梅集句間。", "春淡野橋孤艇遠，暮寒溪寺一鍾閑。", "匆匆又作經旬別，兩處東風各閉關。"]'),
('8233c144-efc4-4edb-aea3-c048f57e426e','道中有感','周弼','宋','宋诗','song-poetry','','[]','遠程已過經行處，別有逶迤古道存。',64,'全唐诗/poet.song.208000.json','["遠程已過經行處，別有逶迤古道存。", "寺已寂寥猶有殿，水纔窮盡又逢村。", "一株枯木人分路，十里飛花客過門。", "必竟悉依生處樂，不知何事別家園。"]'),
('c349199a-481e-4441-ab7e-5ecacea39252','黄溪','周弼','宋','宋诗','song-poetry','','[]','匆匆寧不恨飄零，轉更分岐過別汀。',64,'全唐诗/poet.song.208000.json','["匆匆寧不恨飄零，轉更分岐過別汀。", "世事總如迂曲路，年華都付短長亭。", "冢桃褪蘂無人色，社櫟盤根作鬼形。", "心自感傷人豈識，回頭猶顧峴山青。"]'),
('d1089e54-abc0-4ab6-98d0-72616f49a167','朱潭','周弼','宋','宋诗','song-poetry','','[]','消散羈愁益坦然，况當初暖欲晴天。',64,'全唐诗/poet.song.208000.json','["消散羈愁益坦然，况當初暖欲晴天。", "清溪苔滑重抄紙，淺屋柴香正煮綿。", "隔水殺鷄祠社土，過橋嘶馬入人煙。", "今朝似覺難忘酒，應更無人笑謫仙。"]'),
('5113aa61-8746-4a7a-8953-84cd30a788dc','送人之漢上','周弼','宋','宋诗','song-poetry','','[]','木落千山怨別離，自知難駐馬行蹄。',64,'全唐诗/poet.song.208000.json','["木落千山怨別離，自知難駐馬行蹄。", "上書季子窮歸洛，獻賦荀卿老向齊。", "驛店破旗秋雨細，戍樓殘角夕陽低。", "袖藏秘策君門遠，應望中原泣鼓鼙。"]'),
('5aa4a080-eab1-41f2-b9e1-9a80dc5e1b3a','荻港','周弼','宋','宋诗','song-poetry','','[]','波眼沄沄浪復輕，稍甦羈束過清明。',64,'全唐诗/poet.song.208000.json','["波眼沄沄浪復輕，稍甦羈束過清明。", "倩人覓路先尋酒，久客懷鄉始見餳。", "松下紫芽肥野菜，竹間青葉带山櫻。", "自從一別齊安後，直到今朝始聽鶑。"]'),
('48e70644-c03e-4455-b886-24333bebc997','感事','周弼','宋','宋诗','song-poetry','','[]','書劍悠悠屢變遷，老諳多故始知天。',64,'全唐诗/poet.song.208000.json','["書劍悠悠屢變遷，老諳多故始知天。", "汗青每愧拋長日，髮白無由逐少年。", "暮雨暗消江岸柳，曉霜初透野池蓮。", "此心懸解何須語，人問惟應一指禪。"]'),
('098d3fc4-e933-4322-b344-e2f79dbfe2b6','送遷客','周弼','宋','宋诗','song-poetry','','[]','自謂別離難會面，如何此地又相尋。',64,'全唐诗/poet.song.208000.json','["自謂別離難會面，如何此地又相尋。", "往來雲物他鄉意，輕薄風塵久客心。", "夜雨泥塗三里郭，夕陽煙火數家林。", "送君好去加餐飯，莫聽哀猿徹曉吟。"]'),
('ad7f3b12-f4bf-4829-8e71-1dc6154afd12','送人之京口','周弼','宋','宋诗','song-poetry','','[]','競携書劍去紛紛，誰解登臨對日曛。',64,'全唐诗/poet.song.208000.json','["競携書劍去紛紛，誰解登臨對日曛。", "北道荆夔一江下，南朝徐兖二州分。", "高樓角曉鳴秋雨，遠戍烽寒起暮雲。", "莫把尋常望瓜步，恐驚邊雁不堪聞。"]'),
('e2dce415-f980-4ce0-82e6-e2208b9694a8','留題唐棲寺','周弼','宋','宋诗','song-poetry','','[]','僧房十日相留戀，爲怯生寒未到家。',64,'全唐诗/poet.song.208000.json','["僧房十日相留戀，爲怯生寒未到家。", "插岸斷冰妨蕩槳，入簷飛雪助煎茶。", "香臺穴碎逃秋蟻，古殿巢翻失暮鴉。", "惟有溪梅最禁耐，傍籬爭發向陽花。"]'),
('38614841-eef9-4ef9-b008-adaf55dc403a','送白判官','周弼','宋','宋诗','song-poetry','','[]','著書不就便相拋，遠向襄州謁故交。',64,'全唐诗/poet.song.208000.json','["著書不就便相拋，遠向襄州謁故交。", "里舍千頭無舊橘，客程三脊有荒茅。", "買魚村渡捐孤劍，沽酒山城解弊袍。", "雙鬢豈堪禁歲月，眼看歸鳦又成巢。"]'),
('fd812119-c9a9-4969-bf1e-64ddbf1fbf04','中和節','周弼','宋','宋诗','song-poetry','','[]','時節匆忙過隙駒，可堪岑寂就船居。',64,'全唐诗/poet.song.208000.json','["時節匆忙過隙駒，可堪岑寂就船居。", "不禁衰病慵耽酒，無益閑交懶報書。", "風暖暮田歸海燕，雨甜春水上潮魚。", "客中自是光陰速，纔見新正又月初。"]'),
('1c41e42d-2041-499a-ace1-cc7a67501085','送人之荆門','周弼','宋','宋诗','song-poetry','','[]','昔年此路達王畿，荒燒畬煙事已非。',64,'全唐诗/poet.song.208000.json','["昔年此路達王畿，荒燒畬煙事已非。", "山向崤函空北望，水隨江漢自東歸。", "凄凉坂路征車遠，寂寞郵亭候火稀。", "遥想思鄉怨岐路，杜鵑花發鷓鴣飛。"]'),
('8c2de967-6ffe-4916-ab7c-680ad7f5ec23','嚴陵釣臺','周弼','宋','宋诗','song-poetry','','[]','晴江萬里綠波來，惆悵君房去不回。',64,'全唐诗/poet.song.208000.json','["晴江萬里綠波來，惆悵君房去不回。", "秦苑河山歸故國，越鄉雲雨庇荒臺。", "春風一道江蘺綠，落日千峰杜宇哀。", "欲訪釣船無處所，野花如雪滿汀開。"]'),
('4f1d2e06-efb0-4a5a-a3a9-3f3997024696','遊道場山遇雨','周弼','宋','宋诗','song-poetry','','[]','飄然久作登臨想，纔遇名山雨亦遊。',64,'全唐诗/poet.song.208000.json','["飄然久作登臨想，纔遇名山雨亦遊。", "林尾亂聲猶間響，枝頭殘滴未全收。", "濯翻野竹從教軃，衝落巖花放出流。", "欲把姓名書石上，幾回拈筆又成休。"]'),
('099f2aab-e86c-4eda-949e-6e8839b1d205','浣沙秋日五首  其一','周弼','宋','宋诗','song-poetry','','[]','衣裳單薄鬢蕭騷，獨凭危欄首屢搔。',64,'全唐诗/poet.song.208000.json','["衣裳單薄鬢蕭騷，獨凭危欄首屢搔。", "出壁亂雲分片段，隔江飛雨見絲毫。", "庭前斷續蛩爭響，簷外輕便蝶鬭高。", "多少好山俱在眼，愧無短屐共遊遨。"]'),
('681f3894-db27-405e-8ca3-a6cb14557092','浣沙秋日五首  其二','周弼','宋','宋诗','song-poetry','','[]','當前灘號西施磧，對磧看秋得句清。',64,'全唐诗/poet.song.208000.json','["當前灘號西施磧，對磧看秋得句清。", "五色懸門秦一尉，六經充棟漢諸生。", "石叢細火團荒砌，野蔓疏金出廢城。", "目送浣沙人去後，又聞街鼓報新晴。"]'),
('2af94f57-a529-48ee-b94d-53fad3a65ca8','浣沙秋日五首  其三','周弼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江淡淡樹疏疏，掃却閑庭即故居。',64,'全唐诗/poet.song.208000.json','["長江淡淡樹疏疏，掃却閑庭即故居。", "蟲入暗床頻促織，螢穿虛壁屢翻書。", "破除暮色惟荒菊，薦送秋華有嫩蔬。", "料得故園分社酒，小苞青橘四腮鱸。"]'),
('cb0d9b44-f3d5-442f-8037-8c29142d6bc8','浣沙秋日五首  其四','周弼','宋','宋诗','song-poetry','','[]','自慙尸素嘗多暇，未放秋風變楚顔。',64,'全唐诗/poet.song.208000.json','["自慙尸素嘗多暇，未放秋風變楚顔。", "一夢別離拋白水，三年端的守青山。", "野鷄避鶻遮雛去，沙翮銜魚趁母還。", "縱有亂愁消遣盡，淡雲殘日共人閑。"]'),
('4d8f9778-7156-4cbc-a1ff-68a5c1e26e8a','浣沙秋日五首  其五','周弼','宋','宋诗','song-poetry','','[]','清溪樓閣暮沉沉，不覺登臨夜欲深。',64,'全唐诗/poet.song.208000.json','["清溪樓閣暮沉沉，不覺登臨夜欲深。", "幾處捲簾催酒笛，誰家閉戶搗衣砧。", "一朝野霧三朝濕，十日江天九日陰。", "暗喜礙人公事少，自來收拾送秋吟。"]'),
('fa9c78e5-24bd-4c2f-adae-817437072b87','羅家洲','周弼','宋','宋诗','song-poetry','','[]','對港近村俱有路，扁舟倍覺往來頻。',64,'全唐诗/poet.song.208000.json','["對港近村俱有路，扁舟倍覺往來頻。", "入秋破褐惟存線，盡日收錢不滿緡。", "遠岸冷沙銜墜葉，淺灘寒水卧枯蘋。", "未知行役何時斷，縱使更深亦喚人。"]'),
('7d9ca2ed-7551-4955-ad5e-4d873a5ae036','送陳雲崖遊三衢','周弼','宋','宋诗','song-poetry','','[]','吟得詩成若等閑，爲吾開盡錦囊斑。',64,'全唐诗/poet.song.208000.json','["吟得詩成若等閑，爲吾開盡錦囊斑。", "不專瘦島元和末，要且長城大曆間。", "帆入亂潮隨漲水，帽衝殘雪度危山。", "從今便少春游伴，纔過新正可得還。"]'),
('20279fa1-254f-45d4-a265-0887e99c8599','春怨','周弼','宋','宋诗','song-poetry','','[]','極浦蘋花白，空壕蘭萼紅。',24,'全唐诗/poet.song.208000.json','["極浦蘋花白，空壕蘭萼紅。", "傷心城上燕，飛入館娃宮。"]'),
('51665eaf-44d0-43e8-b13d-b9d3a4c51d0b','送客','周弼','宋','宋诗','song-poetry','','[]','欲知行遠近，細數杜鵑聲。',24,'全唐诗/poet.song.208000.json','["欲知行遠近，細數杜鵑聲。", "暗入蒼山去，千聞是一程。"]'),
('2c134bb0-5c92-4f5e-9a74-083c44c60f67','冷泉幽憩','周弼','宋','宋诗','song-poetry','','[]','水源窮不盡，垢膩生春襪。',24,'全唐诗/poet.song.208000.json','["水源窮不盡，垢膩生春襪。", "未敢輒揭流，且向幽亭歇。"]'),
('396ce1df-4ef1-471e-a584-4a48a395785a','落梅','周弼','宋','宋诗','song-poetry','','[]','玉樹分明照夕流，粉痕翻爲碧苔留。',32,'全唐诗/poet.song.208000.json','["玉樹分明照夕流，粉痕翻爲碧苔留。", "三更枝上玲瓏雨，亂滴寒香一夜愁。"]'),
('52fe7467-2e38-41b1-a690-f49cafcc0b73','回山僧書就題書尾','周弼','宋','宋诗','song-poetry','','[]','憶昔同行題落葉，寺前枯樹鶴巢邊。',32,'全唐诗/poet.song.208000.json','["憶昔同行題落葉，寺前枯樹鶴巢邊。", "不知今度苔枝上，多少秋蟲已化蟬。"]'),
('1439a2ac-647e-42e7-8821-af8d0813ff2f','逢僧文禮  其一','周弼','宋','宋诗','song-poetry','','[]','空山落日又逢僧，雨雜塵灰滿帽紋。',32,'全唐诗/poet.song.208000.json','["空山落日又逢僧，雨雜塵灰滿帽紋。", "但憶來時門不掩，麝香偷卧石床雲。"]'),
('e2b67b29-de0c-4cb9-b091-246e59f0e028','逢僧文禮  其二','周弼','宋','宋诗','song-poetry','','[]','師說古香寮舊開，鮑照曾爲惠休來。',32,'全唐诗/poet.song.208000.json','["師說古香寮舊開，鮑照曾爲惠休來。", "至今猿鶴猶知敬，靜對寒星禮碧苔。"]'),
('df202271-c00c-4b82-99cc-9d33ba435508','秋夜','周弼','宋','宋诗','song-poetry','','[]','山門半掩浮雲闕，古道人稀芳草歇。',32,'全唐诗/poet.song.208000.json','["山門半掩浮雲闕，古道人稀芳草歇。", "夜深零露滴秋香，幽人獨步青蘿月。"]'),
('f7acbf27-a080-4d6d-a587-96e3cb759dfa','寄雲泉僧永頤  其一','周弼','宋','宋诗','song-poetry','','[]','書來只說住高峰，不記松林第幾重。',32,'全唐诗/poet.song.208000.json','["書來只說住高峰，不記松林第幾重。", "欲揀青巒問茅舍，秋山一樣白雲封。"]'),
('783059b2-f279-4672-baa2-fb25130e94d8','寄雲泉僧永頤  其二','周弼','宋','宋诗','song-poetry','','[]','頌罷南華誰得聞，兩川寒玉一禪身。',32,'全唐诗/poet.song.208000.json','["頌罷南華誰得聞，兩川寒玉一禪身。", "松邊彈舌低聲念，莫引龍來變作人。"]'),
('669364c4-abe5-4a47-bfc8-37759aa76896','贈從古上人','周弼','宋','宋诗','song-poetry','','[]','山僧袖出新詩卷，字字馨香撲人面。',32,'全唐诗/poet.song.208000.json','["山僧袖出新詩卷，字字馨香撲人面。", "清晨何處展看來，捲得梅花兩三片。"]'),
('6e300350-e85a-46c4-93e2-38a39b95e50f','野廟','周弼','宋','宋诗','song-poetry','','[]','野廟荒蕪倒掩扉，寂寥香火客來稀。',32,'全唐诗/poet.song.208000.json','["野廟荒蕪倒掩扉，寂寥香火客來稀。", "年年歸燕相看覷，空滴春泥損畫衣。"]'),
('673f4c2c-386e-4e6b-bbf2-5a33314d737a','真娘墓','周弼','宋','宋诗','song-poetry','','[]','青鳥傳書渡海遲，亂山衰草葬蛾眉。',32,'全唐诗/poet.song.208000.json','["青鳥傳書渡海遲，亂山衰草葬蛾眉。", "錦囊消歇餘香在，狼藉春風荳蔻枝。"]'),
('edc0a225-0ed7-4403-b85c-d9fccaf68d94','女墳湖','周弼','宋','宋诗','song-poetry','','[]','石龜無語對東風，海鶴曾迷曉市中。',32,'全唐诗/poet.song.208000.json','["石龜無語對東風，海鶴曾迷曉市中。", "三十六鱗朝夜月，玉釵人在水晶宮。"]'),
('97268c69-2845-4c4e-9e76-6c480f427235','顯應觀桃花','周弼','宋','宋诗','song-poetry','','[]','白雲隨鶴乘將去，深碧桃花滿故宮。',32,'全唐诗/poet.song.208000.json','["白雲隨鶴乘將去，深碧桃花滿故宮。", "三十六簧明月夜，不知何處吸春風。"]'),
('eb9ee288-ffb5-43f7-8bc7-ce76420e958f','四聖觀','周弼','宋','宋诗','song-poetry','','[]','小園寬占一山孤，別有牆遮古觀居。',32,'全唐诗/poet.song.208000.json','["小園寬占一山孤，別有牆遮古觀居。", "到了恩波攔不住，水窗遊出放生魚。"]'),
('490348be-b908-4870-bbd4-1d7c44e9cecc','蠟梅','周弼','宋','宋诗','song-poetry','','[]','愛花偏倩獵人尋，殘雪偷春上棘林。',32,'全唐诗/poet.song.208000.json','["愛花偏倩獵人尋，殘雪偷春上棘林。", "山岸有誰先得見，冷香疏亞辟寒金。"]'),
('29e5fc20-01a4-45b4-b787-f7295614eedb','詠史二首  其一','周弼','宋','宋诗','song-poetry','','[]','一曲呼凰下九霄，石臺春靜海山遥。',32,'全唐诗/poet.song.208000.json','["一曲呼凰下九霄，石臺春靜海山遥。", "周秦戰血縱橫盡，猶卧白雲吹洞簫。"]'),
('52c73ff4-24a0-43e9-930d-bc9dad73f522','詠史二首  其二','周弼','宋','宋诗','song-poetry','','[]','碧樹童童蔭屋廬，分明青蓋畫龍車。',32,'全唐诗/poet.song.208000.json','["碧樹童童蔭屋廬，分明青蓋畫龍車。", "南陽病叟成何事，便謂枯池活得魚。"]'),
('51ee9659-a20c-47d9-82a1-36ea764ba2ec','送人遊西山  其一','周弼','宋','宋诗','song-poetry','','[]','昔人深夜看星斗，鎮壓靈壇尚有符。',32,'全唐诗/poet.song.208000.json','["昔人深夜看星斗，鎮壓靈壇尚有符。", "偷寫只應蒼鼠慣，幾行丹篆繞春蕪。"]'),
('5cdeca13-25cf-446a-b2cb-3b3910667956','送人遊西山  其二','周弼','宋','宋诗','song-poetry','','[]','鎖斷寒蛟亦有神，冷波寒水病殘身。',32,'全唐诗/poet.song.208000.json','["鎖斷寒蛟亦有神，冷波寒水病殘身。", "誰收匙鑰權相借，略放天池洗白鱗。"]'),
('d1ee0ce0-9e38-4e77-aeba-a6973499500c','送人遊西山  其三','周弼','宋','宋诗','song-poetry','','[]','抽鉛點汞舊臺荒，何處搜尋舊草堂。',32,'全唐诗/poet.song.208000.json','["抽鉛點汞舊臺荒，何處搜尋舊草堂。", "誰見洪崖最深處，一坑泥護石中黄。"]'),
('0dc3f49a-5330-42b9-b648-2c23aa1b66c4','出關偶題','周弼','宋','宋诗','song-poetry','','[]','一曲長歌浙水寒，綈袍空往又空還。',32,'全唐诗/poet.song.208000.json','["一曲長歌浙水寒，綈袍空往又空還。", "咸陽若有山東志，莫放蘇秦又出關。"]'),
('5efa7076-7a65-4947-a800-835e05c97d37','吳門送同行者之毗陵','周弼','宋','宋诗','song-poetry','','[]','布帆何處定逢春，身是歸人又送君。',32,'全唐诗/poet.song.208000.json','["布帆何處定逢春，身是歸人又送君。", "明日隔城回首望，冷花寒葉滿秋雲。"]'),
('dc6988dc-6efe-4559-8a93-d951c191b97d','西湖初夏','周弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','花飛春減綠陰成，不住風光繞禁城。',32,'全唐诗/poet.song.208000.json','["花飛春減綠陰成，不住風光繞禁城。", "山寺晚晴蟬欲噪，柳林猶囀數聲鶑。"]'),
('d4d150ae-a577-4396-ad01-12df6c88594f','送曲江友人南歸','周弼','宋','宋诗','song-poetry','','[]','憐君歸橐路迢迢，到得茅齋轉寂寥。',32,'全唐诗/poet.song.208000.json','["憐君歸橐路迢迢，到得茅齋轉寂寥。", "應歎藥欄經雨爛，土肥抽盡縮砂苗。"]'),
('d6bd0848-95da-47f3-9ea5-550a3c43ccce','客樓','周弼','宋','宋诗','song-poetry','','[]','水國秋清潮半生，越王臺殿鎖荒城。',32,'全唐诗/poet.song.208000.json','["水國秋清潮半生，越王臺殿鎖荒城。", "西樓一夜思歸客，斜倚朱欄獨聽笙。"]'),
('ff5665cd-6017-41ca-804f-7e491f8a5ebb','夜深','周弼','宋','宋诗','song-poetry','','[]','虛堂人靜不聞更，獨坐書灰對夜燈。',32,'全唐诗/poet.song.208000.json','["虛堂人靜不聞更，獨坐書灰對夜燈。", "門外不知春雪霽，半峰殘月一溪冰。"]'),
('0c5e220c-ed3f-4be3-aed0-ece8fcb60b2d','胥門','周弼','宋','宋诗','song-poetry','','[]','蘆葦蕭蕭生晚潮，伍員何地更吹簫。',32,'全唐诗/poet.song.208000.json','["蘆葦蕭蕭生晚潮，伍員何地更吹簫。", "夕陽自逐寒鴉去，萬片宮花共寂寥。"]'),
('6d8aa2a7-9a65-4116-9b96-24d6912ba492','送人還姑蘇','周弼','宋','宋诗','song-poetry','','[]','別十三年返故居，可憐世業半空虛。',32,'全唐诗/poet.song.208000.json','["別十三年返故居，可憐世業半空虛。", "布囊惟有焦琴在，乞與秋風葬闔閭。"]'),
('51e338c1-5933-4017-8ea6-3061aa5a101b','題僧子溫畫水墨蒲萄','周弼','宋','宋诗','song-poetry','','[]','裊裊多應半熟時，落斜高掛冷攢枝。',32,'全唐诗/poet.song.208000.json','["裊裊多應半熟時，落斜高掛冷攢枝。", "分明記得山窗下，一架寒藤带雨垂。"]'),
('906e935b-f6dc-490d-9719-2392b1ee45be','望太湖  其一','周弼','宋','宋诗','song-poetry','','["\u592a\u6e56"]','獨立瀰漫灝氣中，倍饒雲霧杳重重。',32,'全唐诗/poet.song.208000.json','["獨立瀰漫灝氣中，倍饒雲霧杳重重。", "直西一道孤光起，指點人看是白龍。"]'),
('fbb156fc-94f1-43ab-b163-91cf09148f86','望太湖  其二','周弼','宋','宋诗','song-poetry','','["\u592a\u6e56"]','眼力難窮遠即昏，縱晴惟只兩三分。',32,'全唐诗/poet.song.208000.json','["眼力難窮遠即昏，縱晴惟只兩三分。", "今朝林屋人皆見，不似峰巒只似雲。"]'),
('0c9baae0-56bf-43ec-bf72-eb22188e7ece','收家信','周弼','宋','宋诗','song-poetry','','[]','渺渺秋風生白波，故鄉歸夢隔山河。',32,'全唐诗/poet.song.208000.json','["渺渺秋風生白波，故鄉歸夢隔山河。", "可憐一紙平安信，不及衡陽雁字多。"]'),
('700fcfbe-97e4-432d-bf08-95f4ac72d91b','聞友人過吳','周弼','宋','宋诗','song-poetry','','[]','詩囊掛在船篷上，吟過江楓落葉中。',32,'全唐诗/poet.song.208000.json','["詩囊掛在船篷上，吟過江楓落葉中。", "爲恐吳牋題不盡，秋風先燥數堆紅。"]'),
('da6b4305-7327-4fc9-b2b1-2c389b50b480','彩雲橋','周弼','宋','宋诗','song-poetry','','[]','斷橋流水兩無期，殘日輕雲處處疑。',32,'全唐诗/poet.song.208000.json','["斷橋流水兩無期，殘日輕雲處處疑。", "乞與行人自沽酒，滿旗風雨豆花籬。"]'),
('36068ffd-ff74-4da7-b660-6739520c989c','龍井道中雜紀  其一','周弼','宋','宋诗','song-poetry','','[]','白髮宮人頻笑謔，羅衣昔對君王著。',32,'全唐诗/poet.song.208000.json','["白髮宮人頻笑謔，羅衣昔對君王著。", "夜驚春雨洗桃花，夢魂猶掛鞦韆索。"]'),
('0d6f6a65-78d2-4b66-85b9-b1f9c7b383df','龍井道中雜紀  其二','周弼','宋','宋诗','song-poetry','','[]','老僧病久聲嘶喝，屢說紫衣勝短褐。',32,'全唐诗/poet.song.208000.json','["老僧病久聲嘶喝，屢說紫衣勝短褐。", "莫嫌兩手漸拘攣，曾把御前供奉鈸。"]'),
('0a9b4166-268a-4087-aef2-425396d2e262','山崦早梅','周弼','宋','宋诗','song-poetry','','[]','晴逼寒笆春滿鄰，漢奩芳額漸輕勻。',32,'全唐诗/poet.song.208000.json','["晴逼寒笆春滿鄰，漢奩芳額漸輕勻。", "東風未放全消息，雨萼愁香不見人。"]'),
('92169042-3897-47c7-82a9-e4f154d8e86a','青陽驛','周弼','宋','宋诗','song-poetry','','[]','悄悄如秋麥氣凉，山風吹透濕衣裳。',32,'全唐诗/poet.song.208000.json','["悄悄如秋麥氣凉，山風吹透濕衣裳。", "小爐深幌枯松火，一夜寒香遶客床。"]'),
('8025c241-712c-4a7c-8097-50c17e57ee83','舟次黄鶴磯','周弼','宋','宋诗','song-poetry','','[]','俯爲江山特地來，勢須時暫走塵埃。',32,'全唐诗/poet.song.208000.json','["俯爲江山特地來，勢須時暫走塵埃。", "稍閑便著携官酒，一酹吳王舊釣臺。"]'),
('82b0e9ba-4f93-43d2-864f-229da17f1422','聞雁','周弼','宋','宋诗','song-poetry','','[]','此是衡陽第幾羣，寂寥偏雜雨聲聞。',32,'全唐诗/poet.song.208000.json','["此是衡陽第幾羣，寂寥偏雜雨聲聞。", "如今遠道多矰繳，莫厭高飛入暮雲。"]'),
('959be201-4066-4e4b-a4b3-5698f07e3d17','風惡偶成二首  其一','周弼','宋','宋诗','song-poetry','','[]','柔櫓雙隨下水船，亂帆輕舵遞相先。',32,'全唐诗/poet.song.208000.json','["柔櫓雙隨下水船，亂帆輕舵遞相先。", "無端繫著山村岸，高枕蘆芽對雨眠。"]'),
('c2abb8bb-00ff-41b0-ac3d-7ba64caf3899','風惡偶成二首  其二','周弼','宋','宋诗','song-poetry','','[]','三日要行還止住，冷沙寒水暗消春。',32,'全唐诗/poet.song.208000.json','["三日要行還止住，冷沙寒水暗消春。", "一千四百蕪湖路，怨雨愁風多少人。"]'),
('73d6d955-1832-44b3-8f18-5885df18022d','溧陽桃花','周弼','宋','宋诗','song-poetry','','[]','見說謫仙曾到此，東風千樹鎖雕牆。',32,'全唐诗/poet.song.208000.json','["見說謫仙曾到此，東風千樹鎖雕牆。", "游人偏向花間酹，雨濕春泥噴酒香。"]'),
('03c7ffd0-3ea3-4414-b68f-77418438e9b9','延山渡','周弼','宋','宋诗','song-poetry','','[]','解帆登岸作山遊，林木茅茨共一丘。',32,'全唐诗/poet.song.208000.json','["解帆登岸作山遊，林木茅茨共一丘。", "數日驟寒消不盡，尚餘殘雪護松瘤。"]'),
('4d740e24-47ac-4d55-9f19-f0cf0a7b36d5','蕭山縣下遇雨二首  其一','周弼','宋','宋诗','song-poetry','','[]','年來沙漲卒難消，更覺西興渡口遥。',32,'全唐诗/poet.song.208000.json','["年來沙漲卒難消，更覺西興渡口遥。", "冷坐看他騎騍馬，半鞍泥水踏春潮。"]'),
('c08232ba-6f75-47ba-b23b-48ed6a76aceb','蕭山縣下遇雨二首  其二','周弼','宋','宋诗','song-poetry','','[]','悠悠心厭出江沙，過得丘亭轉落斜。',32,'全唐诗/poet.song.208000.json','["悠悠心厭出江沙，過得丘亭轉落斜。", "村店自知行客倦，勸嘗新酒賣甜瓜。"]'),
('e825b08b-d360-4a7f-9d92-4a7230f49911','大洲湖','周弼','宋','宋诗','song-poetry','','[]','人居澤國勝居陵，十月陂塘未結冰。',32,'全唐诗/poet.song.208000.json','["人居澤國勝居陵，十月陂塘未結冰。", "殘葦亂茭收拾後，斷筐分曬折腰菱。"]'),
('a9601f03-21fa-4f0e-bea6-80235b27681b','道間偶成','周弼','宋','宋诗','song-poetry','','[]','彎彎田角路周遭，摘盡柔桑露淺蒿。',32,'全唐诗/poet.song.208000.json','["彎彎田角路周遭，摘盡柔桑露淺蒿。", "無限寂寥門半掩，一車偏健夕陽繰。"]'),
('14b5448c-814c-48af-ae74-9eaf178d0dd5','早春','周弼','宋','宋诗','song-poetry','','[]','連朝微雪暗消凝，始覺春風逐旋增。',32,'全唐诗/poet.song.208000.json','["連朝微雪暗消凝，始覺春風逐旋增。", "今早畫簷偏有意，數條吹折曬殘冰。"]'),
('61db9570-262a-4e22-b8fb-74dc9c5fd7e5','送人之漢上','周弼','宋','宋诗','song-poetry','','[]','舊來邊塞自多塵，瘦草寒花强作春。',32,'全唐诗/poet.song.208000.json','["舊來邊塞自多塵，瘦草寒花强作春。", "見說連年更悽愴，亂螢隨趁鬼迷人。"]'),
('2b5fd7b6-3d5a-44a6-b813-8c6e5067aace','思歸  其一','周弼','宋','宋诗','song-poetry','','[]','閙裏看山不識真，偶來軒檻振衣塵。',32,'全唐诗/poet.song.208000.json','["閙裏看山不識真，偶來軒檻振衣塵。", "諸峰便覺移相就，分付春風欲去人。"]'),
('723f09c3-c8d6-41ce-904b-1a48fc9e2491','思歸  其二','周弼','宋','宋诗','song-poetry','','[]','點點楊花飛滿洲，只應催促送行舟。',32,'全唐诗/poet.song.208000.json','["點點楊花飛滿洲，只應催促送行舟。", "非關向晚傷心事，自怯春寒不肯留。"]'),
('853187bb-8e58-4ca8-9de0-3a6ebdcfc8b4','思歸  其三','周弼','宋','宋诗','song-poetry','','[]','盡日憑欄客興濃，山雖西遶水還東。',32,'全唐诗/poet.song.208000.json','["盡日憑欄客興濃，山雖西遶水還東。", "便乘春暮家園去，猶及棠梨滿徑風。"]'),
('cd8307d1-887a-4e32-8939-6e701ab2e808','思歸  其四','周弼','宋','宋诗','song-poetry','','[]','自覺才疏久願歸，敢將山色便相依。',32,'全唐诗/poet.song.208000.json','["自覺才疏久願歸，敢將山色便相依。", "漢家事業雖全盛，亦放梁鴻一箇飛。"]'),
('c067d40c-65ee-4f83-a585-15469a378d7b','贈野逸  其一','周弼','宋','宋诗','song-poetry','','[]','時康難售賈生醫，諫鼓無聲對落暉。',32,'全唐诗/poet.song.208000.json','["時康難售賈生醫，諫鼓無聲對落暉。", "又報一年花信了，滿山鶗鴂送春歸。"]'),
('d6ce7e1f-5a40-4e55-8df4-47491b19b5b8','贈野逸  其二','周弼','宋','宋诗','song-poetry','','[]','悠悠行路雪侵頭，擬出重關洗弊裘。',32,'全唐诗/poet.song.208000.json','["悠悠行路雪侵頭，擬出重關洗弊裘。", "堤上忽逢憔悴客，背花停酒說通州。"]'),
('1e07fe2b-3814-445d-b390-1cb586d60d41','下渚秋暮','周弼','宋','宋诗','song-poetry','','[]','淺灘近渚沙相接，水落漁人朝暮涉。',32,'全唐诗/poet.song.208000.json','["淺灘近渚沙相接，水落漁人朝暮涉。", "摵摵風鳴若雨來，繞堤吹散乾荷葉。"]'),
('7e0cb2af-3e9d-4ff4-93f4-4bdf06ba8b03','秋日馬上','周弼','宋','宋诗','song-poetry','','[]','本無謀略强談兵，每愧臨邊病未能。',32,'全唐诗/poet.song.208000.json','["本無謀略强談兵，每愧臨邊病未能。", "筋力豈知猶可喜，一鞍千里到江陵。"]'),
('fa6ba300-262c-45e2-b098-2e20f3bb7bef','許市罩魚','周弼','宋','宋诗','song-poetry','','[]','網邊分得尾纖纖，腥却蓴絲莫厭嫌。',32,'全唐诗/poet.song.208000.json','["網邊分得尾纖纖，腥却蓴絲莫厭嫌。", "自有野人相料理，柳陰茅店一包鹽。"]'),
('d138e08e-c66e-465c-b442-bcb21ca2feb5','歲除思歸  其一','周弼','宋','宋诗','song-poetry','','[]','山棲書到多日，野渡舟橫幾回。',28,'全唐诗/poet.song.208000.json','["山棲書到多日，野渡舟橫幾回。", "想見溪邊亭上，故人待我銜盃。"]'),
('8c8e4de4-7d4f-48bf-88ce-ef23ba6c6990','歲除思歸  其二','周弼','宋','宋诗','song-poetry','','[]','春風冰斷千尺，曉霽雲開百重。',28,'全唐诗/poet.song.208000.json','["春風冰斷千尺，曉霽雲開百重。", "何處溪橋爭渡，誰家山寺聞鍾。"]'),
('97419b6a-5dde-4d73-9d69-b71f988739d6','歲除思歸  其三','周弼','宋','宋诗','song-poetry','','[]','野屋定堆落葉，山徑應鋪石蕪。',28,'全唐诗/poet.song.208000.json','["野屋定堆落葉，山徑應鋪石蕪。", "一別經秋不到，隔籬黄犬誰呼。"]'),
('49c26b72-6286-4cf2-94e4-7f70967bc3f8','題蕺山僧竹閣','周弼','宋','宋诗','song-poetry','','[]','高閣俯人世，越香清古岑。',96,'全唐诗/poet.song.208000.json','["高閣俯人世，越香清古岑。", "林表山煙薄，竹多苔色深。", "露笋翻曉籜，雲房生晝陰。", "天風自然來，明月照我琴。", "景豁謝幽事，竟日聆仙禽。", "佳言出奇觀，清梵揚空音。", "子猷昔好此，故園今陸沈。", "睠然顧茲賞，蕭蕭生道心。"]'),
('d8c48151-83a2-4beb-b91a-ec6e5caa654c','久客思歸感興','周弼','宋','宋诗','song-poetry','','[]','久客空江上，閒吟對石門。',48,'全唐诗/poet.song.208000.json','["久客空江上，閒吟對石門。", "青山非遠近，流水自朝昏。", "夜月添鄉夢，春風入燒痕。", "翻思南郭路，迢遞隔煙村。"]'),
('8c4823d0-ff4c-42a9-89ac-087245c000d8','訪別','周弼','宋','宋诗','song-poetry','','[]','聖代吟家衆，無君衆體詩。',48,'全唐诗/poet.song.208000.json','["聖代吟家衆，無君衆體詩。", "數奇官職見，心苦道途知。", "積夢難相寄，流年自各悲。", "金閨催製錦，又復向黄陂。"]'),
('3afafbbd-4478-48be-9756-c0b95a4503cb','溪館送別','周弼','宋','宋诗','song-poetry','','[]','旅館成佳集，臨觴送遠征。',48,'全唐诗/poet.song.208000.json','["旅館成佳集，臨觴送遠征。", "厨煙含燭焰，溪雨奪琴聲。", "愁動草邊色，恨牽花外情。", "明朝過平望，應念隔春更。"]'),
('ac6c03d6-a6a9-4577-bb87-605c088505f7','晚泊','周弼','宋','宋诗','song-poetry','','[]','芳草渡頭猿夜吟，孤舟一繫百年心。',64,'全唐诗/poet.song.208000.json','["芳草渡頭猿夜吟，孤舟一繫百年心。", "舊遊零落不知數，客路經過空復尋。", "暮雪關山千里雁，夕陽煙火數家林。", "明朝歎息東征士，髮垢冠欹不欲簪。"]'),
('d577d3fa-0881-4e38-8167-92519ccbf1bd','鄱陽湖四十韻','周弼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','巨浸連吳越，高躔直斗牛。',293,'全唐诗/poet.song.208000.json','["巨浸連吳越，高躔直斗牛。", "玄明開別府，江伯匯支流。", "象緯元精逼，神姦祕怪裒。", "番君疏带礪，彭蠡壯襟喉。", "赴隙如無地，憑壖忽有州。", "津涯逾寫潤，窟宅定刳幽。", "島認瀛鼇戴，濤疑陣馬蒐。", "珠跳憐雨駛，鏡滑識風收。", "樹带喬枝隠，山餘短碧浮。", "窺覘疲罔象，睥睨忲陽侯。", "漾月都迷皓，蒸雲間作油。", "涵濡均藻荇，冗長到{丷/八}鰍。", "蜃幻晴噓閣，龍腥夜拔湫。", "萬尋縣圃玉，一带洞庭秋。", "盈縮知誰紀，吞并似力揫。", "鯉矜封赤鯶，龜笑斥朱眸。", "嵌竇扶桑齧，珍文匠石鎪。", "鷗羣馴野客，蚖肆傲潛虯。", "罟數筐零霰，檣輕弩激鍭。", "孰分浮瓠澨，或訝繞蛇丘。", "弦索延商婦，舽艭送莫愁。", "陶朱誠得策，神禹想遺憂。", "端稱潺湲弄，非無隠伏搜。", "豆分高下渚，葦視去來舟。"]'),
('4bf64cee-991a-4e7a-b9ef-c14a195602d1','溪亭話別','周弼','宋','宋诗','song-poetry','','[]','芳時談古調，霅浦少人同。',24,'全唐诗/poet.song.208000.json','["芳時談古調，霅浦少人同。", "化日桃花外，歸船便隔春。"]'),
('ec9ccfa7-87c8-48c5-b0a2-1c365369445e','題湖上壁','周弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒食風埃滿客襟，西湖煙雨送愁頻。',32,'全唐诗/poet.song.208000.json','["寒食風埃滿客襟，西湖煙雨送愁頻。", "日高未起鳥呼夢，春晚不歸花笑人。"]'),
('34644bff-9d33-47cf-a11a-410d320cc5bc','贈別水雲翁','周弼','宋','宋诗','song-poetry','','[]','離離雙鬢似秋蓬，慣逐沙鷗與斷鴻。',32,'全唐诗/poet.song.208000.json','["離離雙鬢似秋蓬，慣逐沙鷗與斷鴻。", "漂母磯頭春水闊，扁舟何處繫東風。"]'),
('74122b46-e92b-4d53-b05d-68fdf564fbba','煙中梅','周弼','宋','宋诗','song-poetry','','[]','冷花疎蕊竹間橫，淺薄籠煙淡作晴。',32,'全唐诗/poet.song.208000.json','["冷花疎蕊竹間橫，淺薄籠煙淡作晴。", "怊悵野橋春水斷，幾回相見不分明。"]'),
('d39c1a55-5fcc-4934-bd8c-b32f57c4a381','檢校金蓋別業','周弼','宋','宋诗','song-poetry','','[]','獨棹一溪雲，山回景自分。',48,'全唐诗/poet.song.208000.json','["獨棹一溪雲，山回景自分。", "露花藏岸勢，風葉亂泉紋。", "短箭催年急，微陽近草曛。", "斷猿將落木，清夜不堪聞。"]'),
('8d1e1b5d-e030-45cc-a0c4-52d00bf0275d','吳歌','釋善珍','宋','宋诗','song-poetry','','[]','吳兒鳴艣吳波裏，作勞耳熱歌聲起。',151,'全唐诗/poet.song.208000.json','["吳兒鳴艣吳波裏，作勞耳熱歌聲起。", "初猶哇咬雜吁嚱，後方激訐如怨詈。", "芳洲日夕西風來，含情宛轉聲更哀。", "君不見杜老行吟曲江曲，楚臣羈思蘼蕪綠。", "世知忠義鑄偉辭，不知正是阮籍唐衢哭。", "吳時明月梧宮秋，月光曾照吳王愁。", "國人悲憐子胥死，寫出高臺草荒麋鹿游。", "詞亡千古留遺調，南楫北帆昏復曉。", "盡知往事祇蒼烟，渺渺漫漫飛白鳥。"]'),
('3ffd1a54-77f7-455f-ba2b-b417a3c166f8','和忠獻堂諸官韻','釋善珍','宋','宋诗','song-poetry','','[]','魏王爲將過頗牧，轉佐功高蕭相國。',224,'全唐诗/poet.song.208000.json','["魏王爲將過頗牧，轉佐功高蕭相國。", "洗光日轂上天衢，海宇竦瞻如立鶴。", "定儲不用招四老，知公狐鼠視産祿。", "青苗一疏更奇偉，時宰喙硬心愧服。", "當時元老不在廷，中外知非宗社福。", "至今荒棘沒銅駝，志士淚盡以血續。", "故祠金貂色已暗，英風可掃炎海酷。", "尚想喬嶽初降靈，鳳采龍文照山麓。", "聞孫來補翁祖處，玉題繡井新前躅。", "落成舉盃文字飲，高臺何必糟丘築。", "百年往事陵谷改，故國蒼然但喬木。", "公歸補衮居上前，諫草家藏皆可覆。", "才如蘇梅宇內少，流落應憐猶未復。", "曉枝蝶閙不足云，晚節要看秋圃菊。"]'),
('3b86d845-355c-486e-b673-3a54608cb311','和徐國錄韻','釋善珍','宋','宋诗','song-poetry','','[]','當今稱文宗，斗南一和仲。',264,'全唐诗/poet.song.208000.json','["當今稱文宗，斗南一和仲。", "掣鯨力倒海，蘭苕不同夢。", "百年日苦短，千載事誰共。", "賦詩推義山，論舊數季重。", "客持邀我讀，歡喜蹋破甕。", "疾抄畏紙盡，饑誦忘漿凍。", "欲傳換骨方，伎工恐無用。", "塗窗謾成鴉，過門任題鳳。", "唐僧句月鍊，一步不敢縱。", "高參鬼僊吟，下比古佛頌。", "湖江大國楚，宮闕天府雍。", "小大材則殊，未易求折衷。", "公文如珠玉，盛世盍包貢。", "一鶚剡交騰，萬牛挽難動。", "造物或困之，鬰怒使快痛。", "晉康名遠郡，侯印亦久弄。", "蜃噓橫跨海，龍潜中興宋。", "年豐秔稌多，守醉賓客從。", "時時寫烏絲，虹光穿屋棟。", "祖帳在何時，行色當倥傯。", "相期遠公社，後會邈澒洞。", "擬辦酒椀招，更出虎溪送。"]'),
('3936a06d-8f7e-4ae3-b8ea-74fedc5c3d74','送徐國錄守英德','釋善珍','宋','宋诗','song-poetry','','[]','君侯少舉摩天翮，筆陣堂堂萬人敵。',176,'全唐诗/poet.song.208000.json','["君侯少舉摩天翮，筆陣堂堂萬人敵。", "上書自請斗大州，不獨愛閑猶愛石。", "愛閑庭訟自簡寂，愛石不同牛李癖。", "參軍主簿公舉刺，何必喜怒見顔色。", "高臺盛貯錦屠蘇，何如烟林土花碧。", "公餘共賞有歡伯，語妙一笑欲墮幘。", "假令鰲禁未遭遇，傳至雞林能別識。", "大材小用從古然，善舞豈曾嫌地窄。", "愧無膚寸可及物，疊蓋重金竟何益。", "霜寒繫舟峽江側，應念坡仙撫遺跡。", "江流可沿深可𣂏，此水至潔能納汙。"]'),
('2ae35084-1e2b-4598-9e81-f9d4a657bf2f','送靜江曾帥','釋善珍','宋','宋诗','song-poetry','','[]','嶺西支郡聯荆湖，時危選帥勞廟謨。',160,'全唐诗/poet.song.208000.json','["嶺西支郡聯荆湖，時危選帥勞廟謨。", "公才健如天馬駒，胸中戈甲敵萬夫。", "向來持節犯賊區，賊降不用丈二殳。", "浮雲散盡明月孤，世間公論何時無。", "煌煌丹詔來天衢，陰風策策隨兵符。", "大旗十丈車前驅，弓刀武騎前後趨。", "我占福星歲在吳，孱虜數盡當磔誅。", "籠烽平安羽檄疎，玉帳亦可吟撫鬚。", "奏功入覲乘鋒車，峨冠儤直承明廬。", "公家事業青史書，公家祖相兄鴻樞。"]'),
('f729747f-17b1-452d-a1ed-de880129a93f','送傅左司赴袁州  其一','釋善珍','宋','宋诗','song-poetry','','[]','長安貂蟬賤如土，故家文獻餘一縷。',128,'全唐诗/poet.song.208000.json','["長安貂蟬賤如土，故家文獻餘一縷。", "平生粗疎不媚嫵，直語豈知犯張禹。", "腰間金印丈二組，我自棄置君自取。", "兒時翰墨跨諸父，投老爲郎方齒敘。", "天關耽耽守九虎，一節臨遣復不與。", "介堂卜築開宿莽，誰知公意頗有主。", "眼明沙鷗喜欲舞，便請衣冠挂神武。", "聖朝留戣非爲愈，勿薄淮陽宜叱馭。"]'),
('6848d484-fcb8-4fe0-b33e-d26679acf1cf','送傅左司赴袁州  其二','釋善珍','宋','宋诗','song-poetry','','[]','宜春古郡聯荆渚，曩年嘗夢公補處。',128,'全唐诗/poet.song.208000.json','["宜春古郡聯荆渚，曩年嘗夢公補處。", "崢嶸老氣橫九州，直前莫作分外慮。", "秋田旱渴思霖雨，君命敢徐寧畏暑。", "擊强鉏姦雷破柱，仰山古佛亦肯許。", "州黌一記最奇古，機綜遠祖昌黎愈。", "眼前瑣尾相品署，知公千百未一取。", "秋空仰瞻鴻鵠舉，政恐是中有新句。", "三年奏課返林塢，煮茶賀公公莫拒。"]'),
('94a20e14-bdc1-438b-b8d8-087e11ef8a6f','壽曾大監','釋善珍','宋','宋诗','song-poetry','','[]','公家中朝第一人，一門兄弟皆朱輪。',160,'全唐诗/poet.song.208000.json','["公家中朝第一人，一門兄弟皆朱輪。", "公材吏能固無敵，筆端亦自回千鈞。", "我生不識平津閣，晚識老監猶絕倫。", "長松閲世傲雲壑，萬牛回首山嶙峋。", "清都夢斷薄冠冕，三生髣髴賀季真。", "巋然靈光獨殿魯，閑似商皓深避秦。", "園林陰成鐘鼓樂，風波不駭鷗鷺馴。", "千卷賜書善和宅，萬金買石平泉春。", "古來此事總輸公，六環金带何足珍。", "封胡歲歲捧壽樽，蟠桃積核齊崑崙。"]'),
('194fa4bf-d9e4-4188-a99c-c31bddac5582','送趙吏部  其一','釋善珍','宋','宋诗','song-poetry','','[]','健才事聲名，撫案走百吏。',48,'全唐诗/poet.song.208000.json','["健才事聲名，撫案走百吏。", "法家冠柱文，好以殺爲戲。", "要留百年思，莫令一時畏。", "近時攀轅民，未必皆民意。"]'),
('f3eb3b1c-00d6-4cf9-8bda-d061df677460','送趙吏部  其二','釋善珍','宋','宋诗','song-poetry','','[]','千家煮蔗漿，萬里隨風桅。',48,'全唐诗/poet.song.208000.json','["千家煮蔗漿，萬里隨風桅。", "穀少蔗愈多，荒歲不療饑。", "初聞下令嚴，巨賈頗不怡。", "至今訓農文，可配七月詩。"]'),
('1a4fc20f-1462-4bf3-accd-944339f82a03','送趙吏部  其三','釋善珍','宋','宋诗','song-poetry','','[]','薏苡不類珠，疑似多謗傷。',48,'全唐诗/poet.song.208000.json','["薏苡不類珠，疑似多謗傷。", "恭惟大雅姿，南物不入囊。", "鈴齋一片石，歷劫難贊揚。", "常恐雞林客，夜半驚虹光。"]'),
('e045bf1a-0fb6-411e-8863-4f15158b7371','送趙吏部  其四','釋善珍','宋','宋诗','song-poetry','','[]','撫槎泝銀潢，手探支機石。',48,'全唐诗/poet.song.208000.json','["撫槎泝銀潢，手探支機石。", "天孫繭甕絲，擬補衮五色。", "星斗光離離，欲見無羽翼。", "舊恩倘可報，殺身奚足惜。"]'),
('feed0bdc-e7d4-424f-b932-e0eb96194f46','送陳上舍之潮州','釋善珍','宋','宋诗','song-poetry','','[]','元龍湖海士，豪氣卧大床。',156,'全唐诗/poet.song.208000.json','["元龍湖海士，豪氣卧大床。", "著書不療貧，仰面看屋梁。", "昔從諸老游，鬚鬢未老蒼。", "雄篇掩衆作，聲價如琳琅。", "謂當奏賦時，給札香案傍。", "不然如謫仙，布衣登玉堂。", "歲月忽已遲，驅車去潮陽。", "昌黎强項人，斷碑字字芳。", "當年駡佛表，正是護法章。", "大顛亦神奇，世豈有此郎。", "往者不可作，懷古多慨慷。", "有書寄新詩，無書勿相忘。", "善保千金軀，歲晚天雨霜。"]'),
('2aa3736b-e207-4941-86c1-788b54c1393f','送福帥吳侍郎趨朝','釋善珍','宋','宋诗','song-poetry','','[]','恕齋視民猶視兒，先憂兩字寒與饑。',120,'全唐诗/poet.song.208000.json','["恕齋視民猶視兒，先憂兩字寒與饑。", "三冬氣和春有脚，旱歲箋天天雨粟。", "愛杜呼母宗呼爺，史書弄筆人傳誇。", "異類鳴冤古有麽，神明循吏只一箇。", "風伯叫閽稱急報，政聲漲天怕天破。", "龍章夜下五雲間，玉宸喚歸碧落班。", "日邊馹騎催數數，截𩍐留公不停轂，安得雙輪生四角。"]'),
('245392d6-cdb1-4cf4-a985-01ec6360453f','東湖行','釋善珍','宋','宋诗','song-poetry','','[]','湖埆埆，泥駮駮，千夫萬夫鉏剝剝。',199,'全唐诗/poet.song.208000.json','["湖埆埆，泥駮駮，千夫萬夫鉏剝剝。", "菰蒲濛濛深復鑿，湖水渾黄車漉漉。", "朝車暮鑿聲不已，土山矗矗黄埃裏。", "山成蕢土不知幾，上頭望見滄海水。", "我疑神山海外八萬里，山憑鰲戴無根蔕。", "陽侯潜乘鰲力瘁，夜半負走倦復置。", "鼓紞紞，湖邊市。", "騮馬嘶，使君至。", "使君一犒炙千牛，酒舁銀甕糟成丘。", "工出農隙財出州，民肥官瘠農知不。", "君不見淮水頭，田荒白骨無人收。", "僧廬箕歛供防秋，健胡長戈舂爾喉。", "使君告爾農，汝今一勞永不憂，汝今一勞永不憂。"]'),
('f1b64f43-b8e0-4d4d-a0dc-b28ede8e4318','山溪謠','釋善珍','宋','宋诗','song-poetry','','[]','山溪流㶁㶁，山田半砂礫。',164,'全唐诗/poet.song.208000.json','["山溪流㶁㶁，山田半砂礫。", "羸牛領破耕不息，午饑眼花在牛脊。", "我饑田舍無糟糠，但願天常雨粟盈官倉。", "官租吏征有故常，官糴吏橫如虎狼。", "君不見先年春旱牛遇疫，妻兒挽犁代牛力。", "又不見前年龠米抵金璧，僵屍橫草烏不食。", "吏姦積久爲農患，吏愛穀貴農愛賤。", "使君道上聞農歎，下車蠲糴不待旦。", "令行去姦如疾風，心寧負官不負農。", "溪流帖帖船上下，左司文成高紙價。"]'),
('9a35779f-d077-401a-ade5-aee729437cb5','死交行','釋善珍','宋','宋诗','song-poetry','','[]','生交無百年，死交有千載。',62,'全唐诗/poet.song.208000.json','["生交無百年，死交有千載。", "百年追逐能幾何，千載義魄猶相待。", "死不知心，生交徒勞，指天誓日兒女曹。", "羊角哀，左伯桃，吁嗟此冢今蓬蒿。"]'),
('7c585a3b-f265-4199-982b-cf501b44053e','征婦怨效張籍','釋善珍','宋','宋诗','song-poetry','','[]','前年番兵來，郎戰淮河西。',64,'全唐诗/poet.song.208000.json','["前年番兵來，郎戰淮河西。", "官軍來上功，不待郎書題。", "淮河在何許，妾身那得去。", "生死不相待，白骨應解語。", "天寒無衣兒啼苦，妾身不如骨上土。"]'),
('6251e7de-6624-416b-a967-1ce721a8adae','古離別','釋善珍','宋','宋诗','song-poetry','','[]','切切復切切，壯士重離別。',67,'全唐诗/poet.song.208000.json','["切切復切切，壯士重離別。", "壯士別君去，萬里無回轍。", "暫時一樽酒，異日肝膽裂。", "何況岐路間，俄頃生白髮。", "君不見荆軻劍氣凌白虹，易水悲吟淚成血。"]'),
('0cdd13d7-b6e4-45cf-866a-ff2d09d0c4d8','古怨','釋善珍','宋','宋诗','song-poetry','','[]','少卿入胡庭，明妃辭漢殿。',84,'全唐诗/poet.song.208000.json','["少卿入胡庭，明妃辭漢殿。", "君恩如雨絕，生死難再見。", "至忠反爲逆，至美反爲賤。", "含冤天地間，日月爲誰轉。", "河梁泣滿衣，琵琶啼背面。", "千年傳樂府，曲變恨不變。", "常恐胡冢傍，夏月零霜霰。"]'),
('d3391e5a-fc37-49d4-bf9b-b1e62cfe178b','題逸少真蹟','釋善珍','宋','宋诗','song-poetry','','[]','淳化東都羣玉府，光蟠虹霓氣龍虎。',128,'全唐诗/poet.song.208000.json','["淳化東都羣玉府，光蟠虹霓氣龍虎。", "墨池筆冢千歲精，鸞鶱鳳翥來帝庭。", "帝好文似虬鬚主，盜奪鬼偷離復聚。", "珠宮玉函雷電護，犀辟塵埃芸辟蠹。", "崇寧別置書學員，司空無畏博士顛。", "鉤黨牽連穎與玄，氈包駝載遷幽燕。", "司卿巨卿怒裂眥，手攬脫身兵火裏。", "江南不得練兒評，流落無人識真僞。"]'),
('1ef2a91c-8cfe-4be0-bc75-58ecf2ebd76f','題三教三隠三仙三賢畫軸','釋善珍','宋','宋诗','song-poetry','','[]','瞿曇李耳東家丘，不生虞夏生衰周。',168,'全唐诗/poet.song.208000.json','["瞿曇李耳東家丘，不生虞夏生衰周。", "世亂殺奪無時休，佛現身作大慈舟。", "老務靜治銷戈矛，孔以筆誅著春秋。", "學佛亦有絕世流，學老曾見飛昇不。", "最後三人師孔氏，氣節雖同窮達異。", "淵明不仕義熙歲，傾家釀秫供一醉。", "翰林謫仙與蘇二，卒以蛾眉招衆忌。", "脫靴偶忤高力士，觸撥玉環良細事。", "誰知紹述丞相嗔，銅駝陌上荒荆榛。", "僧伽擁扶度鯨海，虜酋過墳禁樵採，使我掩卷增感慨。"]'),
('fdaeabad-0a33-4ad0-855b-6939b57ee52c','又題','釋善珍','宋','宋诗','song-poetry','','[]','李耳西游丘泣麟，戰國十二終一秦。',120,'全唐诗/poet.song.208000.json','["李耳西游丘泣麟，戰國十二終一秦。", "祖龍坑儒儒不死，溺冠復生赤龍子。", "有孫作帝癡求仙，茂陵松柏荒蒼烟。", "瞿曇說法忉利天，下視塵世磨蟻旋。", "丈六身坐黄金蓮，孔老仰望不及肩。", "魏晉隋唐如過鳥，雲外高人眠未曉。", "坡乘剛風爲奎星，白舒逸氣追長鯨，淵明醉鼾猶雷聲。"]'),
('acdf6f5e-f311-473c-b89f-17e44de1a7cc','題東坡儋耳書西江月','釋善珍','宋','宋诗','song-poetry','','[]','儋州禿鬢翁，老氣凌汗漫。',68,'全唐诗/poet.song.208000.json','["儋州禿鬢翁，老氣凌汗漫。", "金鑾嶺海等游戲，盡倒銀河洗憂患。", "山村荷瓢感慨欹，買酒獨賞春夢婆。", "酒酣忽轉商聲急，龍君悲咤波臣泣，錦瑟無端絃五十。"]'),
('8a7f1084-d2ba-4412-a71a-8f3ce6750344','題蓮社圖','釋善珍','宋','宋诗','song-poetry','','[]','遠師東林白蓮社，世上丹青好傳寫。',88,'全唐诗/poet.song.208000.json','["遠師東林白蓮社，世上丹青好傳寫。", "愛陶醉漢招不來，送陸道士大笑回。", "千年此意畫得麽，俗工凡筆何塵埃。", "涪州逐客無聊頼，買酒過溪譏破戒。", "詩人口業不自持，袖手默坐君應知，生天成佛佛是誰。"]'),
('9149275e-c327-4431-8f75-ba79e00d0c27','龍泉山中','釋善珍','宋','宋诗','song-poetry','','[]','自墾屋頭三四畦，得閒時復事鉏犁。',64,'全唐诗/poet.song.208000.json','["自墾屋頭三四畦，得閒時復事鉏犁。", "花粘蛛網礙蜂度，樹带鷹巢無雀栖。", "嘯罷半山聞逸響，詩成絕壁見新題。", "老來定力人難轉，菜葉放教流出溪。"]'),
('e224315f-74fc-4515-b28f-ef30d70d38a1','逢春','釋善珍','宋','宋诗','song-poetry','','[]','衰老逢春能幾回，自憐光景賦殘梅。',64,'全唐诗/poet.song.208000.json','["衰老逢春能幾回，自憐光景賦殘梅。", "齒牙落盡舌猶在，年歲閲多心尚孩。", "座上麈閒談客去，手中書墮睡魔來。", "生平癡絕真堪歎，千古文章水一杯。"]'),
('97eaf775-6932-495c-8984-2c8aa0abd6c9','小雪','釋善珍','宋','宋诗','song-poetry','','[]','雲暗初成霰點微，旋聞蔌蔌洒窗扉。',64,'全唐诗/poet.song.208000.json','["雲暗初成霰點微，旋聞蔌蔌洒窗扉。", "最愁南北犬驚吠，兼恐北風鴻退飛。", "夢錦尚堪裁好句，鬢絲那可織寒衣。", "擁爐睡思難撐拄，起喚梅花爲解圍。"]'),
('17c352d4-4045-4dad-927a-a06001fe4133','賀趙禮部得祠二首  其一','釋善珍','宋','宋诗','song-poetry','','[]','曩歲巍冠接俊髦，玄都又種幾番桃。',64,'全唐诗/poet.song.208000.json','["曩歲巍冠接俊髦，玄都又種幾番桃。", "山中供奉猶遭謗，澤畔靈均盍賦騷。", "世事萬端常倚仗，丈夫百挫見雄豪。", "旁人妄指籠中翮，不識冥鴻天宇高。"]'),
('86911b76-d4ec-43b1-94e9-ae81989a946b','賀趙禮部得祠二首  其二','釋善珍','宋','宋诗','song-poetry','','[]','帝賜琳宮散吏名，寄聲黄閤謝弓旌。',64,'全唐诗/poet.song.208000.json','["帝賜琳宮散吏名，寄聲黄閤謝弓旌。", "琴招野客持盃聽，棋看癡人覆局爭。", "燕頷終當飛食肉，蛾眉最忌美傾城。", "晴空萬里君知不，蒼狗白雲常變更。"]'),
('70953dec-f5da-4684-a384-823954577ba2','呈傅左司','釋善珍','宋','宋诗','song-poetry','','[]','左司聲價過韋郎，小却宜盛白玉堂。',64,'全唐诗/poet.song.208000.json','["左司聲價過韋郎，小却宜盛白玉堂。", "龍卧密雲還不雨，鴂啼衆草自無芳。", "江湖旱地千里赤，淮蜀胡塵十丈黄。", "持節暫閒寧袖手，爲君畫策射天狼。"]'),
('40c14817-3b40-418a-a2d2-59861e871332','林節推架軒扁水木清華','釋善珍','宋','宋诗','song-poetry','','[]','紅滿芳波綠滿蹊，公餘無事似幽棲。',64,'全唐诗/poet.song.208000.json','["紅滿芳波綠滿蹊，公餘無事似幽棲。", "臨池洗硯看魚躍，對竹坐衙聞鳥啼。", "胸次九流如鏡浄，壁間片錦與花齊。", "雲霄別有清華地，早晚朝車過竹溪。"]'),
('ebf9552b-bb6b-4f2b-a704-9720319bfb9f','苔徑','釋善珍','宋','宋诗','song-poetry','','[]','苔徑長年斷俗蹤，亦無交舊可過從。',64,'全唐诗/poet.song.208000.json','["苔徑長年斷俗蹤，亦無交舊可過從。", "閑憂頹墮自鉏菜，老尚怪奇惟種松。", "履破背時翻著襪，詩狂見月亂撞鐘。", "千年陶謝今誰似，恐有山林不易逢。"]'),
('29270559-6e08-4915-9cae-aaeeae4b0ff9','賀劉後村除兵侍兼直院','釋善珍','宋','宋诗','song-poetry','','[]','人物依然元祐中，鶑邊繫馬亦金狨。',64,'全唐诗/poet.song.208000.json','["人物依然元祐中，鶑邊繫馬亦金狨。", "相君惟憶劉夫子，學士須還儋禿翁。", "翰苑鶴天雙鬢雪，玄都燕麥幾春風。", "老來始得文章力，前有歐公後益公。"]'),
('e55b8929-64d2-4048-a131-b6391329805c','送趙禮部提舉江西','釋善珍','宋','宋诗','song-poetry','','[]','玉節來臨昔治州，儀曹爽氣更橫秋。',64,'全唐诗/poet.song.208000.json','["玉節來臨昔治州，儀曹爽氣更橫秋。", "未誇判筆摇山岳，且喜仙槎近斗牛。", "童拾棠陰前竹馬，紗籠寺壁舊銀鉤。", "南塘遺稿公新卷，他日人傳作話頭。"]'),
('83c7475b-c432-48a7-87b9-2bafcd1f96c4','看書憶北磵','釋善珍','宋','宋诗','song-poetry','','[]','無事看書倦即休，心靈遠與古人游。',64,'全唐诗/poet.song.208000.json','["無事看書倦即休，心靈遠與古人游。", "常尊賈島呼吟佛，盍請劉伶謚醉侯。", "歲晚庭梅真益友，天寒爐火是重裘。", "兩冬京浙無消息，老磵年來安健不。"]'),
('c68f3f46-0859-4a7f-abb0-6b4005d5b466','寄照晦巖','釋善珍','宋','宋诗','song-poetry','','[]','身世浮沈莫更論，百年大笑付乾坤。',64,'全唐诗/poet.song.208000.json','["身世浮沈莫更論，百年大笑付乾坤。", "機關鬼面神頭戲，歲月風檣陣馬奔。", "時過黄扉俄瘴海，寵衰金屋又長門。", "人生萬事真難料，不若深山無怨恩。"]'),
('59c77650-22af-4115-a1c8-539ed6e3f23f','歲晚寄愚谷','釋善珍','宋','宋诗','song-poetry','','[]','病餘顧影瘦崚嶒，閲歲無過白髮增。',64,'全唐诗/poet.song.208000.json','["病餘顧影瘦崚嶒，閲歲無過白髮增。", "天與聰明減癡福，年侵衰老惜友朋。", "尋梅廢苑霜穿屨，聽雁寒窗雪洒燈。", "追憶舊遊如昨日，想君夜夢到西陵。"]'),
('b5c90817-6696-439d-ae68-600ecfdaef0b','破衲','釋善珍','宋','宋诗','song-poetry','','[]','破衲襤襂兩鬢霜，耳邊誰管俗雌黄。',64,'全唐诗/poet.song.208000.json','["破衲襤襂兩鬢霜，耳邊誰管俗雌黄。", "自騎馿鍊推敲字，不與人知安樂方。", "五柳傳中尋靖節，孤桐聲裏見嵇康。", "深山敢歎無知己，饑食松花死亦香。"]'),
('0a408804-6e2d-4bcf-aca2-9d9e4c9f5dd1','投贈張斗野  其一','釋善珍','宋','宋诗','song-poetry','','[]','雪曲從來難賞音，無機古路綠苔深。',64,'全唐诗/poet.song.208000.json','["雪曲從來難賞音，無機古路綠苔深。", "驥寒遠放雁爲伴，鶴晚未歸鴉滿林。", "紫領寬袍籠袖醉，烏紗側帽掉頭吟。", "公侯多少身名滅，李杜光芒尚至今。"]'),
('c96e31c5-7d72-48a6-9f07-5b7892b60148','投贈張斗野  其二','釋善珍','宋','宋诗','song-poetry','','[]','曩歲懷忠扣帝閽，東游未久赦虞翻。',64,'全唐诗/poet.song.208000.json','["曩歲懷忠扣帝閽，東游未久赦虞翻。", "流芳千載凜生氣，拜賜九河湔淚痕。", "釣艇带烟飛鷺渚，轡馿衝雪早梅村。", "雖云冷淡窮生活，刺繡終勝倚市門。"]'),
('f8ca9229-f4f4-4ff3-a167-00c29d5e9288','湖邊','釋善珍','宋','宋诗','song-poetry','','[]','欲離湖邊別卜居，每亭隨意坐須臾。',64,'全唐诗/poet.song.208000.json','["欲離湖邊別卜居，每亭隨意坐須臾。", "水漂魚沫粘花片，風拂蛛絲落露珠。", "竹閣晚晴山見越，蓴鄉日暖客遊吳。", "向來和靖高吟地，不記殘梅尚幾株。"]'),
('59a70884-6485-4a2c-a819-6c47a83b2c4a','賀曾帥得祠  其一','釋善珍','宋','宋诗','song-poetry','','[]','臺省羣飛競刺天，琳宮散吏管雲烟。',64,'全唐诗/poet.song.208000.json','["臺省羣飛競刺天，琳宮散吏管雲烟。", "長才十月得霜鶻，拙宦三江上水船。", "身外聲名輸飲酒，世間屈曲勝巢仙。", "丈夫功業誰能料，起渭征遼盡暮年。"]'),
('68f2f9c4-a214-465b-83dc-cc218b550655','賀曾帥得祠  其二','釋善珍','宋','宋诗','song-poetry','','[]','千騎叢中舊擁旄，丹心猶在鬢蕭騷。',64,'全唐诗/poet.song.208000.json','["千騎叢中舊擁旄，丹心猶在鬢蕭騷。", "漢庭重少馮唐老，晉士趨卑張翰高。", "靜看棋枰爭勝負，閑馳筆陣寄雄豪。", "搶榆擊水公俱樂，却是旁人嘆不遭。"]'),
('92d4b7ee-0ea8-4ae6-9eff-e35362de7c67','江南','釋善珍','宋','宋诗','song-poetry','','[]','江南春水荻芽青，江北春風魚上冰。',64,'全唐诗/poet.song.208000.json','["江南春水荻芽青，江北春風魚上冰。", "花發正催寒食節，鴈歸應過永昌陵。", "騎奴玉轡閑調馬，公子錦韝行臂鷹。", "曾宿楊州建隆寺，五更吹角鼓騰騰。"]'),
('9c03dc5a-b920-49c9-9eef-aa9a70f1b1de','已往','釋善珍','宋','宋诗','song-poetry','','[]','前三十萬歲已往，後千億年來無窮。',64,'全唐诗/poet.song.208000.json','["前三十萬歲已往，後千億年來無窮。", "化工團土爲愚漢，傀儡牽絲弄老翁。", "堯桀是非俱蔓草，嬴劉成敗等飛鴻。", "午窗睡起摩雙眼，落盡瓶花糝桉紅。"]'),
('374ec561-8021-4b90-b0de-fde78676f6a4','悼上官良史','釋善珍','宋','宋诗','song-poetry','','[]','京口見君乘早潮，短巾調笑立溪橋。',64,'全唐诗/poet.song.208000.json','["京口見君乘早潮，短巾調笑立溪橋。", "長瓶買酒典孤劍，一夜枕書談六朝。", "常恐騎鯨狂捉月，不然跨鶴坐橫簫。", "遠公多病宗雷死，惆悵社中人寂寥。"]'),
('7b224fec-0c86-465d-8fd8-67eac97cac98','哭寒巖傳權院','釋善珍','宋','宋诗','song-poetry','','[]','早歲驅馳翰墨場，快如陣馬與風檣。',64,'全唐诗/poet.song.208000.json','["早歲驅馳翰墨場，快如陣馬與風檣。", "自期作佛先靈運，那肯堆錢付窟郎。", "閑日有僧來乞米，死時無妓共分香。", "神仙謫墮年期滿，應合乘雲在帝旁。"]'),
('37bfdd80-78ac-41dd-874f-9fdb0845a61b','借甑','釋善珍','宋','宋诗','song-poetry','','[]','投老林間借甑炊，心閑自覺樂無時。',64,'全唐诗/poet.song.208000.json','["投老林間借甑炊，心閑自覺樂無時。", "生臺拋飯暗持咒，山路負薪高誦詩。", "惜燕常年尋故主，笑人荒冢樹穹碑。", "白頭寂寞安吾分，何用黄金鑄子期。"]'),
('b852b3d4-7405-44b8-982c-8523aef757b3','送趙司令之金陵  其一','釋善珍','宋','宋诗','song-poetry','','[]','自古詞人例謫遷，十年無路可棧天。',64,'全唐诗/poet.song.208000.json','["自古詞人例謫遷，十年無路可棧天。", "督師上正倚裴相，破賊叔應推謝玄。", "伏櫪驥思沙漠外，脫韝鷹去碧霄邊。", "僧隟早辱萊公賞，他日牽聯得並傳。"]'),
('3e29e9e8-fb6a-4293-853d-f65c5dc28f83','送趙司令之金陵  其二','釋善珍','宋','宋诗','song-poetry','','[]','血戰荆江障賊鋒，無端讒嗔困英雄。',64,'全唐诗/poet.song.208000.json','["血戰荆江障賊鋒，無端讒嗔困英雄。", "念親不隔關山夢，憂國常懷畎畝忠。", "早歲交游今改事，少年豪舉晚收功。", "碧油談笑多新句，倘值南雲寄便鴻。"]'),
('2672f674-a280-4cfa-ae24-abf9206fd21d','徐教下第歸','釋善珍','宋','宋诗','song-poetry','','[]','奏賦長安不遇知，丈夫失意肯生悲。',64,'全唐诗/poet.song.208000.json','["奏賦長安不遇知，丈夫失意肯生悲。", "科名自古與風漢，造物至今猶小兒。", "道在布韋輕將相，時危耕釣隠英奇。", "渡江亦謁青山不，應念曾公爲製碑。"]'),
('a2a9628a-107d-40e8-829e-6ffe238e255c','京口時楚寇侵維揚','釋善珍','宋','宋诗','song-poetry','','[]','河淮羽騎召兵頻，臘月花開暖似春。',64,'全唐诗/poet.song.208000.json','["河淮羽騎召兵頻，臘月花開暖似春。", "鬭雀倚風將墜地，長鯨吸海欲生塵。", "燒紅天半無飛鳥，雲白山中有隠人。", "回首南園舊城闕，斷烟荒樹更傷神。"]'),
('83189444-4c9a-4e09-a6b1-aa334331b69b','小築','釋善珍','宋','宋诗','song-poetry','','[]','小築林間憩倦游，莫年幽事勝西州。',64,'全唐诗/poet.song.208000.json','["小築林間憩倦游，莫年幽事勝西州。", "松陰猿嘯閑行藥，日夕鴉歸獨倚樓。", "山色齊奴開步障，葉聲楚客賦悲秋。", "一生不曉樊川意，剛把詩方萬戶侯。"]'),
('e03a737c-1c55-433d-ae58-64340f175237','一榻','釋善珍','宋','宋诗','song-poetry','','[]','奇事渾無俗事稠，掃除一榻夢滄洲。',64,'全唐诗/poet.song.208000.json','["奇事渾無俗事稠，掃除一榻夢滄洲。", "草蟲呢呢兒女語，風蝶翩翩公子流。", "烟雨樓臺六朝寺，圖書雞犬五湖舟。", "少年伴祇孤筇在，時復相從說舊游。"]'),
('d3e7444f-8920-456d-8759-6fbd72b096fa','送黄凝雲歸常州','釋善珍','宋','宋诗','song-poetry','','[]','一住京華能幾日，故山欲去值春寒。',64,'全唐诗/poet.song.208000.json','["一住京華能幾日，故山欲去值春寒。", "石壇經雨草生遍，庭果落階鳥啄殘。", "雲表鶴聲朝返佩，林間虹氣夜開丹。", "僊家縮地尋常事，試與思歸倦客看。"]'),
('a9f66264-35c7-49e7-a113-973ab95bb42d','次陳上舍韻','釋善珍','宋','宋诗','song-poetry','','[]','壯不封侯老背時，雲山得意合忘歸。',64,'全唐诗/poet.song.208000.json','["壯不封侯老背時，雲山得意合忘歸。", "思魚不肯歌長鋏，射虎猶堪著短衣。", "椽筆枉將修野史，陣圖少試解棋圍。", "元龍心事應如許，何日相逢語入微。"]'),
('5c36c08a-1ee5-479f-8020-f61716edf726','寄孚老','釋善珍','宋','宋诗','song-poetry','','[]','雙眼常時看屋椽，從來不結俗人緣。',64,'全唐诗/poet.song.208000.json','["雙眼常時看屋椽，從來不結俗人緣。", "早年曾悟出師表，晚歲始參齊物篇。", "魔壘孤軍降百萬，詩壇一首當三千。", "清溪結得茆菴未，閑欲尋君共泛船。"]'),
('86165eee-30b3-4f4a-8cdf-b1ac06b9846b','寄朋介石','釋善珍','宋','宋诗','song-poetry','','[]','詩卷前年手自携，秋風客路易東西。',64,'全唐诗/poet.song.208000.json','["詩卷前年手自携，秋風客路易東西。", "遊淮戰士看飛錫，渡海神魚驚照犀。", "故國身歸疑化鶴，深山睡穩厭聞雞。", "一生結友皆奇衲，難得如君無町畦。"]'),
('7fbbe570-5969-44fd-b330-7a4c631759d0','夢元雙杉','釋善珍','宋','宋诗','song-poetry','','[]','晚睡初醒月上階，遠村何處笛聲哀。',64,'全唐诗/poet.song.208000.json','["晚睡初醒月上階，遠村何處笛聲哀。", "霜凋隴岸有梅破，雪隔炎洲無雁來。", "舊隠青山猶在夢，故交白骨已生苔。", "欲談往事無人共，自擁寒爐自畫灰。"]'),
('e4e15fa5-64e9-42a5-8a42-4f5c5d82e865','倚筇','釋善珍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','楓葉蘆花滿目秋，倚筇那復少年游。',64,'全唐诗/poet.song.208000.json','["楓葉蘆花滿目秋，倚筇那復少年游。", "眼看桑海夢相似，骨瘞匡廬心始休。", "萬里霜天孤唳鶴，五湖烟水一身鷗。", "君看清絕無攀處，著得塵埃半點不。"]'),
('f3d5da0b-b401-4353-83f0-a459fc6f233a','城歸','釋善珍','宋','宋诗','song-poetry','','[]','一宿城闉便憶歸，雲林長恐與心違。',64,'全唐诗/poet.song.208000.json','["一宿城闉便憶歸，雲林長恐與心違。", "真金化得終無藥，脫粟空時尚有薇。", "野雀避鷹巢竹棟，樵童背日睡蓑衣。", "近聞谷口梅花發，病擬搘筇下翠微。"]'),
('df9ce044-3a68-4797-bfa5-75fc5e9755f9','過南墅懷寒巖  其一','釋善珍','宋','宋诗','song-poetry','','[]','年年散粟出朱門，狗盜雞鳴總受恩。',64,'全唐诗/poet.song.208000.json','["年年散粟出朱門，狗盜雞鳴總受恩。", "空有玉棺歸碧落，更無紅粉哭黄昏。", "徧行苔蘚尋陳迹，擬倩梅花招醉魂。", "常恐丘原千載後，不生荆棘長蘭蓀。"]'),
('fdc99ff0-3a39-41fb-814b-56c8d1633c33','過南墅懷寒巖  其二','釋善珍','宋','宋诗','song-poetry','','[]','草沒亭臺不見蹤，故交掩淚立寒風。',64,'全唐诗/poet.song.208000.json','["草沒亭臺不見蹤，故交掩淚立寒風。", "食魚客去餘空館，放鶴童歸棄舊籠。", "病悟前書藏夏口，死留好句在江東。", "徐陵元是麒麟種，天上應須見寶公。"]'),
('0eb1cb12-27a0-45c3-bf4f-65c9549931a0','挽劉常簿贛州','釋善珍','宋','宋诗','song-poetry','','[]','遠遊少負長卿才，晚亦乘車衣錦回。',64,'全唐诗/poet.song.208000.json','["遠遊少負長卿才，晚亦乘車衣錦回。", "正喜瘴溪鰐移去，又驚遼海鶴歸來。", "祕書入社花簪帽，賓客分司酒滿杯。", "莫怪一麾不辭遠，吟詩要上鬰孤臺。"]'),
('acfae0a3-4f31-4e39-941a-1eb1f83e96ad','送金橘與徐釣舟','釋善珍','宋','宋诗','song-poetry','','[]','竹籠盛來露未乾，試嘗數顆已無酸。',64,'全唐诗/poet.song.208000.json','["竹籠盛來露未乾，試嘗數顆已無酸。", "味同楚水赤萍實，色比韓郎金彈丸。", "委地兒童難識價，經霜桃李不同盤。", "緘題寄去非無意，相約交情到歲寒。"]'),
('d34180db-56a2-40e7-98a2-57cc827b88a4','次曾都倉韻','釋善珍','宋','宋诗','song-poetry','','[]','學問淵源汲綆深，逢時肯作子光瘖。',64,'全唐诗/poet.song.208000.json','["學問淵源汲綆深，逢時肯作子光瘖。", "平泉舊圃多奇石，栗里閑居只素琴。", "終竟封侯憑燕頷，莫誇對客割牛心。", "向來謝傅游山伴，尚有白頭支道林。"]'),
('8e740c24-d669-40c3-ad29-38ed92243338','次徐監簿韻賀吳侍郎新第落成  其一','釋善珍','宋','宋诗','song-poetry','','[]','碧落仙人上界還，手携奎壁下天關。',64,'全唐诗/poet.song.208000.json','["碧落仙人上界還，手携奎壁下天關。", "百年第宅復金琖，萬卷圖書圍玉山。", "霜壓老槐龍卧壑，春催紅藥鳳銜環。", "時危報主詩人志，好愛蒼生莫愛閑。"]'),
('04de9848-bc1a-46dc-9cba-a295a3bbb037','次徐監簿韻賀吳侍郎新第落成  其二','釋善珍','宋','宋诗','song-poetry','','[]','詞源本本自歐蘇，胸次湖江跨楚吳。',64,'全唐诗/poet.song.208000.json','["詞源本本自歐蘇，胸次湖江跨楚吳。", "縱未押班坐鴟閤，亦須開府佩麟符。", "拂衣太華今無放，卜築中條昔有圖。", "久矣笙竽喧衆耳，新聲待奏鳳將雛。"]'),
('ebd32de7-39f0-4bde-b078-7a422569dcb5','金陵懷古  其一','釋善珍','宋','宋诗','song-poetry','','[]','齊樓梁殿黍離離，王氣潜隨斗柄移。',64,'全唐诗/poet.song.208000.json','["齊樓梁殿黍離離，王氣潜隨斗柄移。", "秋雨狐藏宮井樹，夕陽鴉立御園枝。", "詩人閑管江家宅，宰相偏嫌蔡充兒。", "青史鬼雄元不死，歸來化鶴有誰知。"]'),
('aa6ebbc9-462e-46cb-9e00-46bebcc66f30','金陵懷古  其二','釋善珍','宋','宋诗','song-poetry','','[]','國號倉皇更幾回，昔人事往後人哀。',64,'全唐诗/poet.song.208000.json','["國號倉皇更幾回，昔人事往後人哀。", "相賡璧月詞千闋，帝勸長星酒一杯。", "春草不憐同泰廢，曉鐘猶是景陽來。", "陵荒玉椀無踪跡，寒食梨花依舊開。"]'),
('2f45c924-6711-49fd-89f0-85689c8bfeb1','送孚老再游浙','釋善珍','宋','宋诗','song-poetry','','[]','楚柁吳檣興未休，好山謝事要閑游。',64,'全唐诗/poet.song.208000.json','["楚柁吳檣興未休，好山謝事要閑游。", "常憎駑馬戀棧豆，今見蒼鷹掣臂韝。", "歲晚老松無伴侶，天寒落葉正颼飀。", "人間果是風堪御，却欲携君徧九州。"]'),
('62b34810-35ac-49a3-a572-47ed61f7a438','送楊戶部','釋善珍','宋','宋诗','song-poetry','','[]','鈴齋去歲念民饑，鬢雪凋疎带減圍。',64,'全唐诗/poet.song.208000.json','["鈴齋去歲念民饑，鬢雪凋疎带減圍。", "史冊千年循吏少，江湖萬里散人歸。", "兒童不信夷齊溷，黨論嘗攻韓范非。", "臨別祝公堅晚節，受恩何敢望留衣。"]'),
('3fd3583c-991d-486a-9312-5c1032e4238b','送蔡察院將漕廣東','釋善珍','宋','宋诗','song-poetry','','[]','峨冠人避柏臺驄，弭節光分澤國龍。',64,'全唐诗/poet.song.208000.json','["峨冠人避柏臺驄，弭節光分澤國龍。", "應似鮮于福京左，還同司馬過臨邛。", "風生廉按清南嶠，冰解將輸佐大農。", "拈起瓣香說無極，千年道統繼儒宗。"]'),
('5d84bf63-6364-45c2-ad2d-a62a25372eed','送顔倅之江西','釋善珍','宋','宋诗','song-poetry','','[]','檻外江流知幾霜，煩君著語吊滕王。',64,'全唐诗/poet.song.208000.json','["檻外江流知幾霜，煩君著語吊滕王。", "琴中誰識啼烏曲，酒後任稱司馬狂。", "閣序尚留唐篆刻，劍光何預晉興亡。", "此行遍覽遺蹤了，歷有徵書出建章。"]'),
('8d838c38-5e98-4891-aea5-791b7b8a98b3','送傅提幹','釋善珍','宋','宋诗','song-poetry','','[]','渡江諸老盡蘭蓀，當日琳琅照一門。',64,'全唐诗/poet.song.208000.json','["渡江諸老盡蘭蓀，當日琳琅照一門。", "龍去難尋神劍迹，鶴歸猶記舊巢痕。", "百年閥閲須關念，五里松楸易斷魂。", "京浙故人無恙不，相逢記爲問寒溫。"]'),
('29129260-bac2-4b88-853f-f8d4bc899e60','送蔡秀才之漳浦','釋善珍','宋','宋诗','song-poetry','','[]','夜冷螢窗書倦看，解鞍南去路漫漫。',64,'全唐诗/poet.song.208000.json','["夜冷螢窗書倦看，解鞍南去路漫漫。", "霜乾處士梅花圃，日照先生苜蓿盤。", "乞米剩堪供鶴料，釣鼇重怕壞魚竿。", "何當著意拋妻子，共入深山學養丹。"]'),
('521cb3cf-86b8-4f99-af64-203a023e900b','送林南恩入京','釋善珍','宋','宋诗','song-poetry','','[]','曩賦登樓望故鄉，邊淮十丈戰塵黄。',64,'全唐诗/poet.song.208000.json','["曩賦登樓望故鄉，邊淮十丈戰塵黄。", "已聞淝水返朱序，亦說漢庭憐孝章。", "千載青編如屬國，一麾白髮出炎荒。", "山林朝市終殊路，只待除書慰別腸。"]'),
('a1c5b6db-1800-4972-a16b-34483185eb0f','寄見首座','釋善珍','宋','宋诗','song-poetry','','[]','借得茆齋傍澗泉，新年樂事勝常年。',64,'全唐诗/poet.song.208000.json','["借得茆齋傍澗泉，新年樂事勝常年。", "詩逢得意猶藏稿，琴畏知音自斷絃。", "鯨浪粘天思渡海，狼烽照夜憶遊邊。", "嶮途試盡身猶在，來共看雲聽雨眠。"]'),
('902d28f4-f5a1-4d28-9ea1-2e9d7d011d8b','寄趙西巖','釋善珍','宋','宋诗','song-poetry','','[]','暑退江城又素秋，想因懷土亦登樓。',64,'全唐诗/poet.song.208000.json','["暑退江城又素秋，想因懷土亦登樓。", "蘭香盍稱騷人佩，萱草難忘志士憂。", "紙上雕蟲真害道，山中射虎勝封侯。", "四方弧矢男兒事，慎勿悲傷念少游。"]'),
('873875da-6adb-42c8-a802-a0a3d5bf2d5a','和陳宰諸官登羅漢閣看草書經卷韻','釋善珍','宋','宋诗','song-poetry','','[]','柳公遺蹟留芳扁，一度摩挲一歎嗟。',64,'全唐诗/poet.song.208000.json','["柳公遺蹟留芳扁，一度摩挲一歎嗟。", "佛閣僧居如穴蟻，梵編蟲蠹失驚蛇。", "文占天上奎星聚，語到宵中斗柄斜。", "老衲畏寒仍戒酒，不能伴客賦梅花。"]'),
('e4f49659-a80b-4faf-985b-145bf3908ade','代趙景賢和林定庵韻','釋善珍','宋','宋诗','song-poetry','','[]','閑携竹杖過橫塘，碧藕無花葉更香。',64,'全唐诗/poet.song.208000.json','["閑携竹杖過橫塘，碧藕無花葉更香。", "齋後隨僧同洗鉢，醉中得句旋投囊。", "魚沈似厭池光靜，禽語如欣樹影凉。", "更欲招邀鷗鷺伴，菰蒲深處共平章。"]'),
('9a2dc686-7d19-4029-95e2-2a5c09661e58','賀洪陽巖帥閩','釋善珍','宋','宋诗','song-poetry','','[]','萬馬羣中一馬驄，擊姦白簡尚生風。',64,'全唐诗/poet.song.208000.json','["萬馬羣中一馬驄，擊姦白簡尚生風。", "衣冠南紀瞻鳴鳳，雲雨東山起卧龍。", "臺閣難招真鐵壁，林泉未隠且金狨。", "擁旄前有莆陽蔡，相繼名齊石鼓峰。"]'),
('20ac8747-e0f8-4b9a-b9ed-11401e4c78fb','寄智愚谷','釋善珍','宋','宋诗','song-poetry','','[]','袖裏明珠思暗投，衰頹未敢學伊優。',64,'全唐诗/poet.song.208000.json','["袖裏明珠思暗投，衰頹未敢學伊優。", "座談寧受鬼擘口，舟滯不嫌風打頭。", "鳳去麟亡千載遠，蝸爭蟻鬭幾時休。", "百年等死分前後，說與髯兄一笑不。"]'),
('8462c46a-df96-4451-aba2-2dc0127e7a31','擁爐','釋善珍','宋','宋诗','song-poetry','','[]','俗客敲門以病辭，擁爐時復撚吟髭。',64,'全唐诗/poet.song.208000.json','["俗客敲門以病辭，擁爐時復撚吟髭。", "雀栖梅日印孤影，蛛去簷風吹斷絲。", "舊友漸稀增感慨，良辰易過莫尋思。", "六年世態看差熟，惟有青山無變姿。"]'),
('752c969a-eb90-428c-8765-d0df9e0f235b','徂歲','釋善珍','宋','宋诗','song-poetry','','[]','徂歲忙如電後雷，新年又下急符催。',64,'全唐诗/poet.song.208000.json','["徂歲忙如電後雷，新年又下急符催。", "雪將解舞絮誇柳，春遣先鋒花付梅。", "窗白看書俄晻靄，爐紅炙手倏寒灰。", "憑欄大笑無人會，瞥爾晴空一鳥來。"]'),
('859dc913-8dc4-48f0-afab-410bbe1035d7','門徑','釋善珍','宋','宋诗','song-poetry','','[]','門徑莓苔古意深，閉門懶復事參尋。',64,'全唐诗/poet.song.208000.json','["門徑莓苔古意深，閉門懶復事參尋。", "棋圖靜見孫吳法，樵唱真聞韶濩音。", "米盡有方烹白石，丹靈無意化黄金。", "花飛又是春將莫，小復風前擁鼻吟。"]'),
('0bec81e6-cb75-4f09-be33-b170ff479593','採藥','釋善珍','宋','宋诗','song-poetry','','[]','每共樵翁採藥歸，晚晴荷鍤又相隨。',64,'全唐诗/poet.song.208000.json','["每共樵翁採藥歸，晚晴荷鍤又相隨。", "行逢流水便乘犢，坐到爛柯因看棋。", "鳥踏高枝收墜果，人耕古冢得殘碑。", "遠公幸自逃名好，何必栽蓮誑小兒。"]'),
('47c10425-3d1f-47d0-b2c3-34ea715c6a2f','首夏','釋善珍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','首夏山中風物和，不妨老子小婆娑。',64,'全唐诗/poet.song.208000.json','["首夏山中風物和，不妨老子小婆娑。", "竹亭晴坐燕泥少，花逕曉行蛛網多。", "雲表危峯干北斗，道傍古樹識東坡。", "匡廬深處堪歸隠，歲月瀾翻奈老何。"]'),
('19e23b1f-f4c6-4e36-96a2-47976b55da32','題金山寺','釋善珍','宋','宋诗','song-poetry','','[]','寺不干興廢，江流曾策勳。',48,'全唐诗/poet.song.208000.json','["寺不干興廢，江流曾策勳。", "門栖征虜艦，僧誦設冥文。", "薄靄遮西日，歸鵰带北雲。", "江心數峰小，傳是晉人墳。"]'),
('e40e5291-7c71-42cf-8475-8982ce16f308','曉登甘露寺樓','釋善珍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','秦吳相接處，遠客獨來游。',48,'全唐诗/poet.song.208000.json','["秦吳相接處，遠客獨來游。", "秋盡斗移柄，曙分河隠流。", "馬嘶殘月壘，雁入向陽州。", "北望長江在，悠悠波浪愁。"]'),
('29076f60-b797-4112-855e-e9fb89893030','偶成','釋善珍','宋','宋诗','song-poetry','','[]','長年狎樵牧，門外即荒郊。',48,'全唐诗/poet.song.208000.json','["長年狎樵牧，門外即荒郊。", "瘦草牛羊路，高松鸛鶴巢。", "病來勤習定，老去懶尋交。", "常愧逃名者，深山自縛茆。"]'),
('f52a641a-3265-4ae2-91b9-68727b908e9b','孤山','釋善珍','宋','宋诗','song-poetry','','[]','數樹梅花地，先朝處士廬。',48,'全唐诗/poet.song.208000.json','["數樹梅花地，先朝處士廬。", "柳凹人繫馬，萍破鷺窺魚。", "空冢衣冠蛻，山房水石虛。", "白頭舊園吏，曾見幸金輿。"]'),
('25047ed7-af70-46d3-ae57-68017302786b','春寒','釋善珍','宋','宋诗','song-poetry','','[]','松間燈夕過，顧影在天涯。',48,'全唐诗/poet.song.208000.json','["松間燈夕過，顧影在天涯。", "雪暝迷歸鶴，春寒誤早花。", "艱難知世味，貧病厭年華。", "故國風塵外，無心更問家。"]'),
('822b6477-5c13-4136-86c9-cf30c944b25f','莫春','釋善珍','宋','宋诗','song-poetry','','[]','門外柳花過，似予飄泊身。',48,'全唐诗/poet.song.208000.json','["門外柳花過，似予飄泊身。", "吟高妨定衲，客久羨歸人。", "無藥可醫俗，有錢難買春。", "山中舊同伴，招隠寄書頻。"]'),
('6e463c2e-ff6c-4f50-ac1a-bf40a081304f','游下竺御園','釋善珍','宋','宋诗','song-poetry','','[]','山氣曉常雨，晚晴溪見沙。',48,'全唐诗/poet.song.208000.json','["山氣曉常雨，晚晴溪見沙。", "荒園閑柳色，斜日淡梨花。", "訪隠行過洞，思親夢到家。", "十年此來往，今度鬢將華。"]'),
('f1821be8-1e73-4a79-a054-a2f0e3574bec','山行晚歸','釋善珍','宋','宋诗','song-poetry','','[]','藥逕入雲林，晚晴扶杖吟。',48,'全唐诗/poet.song.208000.json','["藥逕入雲林，晚晴扶杖吟。", "照泥星復雨，經朔月猶陰。", "樹折憐巢覆，泉清見葉沈。", "愛閑自如此，不是學灰心。"]'),
('f042cad8-a3a9-4fb5-8a3f-82173bcc4510','郊原','釋善珍','宋','宋诗','song-poetry','','[]','郊原春過後，日日長新梢。',48,'全唐诗/poet.song.208000.json','["郊原春過後，日日長新梢。", "洗竹去蛛網，疎松留鶴巢。", "雲衣慵補綴，月戶自推敲。", "舊種梅花樹，吾今與汝交。"]'),
('d83e1ca6-e572-4953-a5fb-f50908a4bace','送客宿九日山','釋善珍','宋','宋诗','song-poetry','','[]','石竈斷苔紋，摩挲弔隠君。',48,'全唐诗/poet.song.208000.json','["石竈斷苔紋，摩挲弔隠君。", "風吹遊子袂，月照古人墳。", "舊事殘碑在，荒祠流水分。", "永懷山忽冥，紅葉墜秋雲。"]'),
('124c284b-0c5f-42a0-9479-52057464e814','哭元雙杉','釋善珍','宋','宋诗','song-poetry','','[]','哭公非故人，覺苑失龍麟。',48,'全唐诗/poet.song.208000.json','["哭公非故人，覺苑失龍麟。", "白日有明暗，青天無鬼神。", "戒珠常照夜，鎖骨不棲塵。", "老我誰相問，空餘影伴身。"]'),
('6ac1c2c8-0741-4f29-b8bd-972153814354','次愚谷游北山韻','釋善珍','宋','宋诗','song-poetry','','[]','登山行復歇，脚力鈍如蛙。',48,'全唐诗/poet.song.208000.json','["登山行復歇，脚力鈍如蛙。", "宿雨少游客，荒畦多落花。", "公侯歸蔓草，池館破誰家。", "同是傷春者，留連惜物華。"]'),
('a6682b70-5064-4d5c-9f79-5c3757b9acbc','送趙禮部將漕廣東','釋善珍','宋','宋诗','song-poetry','','[]','玉節畀名流，澄清十四州。',48,'全唐诗/poet.song.208000.json','["玉節畀名流，澄清十四州。", "元公著書處，葛老鍊丹洲。", "星應郎官舍，霜侵使者裘。", "東南箕歛極，寬得一分不。"]'),
('8aa88ceb-2dc3-4187-b8a5-360c7728d29a','送林節推  其一','釋善珍','宋','宋诗','song-poetry','','[]','魁宿來臨幕，不同常郡僚。',48,'全唐诗/poet.song.208000.json','["魁宿來臨幕，不同常郡僚。", "名高饒薦剡，官滿合歸朝。", "綵旆傾城送，清聲載路謠。", "麗譙雖末績，亦自出雲霄。"]'),
('fc49d0df-ab10-4055-bce0-cf5e72a9ed0d','送林節推  其二','釋善珍','宋','宋诗','song-poetry','','[]','幕皆資畫諾，人最說君賢。',48,'全唐诗/poet.song.208000.json','["幕皆資畫諾，人最說君賢。", "判好堪呈佛，心清亦近禪。", "著書僧有傳，執法吏無權。", "風雨東門路，分携忽黯然。"]'),
('f5f6a13d-7d7f-4f36-b07d-633a53319182','送顔主簿之懷安','釋善珍','宋','宋诗','song-poetry','','[]','古廨大江邊，多閑少俸錢。',48,'全唐诗/poet.song.208000.json','["古廨大江邊，多閑少俸錢。", "鳳棲仇覽棘，虹貫米家船。", "心靜佛三昧，時來官九遷。", "外臺兼督府，幕下正須賢。"]'),
('fbf5c6a8-583e-46c0-ade6-ea865e8d82c7','題狗葬劉家寺','釋善珍','宋','宋诗','song-poetry','','[]','廢殿何年寺，門開不見僧。',48,'全唐诗/poet.song.208000.json','["廢殿何年寺，門開不見僧。", "犬眠莎砌日，鴉啄菜池冰。", "濕蘚侵碑字，空巢綴壁層。", "誰家古祠在，無主夜燒燈。"]'),
('6dc9d3d7-c915-44dd-9907-af7b0930881e','除夕','釋善珍','宋','宋诗','song-poetry','','[]','七十明朝是，年將衰併來。',48,'全唐诗/poet.song.208000.json','["七十明朝是，年將衰併來。", "頑皮禁冷暖，老氣壓凶災。", "鐵硯穿何益，金丸跳不回。", "羣兒愛伶利，與汝換癡獃。"]'),
('5d7998bc-3fed-436d-aba7-68cb8e3ff1cf','雪峰舊院','釋善珍','宋','宋诗','song-poetry','','[]','住壁與雲鄰，荒畦虎跡新。',48,'全唐诗/poet.song.208000.json','["住壁與雲鄰，荒畦虎跡新。", "樵鳴猿落果，鷹急鳥依人。", "陰磵澌經月，寒花開過春。", "鰲山前事在，獨坐想芳塵。"]'),
('dce27bca-b2a3-4871-bb5e-6960f143ba2d','新歲','釋善珍','宋','宋诗','song-poetry','','[]','新歲七十三，駑癡不脫銜。',48,'全唐诗/poet.song.208000.json','["新歲七十三，駑癡不脫銜。", "搓繩謀繫日，儲藥要醫凡。", "魘鬼驚酣枕，村優笑戲衫。", "災祥總由我，何必問巫咸。"]'),
('829860f9-74a1-46ca-ae65-87a6d5f75b2b','次蒲心泉韻','釋善珍','宋','宋诗','song-poetry','','[]','京華厭塵土，借屋瞰湖邊。',48,'全唐诗/poet.song.208000.json','["京華厭塵土，借屋瞰湖邊。", "馿蹇馱詩笈，鷗閑傍酒船。", "啼鵑殘月曉，細雨落花天。", "何日東林伴，同脩蓮社緣。"]'),
('61013dfd-30be-4405-a701-b63240946898','策蹇','釋善珍','宋','宋诗','song-poetry','','[]','策蹇下山椒，冬深寒意驕。',48,'全唐诗/poet.song.208000.json','["策蹇下山椒，冬深寒意驕。", "瀑風吹帽濕，杉雪落衣銷。", "梅嫩有花早，桐衰無葉凋。", "是山皆可隠，不用楚詞招。"]'),
('3d9d06d5-d15b-43f2-85d9-f658b1b360e8','古意  其一','釋善珍','宋','宋诗','song-poetry','','[]','力耕野老嫌兒少，苦戰將軍羨級多。',32,'全唐诗/poet.song.208000.json','["力耕野老嫌兒少，苦戰將軍羨級多。", "祇道亂離人死盡，朱門日日買青娥。"]'),
('ccf4cc60-b4be-4b37-acdb-af70c49fda93','古意  其二','釋善珍','宋','宋诗','song-poetry','','[]','燕山燒營火照雲，羽書夜半飛入秦。',32,'全唐诗/poet.song.208000.json','["燕山燒營火照雲，羽書夜半飛入秦。", "鐵衣血冷不敢脫，功在將軍不在身。"]'),
('24fe0eb7-6762-489c-8b62-920b1f595861','龍泉山中','釋善珍','宋','宋诗','song-poetry','','[]','夜半巖間坐看星，千年老樹有精靈。',32,'全唐诗/poet.song.208000.json','["夜半巖間坐看星，千年老樹有精靈。", "前山月上青楓頂，照見白鷴來聽經。"]'),
('c0b990c7-c19e-4d60-8130-964f8be9b12c','題雅上人手抄唐詩後','釋善珍','宋','宋诗','song-poetry','','[]','天孫錦段冰蠶繭，太古盤銘蒼頡文。',32,'全唐诗/poet.song.208000.json','["天孫錦段冰蠶繭，太古盤銘蒼頡文。", "三百年來消息絕，無人爲酬杜陵墳。"]'),
('9175cd2b-0130-49a9-b42f-174bec056c8b','老馬','釋善珍','宋','宋诗','song-poetry','','[]','營司牽浴柳邊池，玉沫垂銜步較遲。',32,'全唐诗/poet.song.208000.json','["營司牽浴柳邊池，玉沫垂銜步較遲。", "洗見箭瘢如有恨，將軍忘却未侯時。"]'),
('7bde24bb-18fc-4bac-a860-b5dcd19e57f9','墨梅','釋善珍','宋','宋诗','song-poetry','','[]','水邊烟外見橫枝，畫裏尋思記舊詩。',32,'全唐诗/poet.song.208000.json','["水邊烟外見橫枝，畫裏尋思記舊詩。", "祇道老來風味減，鐵心還自有愁時。"]'),
('711248ce-b6cc-40bd-91d7-665bf99c003c','芭蕉','釋善珍','宋','宋诗','song-poetry','','[]','瓦溝月暗亂螢飛，照見芭蕉葉上詩。',32,'全唐诗/poet.song.208000.json','["瓦溝月暗亂螢飛，照見芭蕉葉上詩。", "憶得前時吟最苦，自携殘燭拂蛛絲。"]'),
('1f22b5c8-e874-4763-b753-1afb25a54be0','答羅野乞米','釋善珍','宋','宋诗','song-poetry','','[]','山房歲晚冷如冰，欲訪盧仝病未能。',32,'全唐诗/poet.song.208000.json','["山房歲晚冷如冰，欲訪盧仝病未能。", "莫怪鄰僧無米送，無人送米與鄰僧。"]'),
('4409ca92-d9de-416a-b10e-ad6c7d74ba3a','題紫極宮晉檜','釋善珍','宋','宋诗','song-poetry','','[]','老君壇西晉朝柏，拜壇道士頭髮白。',32,'全唐诗/poet.song.208000.json','["老君壇西晉朝柏，拜壇道士頭髮白。", "賣丹得錢還酒客，肉重欲飛鶴無力。"]'),
('e5a09731-9105-4a5a-965d-d9d2148d9082','古松','釋善珍','宋','宋诗','song-poetry','','[]','武夷洞中老松樹，上有千年仙鶴巢。',32,'全唐诗/poet.song.208000.json','["武夷洞中老松樹，上有千年仙鶴巢。", "幾度隔雲茶臼響，山童樹下拾枯梢。"]'),
('b07de9d3-b703-4eb7-a3a1-5c7197487291','送米與陳監元','釋善珍','宋','宋诗','song-poetry','','[]','鬢毛蕭颯已成翁，奇怪胸中盡掃空。',32,'全唐诗/poet.song.208000.json','["鬢毛蕭颯已成翁，奇怪胸中盡掃空。", "尚要俗人傳好事，歲殘乞米送盧仝。"]'),
('b0122476-e053-42fe-b001-7e181f3a4fea','雨後過光嚴寺','釋善珍','宋','宋诗','song-poetry','','[]','小橋路入野僧家，山犬眠莎向日斜。',32,'全唐诗/poet.song.208000.json','["小橋路入野僧家，山犬眠莎向日斜。", "庭戶幾時風雨橫，粉牆壓倒佛桑花。"]'),
('a56dd4bd-58ae-48b1-af5e-ecde9aae5637','題范石湖淳熙中出守帖','釋善珍','宋','宋诗','song-poetry','','[]','淳熙天子課農桑，黄閤鴻儒綰郡章。',32,'全唐诗/poet.song.208000.json','["淳熙天子課農桑，黄閤鴻儒綰郡章。", "文物昇平今已遠，斷篇流落入僧房。"]'),
('75fdcede-d9de-4d38-b8c3-bcc8caefafa1','題四畫 桃花竹石鶴','釋善珍','宋','宋诗','song-poetry','','[]','朝遊金谷莫東市，心憶平泉身海涯。',32,'全唐诗/poet.song.208000.json','["朝遊金谷莫東市，心憶平泉身海涯。", "化鶴歸來人不識，春風開盡碧桃花。"]'),
('8febaa82-dad0-4d7a-8a1b-50c244e9fc6a','題四畫 榴花竹石鶴','釋善珍','宋','宋诗','song-poetry','','[]','剪翮花前老可哀，寄聲鷹隼莫相猜。',32,'全唐诗/poet.song.208000.json','["剪翮花前老可哀，寄聲鷹隼莫相猜。", "舊游赤壁君知不，曾伴坡仙作賦來。"]'),
('e4747af6-9ebe-43b0-8200-035b729ae475','題四畫 鬭雞','釋善珍','宋','宋诗','song-poetry','','[]','天寶三郎好鬭雞，醉中官錦賤如泥。',32,'全唐诗/poet.song.208000.json','["天寶三郎好鬭雞，醉中官錦賤如泥。", "沉香亭北花含笑，不管漁陽胡馬嘶。"]'),
('96f34ebd-740b-48f0-afe6-6e713eb005c6','題四畫 一雄雞立籠上一雌覆雛於籠','釋善珍','宋','宋诗','song-poetry','','[]','田翁養雞竹作籠，老雌戀雛不顧雄。',32,'全唐诗/poet.song.208000.json','["田翁養雞竹作籠，老雌戀雛不顧雄。", "催租無人歲常豐，殺身爲黍堪酬翁。"]'),
('e2cac6e2-aca2-400c-b459-1e897ad55f90','題六畫 淵明','釋善珍','宋','宋诗','song-poetry','','[]','寄奴開國勢龍驤，轉眼更齊又換梁。',32,'全唐诗/poet.song.208000.json','["寄奴開國勢龍驤，轉眼更齊又換梁。", "惟有先生賦歸去，至今猶是晉文章。"]'),
('4df23f1c-74ce-491e-9ec4-934f33258147','題六畫 靈運','釋善珍','宋','宋诗','song-poetry','','[]','昏朝麟醢鳳遭烹，鴻盍高飛入杳冥。',32,'全唐诗/poet.song.208000.json','["昏朝麟醢鳳遭烹，鴻盍高飛入杳冥。", "成佛生天俱妄想，築臺當日譯何經。"]'),
('915ecec9-b159-417e-85a9-d726b43c3c1a','題六畫 太白','釋善珍','宋','宋诗','song-poetry','','[]','脫鞾殿上醉陽狂，觸撥春風睡海棠。',32,'全唐诗/poet.song.208000.json','["脫鞾殿上醉陽狂，觸撥春風睡海棠。", "放逐一身窮不恨，三郎入蜀更郎當。"]'),
('669277f9-809a-48f1-9eda-c6205601232b','題六畫 東坡','釋善珍','宋','宋诗','song-poetry','','[]','天津橋上聽啼鵑，從此南人弄相權。',32,'全唐诗/poet.song.208000.json','["天津橋上聽啼鵑，從此南人弄相權。", "多少衣冠落沙漠，朱崖宜著玉堂仙。"]'),
('1b1286e1-6a07-4aaf-8819-af08471ae16a','題六畫 少陵騎馿','釋善珍','宋','宋诗','song-poetry','','[]','市橋日莫蹇馿嘶，雙袖龍鍾醉似泥。',32,'全唐诗/poet.song.208000.json','["市橋日莫蹇馿嘶，雙袖龍鍾醉似泥。", "回首長安淚沾臆，落花何處杜鵑啼。"]'),
('154db1a1-a0a6-480e-b442-5430dffca7fd','題六畫 浪仙騎馿','釋善珍','宋','宋诗','song-poetry','','[]','官路騎馿突尹騶，尹曾駡佛去潮州。',32,'全唐诗/poet.song.208000.json','["官路騎馿突尹騶，尹曾駡佛去潮州。", "却從渠問推敲字，千古詩人作話頭。"]'),
('098b04e7-b508-4121-87b9-3909d440d156','碧沼即事','釋善珍','宋','宋诗','song-poetry','','[]','看書多事置書休，收歛胸懷入倚樓。',32,'全唐诗/poet.song.208000.json','["看書多事置書休，收歛胸懷入倚樓。", "送盡歸鴻簷日晚，敗荷疎柳一池秋。"]'),
('ce875f4b-ec08-419a-8b46-f6d735fa5651','清明游張園桃李盛開獨梅花一株尚未零落','釋善珍','宋','宋诗','song-poetry','','[]','傲寒開晚背時香，尋伴天荒地亦荒。',32,'全唐诗/poet.song.208000.json','["傲寒開晚背時香，尋伴天荒地亦荒。", "不覺春風紅紫閙，老翁偷入少年場。"]'),
('5066cbbe-3266-4d9a-b0bc-3202ed47e080','少陵','釋善珍','宋','宋诗','song-poetry','','[]','少陵絃斷無膠續，鸞鳳巢高隔五雲。',32,'全唐诗/poet.song.208000.json','["少陵絃斷無膠續，鸞鳳巢高隔五雲。", "老子一身都是膽，要傾東海取龍筋。"]'),
('ad925fc4-49d3-4348-b4ef-7d15d98fd1aa','春日湖上  其一','釋善珍','宋','宋诗','song-poetry','','[]','燕外遊絲暖欲迷，酒船吹笛水亭西。',32,'全唐诗/poet.song.208000.json','["燕外遊絲暖欲迷，酒船吹笛水亭西。", "梨花唫苴桃花笑，惱殺春光醉似泥。"]'),
('86347dd6-46c8-461e-a010-38618edb9ffc','春日湖上  其二','釋善珍','宋','宋诗','song-poetry','','[]','晚寒晻靄失樓臺，絃管聲收野意回。',32,'全唐诗/poet.song.208000.json','["晚寒晻靄失樓臺，絃管聲收野意回。", "柳下繫舟覓閑伴，更無一箇白鷗來。"]'),
('c4bf872b-3142-4df4-a7a6-bdd90cfa0fa0','題畫梅','釋善珍','宋','宋诗','song-poetry','','[]','羌笛誰將花外吹，十年心事暗香知。',32,'全唐诗/poet.song.208000.json','["羌笛誰將花外吹，十年心事暗香知。", "夜寒瘦影侵衣袖，月滿闌干獨倚時。"]'),
('3d53bbe2-0a2e-41f1-a795-7fce211d4414','山行  其一','釋善珍','宋','宋诗','song-poetry','','[]','麥畦微雨過，日照青濕濕。',24,'全唐诗/poet.song.208000.json','["麥畦微雨過，日照青濕濕。", "牧童坐短蓑，牛卧寒鴉立。"]'),
('90e6459c-7d29-4b7e-83b8-c874357cd447','山行  其二','釋善珍','宋','宋诗','song-poetry','','[]','歸牛晚失犢，牧童學聲喚。',24,'全唐诗/poet.song.208000.json','["歸牛晚失犢，牧童學聲喚。", "溪邊白鷺鷥，銜魚上田岸。"]'),
('c95b9836-8c08-41df-914b-429f1826ed55','題侃古樵詩卷','釋善珍','宋','宋诗','song-poetry','','[]','死別日益遠，年衰夢亦無。',24,'全唐诗/poet.song.208000.json','["死別日益遠，年衰夢亦無。", "忽開舊詩卷，淚灑白髭鬢。"]'),
('041b6fe0-19ca-406b-8585-4fa7d615710e','題東坡墨蹟','釋善珍','宋','宋诗','song-poetry','','[]','黨籍英賢盡，長淮南北分。',24,'全唐诗/poet.song.208000.json','["黨籍英賢盡，長淮南北分。", "忠奸論方定，金璧購遺文。"]'),
('3f9a1f2d-0833-47a2-8bb1-1c4db6591439','騷詞  其一','釋善珍','宋','宋诗','song-poetry','','[]','獲印兮汾陽，結茆兮湘之崗。',160,'全唐诗/poet.song.208000.json','["獲印兮汾陽，結茆兮湘之崗。", "湘之岳兮帝宮謁帝，帝不敢驕兮奔魑魅而走蜚龍。", "余行兮余意，一笑兮足驚一世。", "人不知兮謂余立異，豈人見兮勝帝。", "調古兮湘童，大道兮壺之中。", "白璧蒼蠅兮何污，噤不敢陳兮君怒。", "蒼蒼上兮皇皇下，樂莫樂兮郴之土。", "藐郴城兮楚涯，身非余兮辱余奚爲。", "策空鳴兮余去，人曰吾能料生不能料死。", "生可玩兮不可留，宛故廬兮風翛翛。"]'),
('8573ee76-7ede-4c64-b537-cf0dfe51f7bb','騷詞  其二','釋善珍','宋','宋诗','song-poetry','','[]','山曇曇兮起雲，山浪浪兮流水。',181,'全唐诗/poet.song.208000.json','["山曇曇兮起雲，山浪浪兮流水。", "神何爲兮山中，豈懷忠兮放棄。", "沃牛炙兮療饑，挈壺兮荷鍤隨之，生不封侯兮死何廟食爲。", "是耶非耶，余不得而知。", "女巫兮擊鼓，坎坎兮祠之下。", "帝不下招兮遺怒，馘長蛟兮縛雄虎。", "野無烽兮海無瀾，馬不用兮都且閑，都且閑兮神乎何以爲御。", "振策而風兮回軒爲雨，風雨時兮多黍稌，風休雨止兮神何處所。", "桂橑兮蘭楣，朝雲出游兮莫雲來歸。", "雲輝輝兮神來歸，雲霏霏兮神來歸。"]'),
('6f77cec5-0605-4731-9b65-3e176a2f7936','祭佛照塔','釋善珍','宋','宋诗','song-poetry','','[]','師在乾淳，名塞穹壤。',60,'全唐诗/poet.song.208000.json','["師在乾淳，名塞穹壤。", "據妙喜室，鞭撻龍象。", "諸子迭出，如鳳如麟。", "如雷破蟄，何草不春。", "余不肖孫，亦忝備位。", "蕪辭匪瀆，惟以識愧。"]'),
('fd539a45-c469-412c-9258-a7851356ab0e','祭端明尤木石','釋善珍','宋','宋诗','song-poetry','','[]','昔大慧師，道鳴東南。',248,'全唐诗/poet.song.208000.json','["昔大慧師，道鳴東南。", "率先伏膺，橫浦紫岩。", "繇是徧交，渡江諸老。", "鉤黨牽連，優游嶺島。", "至今微言，皎若日星。", "公忽開卷，如暗得燈。", "遂登蓬山，乃掌太史。", "金鑾應制，倚馬萬字。", "平生補衮，用功最深。", "群媢衆嫉，獨天賞音。", "寶祐一疏，據經引義。", "申救大臣，惟有去耳。", "疑公前身，即二張公。", "與大慧師，所立一同。", "末劫浮榮，磨滅誰紀。", "晚節芬芳，公真不死。", "公於大慧，世異心通。", "儒喜詆佛，公愈推宗。", "紫岩之銘，過者必式。", "酷哉秦火，毀珠隕璧。", "公重感慨，伐石再鎸。", "著語未了，騎鯨翩然。", "某疇昔親奉麈尾，霏屑冰座，墨妙堆几。", "俛仰之間，事往迹陳。"]'),
('54bf60bf-d92a-4d4b-9291-abf83c83821f','祭觀文忠惠趙節齋','釋善珍','宋','宋诗','song-poetry','','[]','公真天人，謫墮塵世。',248,'全唐诗/poet.song.208000.json','["公真天人，謫墮塵世。", "方朔歲星，傅說箕尾。", "又疑山林，一念差耳。", "樂全僧身，忠宣佛位。", "夙弘願力，出濟事會。", "作民司命，壽國元氣。", "神皇布政，夐古鮮儷。", "誰爲謗書，陰受風旨。", "疾雷破柱，公不失匕。", "關弓射羿，公愈薦禰。", "山藪高深，天球粹美。", "出夷入險，更使迭帥。", "長淮虜衝，孽雛旁睨。", "飛囊走羽，秉鉞危寄。", "初聞謝公，語誤客異。", "復傳孔明，食少敵喜。", "牋病乞閑，易蘇舊治。", "大星竟隕，白雞告祟。", "撫公平生，竹帛光煒。", "諒公精爽，河岳流峙。", "萬鍾千駟，濁世糠粃。", "五龍九鯤，乘雲謁帝。", "某閩衲野鶴難繫，公呼來霅，獲望簪履。", "酒闌燭跋，孤客末至。"]'),
('681f0e09-9a98-4a08-a8aa-e4234a9d9c64','辭觀文趙忠惠墳','釋善珍','宋','宋诗','song-poetry','','[]','公歸兜率，局面屢變。',140,'全唐诗/poet.song.208000.json','["公歸兜率，局面屢變。", "青雲交絕，珠履客散。", "白傅草堂，裴公經院。", "僧定未起，樵柯將爛。", "老鶴倦飛，不慕霄漢。", "駑馬戀主，非貪豆棧。", "風雨憂愁，常占春半。", "昔倚山岳，今悲露電。", "語猶在耳，事不如願。", "病憶故鄉，一筇易辦。", "受恩莫報，遲回眷眷。", "入西州門，淚流被面。", "知音永已，絃斷琴爨。", "袖香告辭，用寫繾綣。"]'),
('b0e24e58-fa3b-47e8-b5a8-e85bd9a8a143','祭靜江帥曾吏部','釋善珍','宋','宋诗','song-poetry','','[]','公掾富沙，來就師語。',240,'全唐诗/poet.song.208000.json','["公掾富沙，來就師語。", "少服師訓，稱公豪舉。", "後二十年，麾節煌煌。", "老客輦寺，傳公除郎。", "桂聯荆渚，朔風孔棘。", "見公起家，大刀長戟。", "冠彈復挂，印刻復銷。", "羨公槍榆，如摶扶摇。", "如生馬駒，不受控勒。", "如鋼百鍊，愈不改色。", "士不患才，患不身脩。", "脩身既才，奚訾奚尤。", "士挾一能，足以駴世。", "公百其藴，而不盡試。", "私嘗嘖嘖，歎公不逢。", "公笑謂予，子何褊胸。", "墳寺虛席，乃命掃洒。", "曰子非我，子豈肯下。", "感激懷人，慷慨受知。", "愧無黄金，鑄鍾子期。", "事與心違，公又仙去。", "精靈地下，知予心事。", "哭西州門，何必羊侯。", "萬事宛如，華屋山丘。"]'),
('4bcee47f-abb3-41ad-a35f-1cb9dcb6de92','祭粹古雲代','釋善珍','宋','宋诗','song-poetry','','[]','烏乎古雲，蔚有時譽。',131,'全唐诗/poet.song.208000.json','["烏乎古雲，蔚有時譽。", "執古刀尺，割棄華組。", "宿鈔成山，臆斷意取。", "羣疑塞胸，耳領心悟。", "汲汲著書，恢恢養士。", "猗公之起，惟皇有旨。", "猗法之嗣，惟北峰有子。", "遠矣北峰，曰公是似。", "胡不百年，後學之思。", "公不百年，後學思之。", "矧予卜鄰，歲寒疇依。", "稚予閲朋，至老無幾。", "惟茲不磨，昭然永垂。"]'),
('8ef3b419-fead-4e7c-b3dd-6eb4e7f94789','祭介石','釋善珍','宋','宋诗','song-poetry','','[]','末俗住山，尤貴黄紙。',160,'全唐诗/poet.song.208000.json','["末俗住山，尤貴黄紙。", "造物畀公，共衰病至。", "既病之矣，復遇歲艱。", "當八面風，撐百漏船。", "漫刺銜袖，臨齋乞米。", "驕兒索飯，饑嗔飽喜。", "我行四方，閲士如牆。", "小智虛夸，妄夫荒唐。", "宣紹命脈，乾淳氣魄。", "天慳地閟，神盍寶惜。", "冷灰粟焰，將曉景星。", "泯滅甚易，佛法替陵。", "同時愛憎，異世悲慨。", "諸君不信，有遺錄在。", "我作苦語，模寫虛空。", "淚盡血續，夫豈爲公。"]'),
('226642d8-b6dd-468c-a858-3e95005700ad','祭光孝南老','釋善珍','宋','宋诗','song-poetry','','[]','我昔遊浙，多賢友朋。',120,'全唐诗/poet.song.208000.json','["我昔遊浙，多賢友朋。", "老歸故山，耳冷如冰。", "忽聞君來，語作吳馨。", "白而長身，美髯垂膺。", "未幾月臺，撾鼓騰騰。", "巍然廣座，攝衣而升。", "我忝隣居，復爲交承。", "君素恢疎，不立戶庭。", "舌端騁辭，驅濤卷霆。", "疾誰使之，一瞑不醒。", "七尺桐棺，蕭然行幐。", "侑此瓣香，感慨曷勝。"]'),
('66d9696e-7beb-47e7-b0cb-1a21386602f5','祭果南澗南叔凱','釋善珍','宋','宋诗','song-poetry','','[]','我憩閩北，叔凱枉顧。',180,'全唐诗/poet.song.208000.json','["我憩閩北，叔凱枉顧。", "出南澗書，劇談至暮。", "言昔之夜，得夢怪奇。", "當與藏叟，會阿耨池。", "想耶因耶，一笑眇邈。", "執手告戒，義均骨肉。", "心平行粹，愛南澗翁。", "人百忤之，而無慍容。", "凱病且貧，戶滿客屨。", "翁常解衣，騷騷治具。", "嘉翁風致，古人所難。", "鄙夫慳嗇，拔毫如山。", "吁嗟衰年，失二益友。", "耨池西方，遊必俱不。", "晝詩絕吟，永帖罷揮。", "猨哀鶴怨，金環不歸。", "弔既後時，奠復不早。", "瓣香懺悔，淚濕春草。"]'),
('e0da0313-a226-4bc1-b6ab-2a8399001224','祭見首座','釋善珍','宋','宋诗','song-poetry','','[]','佛法下衰，衆魔崢嶸。',180,'全唐诗/poet.song.208000.json','["佛法下衰，衆魔崢嶸。", "如虎而祴，白晝市行。", "晚交得君，如黄河清。", "君與予談，洞見底裏。", "予建一事，君曰可紀。", "予出一辭，君曰入理。", "狂猘狺狺，嗾之者誰。", "君躡予足，怒形于辭。", "古有徇義，捨父背師。", "曷不千指，曷不百歲。", "神祐靡專，貴姦壽悖。", "謂天昭昭，天實茫昧。", "君素清苦，簡潔自持。", "如政黄牛，標韻過之。", "有德操才，得疾亦奇。", "浮華眼前，道義千古。", "昔有微言，噤不敢吐。", "含哀以告，君必領悟。"]'),
('114a940f-e339-4d76-a7d8-90ff5bd7b9c1','祭崇福肇老','釋善珍','宋','宋诗','song-poetry','','[]','兄主兩山，無頃刻暇。',150,'全唐诗/poet.song.208000.json','["兄主兩山，無頃刻暇。", "踆踆走俗，類古普化。", "人始不識，睢盱猜訝。", "徐察情真，有樸無詐。", "翕然同聲，真本色者。", "未幾廢宇，耽耽大厦。", "昔瓶無粟，今廩多稼。", "松彎易地，筋力已謝。", "猶命肩輿，日謁百舍。", "車殆馬煩，途遠將夜。", "一身破甑，萬事飄瓦。", "追惟何及，撫事悲吒。", "飛書別我，歷舉昔話。", "云何良友，天不少借。", "一香永訣，老淚盈把。"]'),
('7fa03397-cbd9-4c46-ad3f-ee84ec5795c3','祭侃古樵塔','釋善珍','宋','宋诗','song-poetry','','[]','嘉定之間，公壯我少。',160,'全唐诗/poet.song.208000.json','["嘉定之間，公壯我少。", "意氣盡同，豈但同調。", "衆誇蠅聲，而出蚓竅。", "一唱十和，撫掌稱妙。", "公獨雄渾，間見奇峭。", "如行空麟，如追風驃。", "擁絮曦簷，煬袍夜燎。", "俄聚忽散，人事難料。", "遥睇吳雲，夐絕閩徼。", "每得尺書，恍陪色笑。", "龍鍾出嶺，隻影自弔。", "回思歲月，真過野燒。", "僂指舊游，半墮縹渺。", "叫公不應，一燈誰紹。", "銖香後時，幸毋我誚。", "飛錫何之，山深猨嘯。"]'),
('13963276-840f-4c55-a4d2-0ea672ee7668','祭雙杉塔','釋善珍','宋','宋诗','song-poetry','','[]','甲午之冬，一笑分袂。',140,'全唐诗/poet.song.208000.json','["甲午之冬，一笑分袂。", "交游累千，名字難記。", "公雖它鄉，常在眼底。", "公今隔世，猶見夢寐。", "念昔與公，情同昆弟。", "老離閩山，再飲吳水。", "三十年間，死盡流輩。", "顧瞻浮圖，洪木翳翳。", "叢林凋疎，變習日異。", "願起公死，爲砭爲劑。", "爲師爲承，爲祥爲瑞。", "千載追難，百年滿易。", "意長景促，人往物是。", "春寒野陰，感慨歔欷。"]'),
('8215f958-1027-4511-8f00-1dba49530886','祭愚谷','釋善珍','宋','宋诗','song-poetry','','[]','前春還閩，道傳公病。',170,'全唐诗/poet.song.208000.json','["前春還閩，道傳公病。", "聰明忽癡，醫不識證。", "石門迎見，悲喜深省。", "莫年客土，相依爲命。", "太白殘月，同光共影。", "吾曹恢疎，世路機穽。", "身猶棄遺，奚顧墮甑。", "古琴絕絃，缺鐺折柄。", "二子談禪，時隠几聽。", "退士獻書，阿婆窺鏡。", "鬼笑揶揄，人笑齒冷。", "少日與公，講明素定。", "丹心如鐵，空橐如罄。", "千載意長，百年俄頃。", "一死一生，遇此衰境。", "薑鹽鬻茶，油葱澆餠。", "喚公不應，老淚泉迸。"]'),
('b4590bb8-c9d5-4531-98a3-eb7cbe7e07b9','自戒','徐元杰','宋','宋诗','song-poetry','','[]','震畏四知，我畏我知。',20,'全唐诗/poet.song.208000.json','["震畏四知，我畏我知。", "心之所畏，天不可欺。"]'),
('fcb1c99d-bf74-4d39-b336-b8aa1c99e07a','館中分韻餞李大著出守上饒','徐元杰','宋','宋诗','song-poetry','','[]','赤城烏府家，忠信以爲寶。',264,'全唐诗/poet.song.208000.json','["赤城烏府家，忠信以爲寶。", "當年璧海珍，摛文絢春藻。", "光焰萬丈餘，膏丐淵浩浩。", "梯級丹霄寬，聲名日杲杲。", "幾載造筍班，細武歷蓬島。", "恬淡簡世味，真實契穹昊。", "興感秋風蓴，夢繞春色草。", "有欲爲留行，不可奪所抱。", "乃睠古江城，姑煩寄牙纛。", "除目出脩門，驩頌生野老。", "清透溪冰寒，明映巖月好。", "心傾子衿青，魄褫猾隸皂。", "饑歲忍流甿，烈風助淫潦。", "其如來暮何，弗翅蘇雨槁。", "疾驅召父車，增峻尹鐸堡。", "顧余學獨晚，遇李愧弗早。", "茲尾羣士僚，乃階二天造。", "恩休到松檟，慶色滿粱稻。", "賦別無佳言，劼毖有真禱。", "祇恐難久外，端不竢及考。", "寵褒騰璽書，虛竚副旒璪。", "其以公之歸，出手扶世道。"]'),
('715f0261-be10-468f-82e0-4711a5211fdc','題竹洲','徐元杰','宋','宋诗','song-poetry','','[]','人之生也直，此君亦如是。',252,'全唐诗/poet.song.208000.json','["人之生也直，此君亦如是。", "我酷愛此君，臭味本相似。", "方其出地初，一種根萌異。", "剛特儼不回，鈞石莫障蔽。", "日夜之所息，雨露之所漬。", "玉成脩茂姿，表表在天地。", "其靜專似仁，其動闢似智。", "其肅然似禮，其凝然似義。", "虛中純白生，似信不容僞。", "在人該五常，在天足五氣。", "六月蒼蒼寒，不附炎熱勢。", "雨雪披猖中，彈壓萬凋瘁。", "似正色立朝，忠誠著於世。", "似廣厦萬間，其蔭足以庇。", "似聞伯夷風，頑廉懦立志。", "似堅子卿節，夷險無二致。", "似見魯仲連，不復論鄙事。", "似識元紫芝，頓消名與利。", "子陵釣嚴灘，太公釣璜渭。", "風月一竿中，相從神骨契。", "持此叩竹洲，考功言外意。"]'),
('3e5b5b06-cbcd-4120-887b-8b623469d3a3','和祝子壽作詩須索意韻','徐元杰','宋','宋诗','song-poetry','','[]','翰墨絕畦逕，言詞中律度。',156,'全唐诗/poet.song.208000.json','["翰墨絕畦逕，言詞中律度。", "筆落風雨驚，詩得江山助。", "不食烟火語，說到精髓處。", "升堂必入室，由道誰不戶。", "達者無後先，成賢特指顧。", "要亦認意思，初不在章句。", "伊欲登壇場，且闊著地步。", "其中有活法，此理若大路。", "所差只毫釐，相去已冠屨。", "蘭室味本同，蓮社約此去。", "把定心鴻鵠，直須盟鷗鷺。", "多才夙究明，一見已穎悟。", "貂續不勝情，用得以布露。"]'),
('3b91d493-4cd4-4e2b-8c6c-cfb5eacaa9a7','和金兄','徐元杰','宋','宋诗','song-poetry','','[]','大學融智門，至善在所止。',192,'全唐诗/poet.song.208000.json','["大學融智門，至善在所止。", "明德與新民，貫通無異理。", "萬折水必東，千古吾晦翁。", "考亭追杏壇，猶存舞雩風。", "昔者學易堂，粵山寬閒野。", "此道聞而知，篤信無虛假。", "尚有劉靜春，至理共樂循。", "我登二老門，天方壽斯文。", "服膺善恐失，適正杜邪曲。", "當時片言下，問道不隔宿。", "學易堂已空，誰與鞭凡庸。", "靜春正耆龐，摳衣儘從容。", "襟誼子崇篤，遠來顧煢獨。", "作詩念清新，愧我言腐熟。", "四海皆弟兄，尚友惟輔仁。", "春草正碧色，話別同敷陳。"]'),
('0a552c82-6a66-449c-b32c-6e259f7eede3','送上饒皇甫宰','徐元杰','宋','宋诗','song-poetry','','[]','天下邑無不可爲，在人忍耐自爲之。',384,'全唐诗/poet.song.208000.json','["天下邑無不可爲，在人忍耐自爲之。", "信能寧心辦堅苦，事到難處天扶持。", "民吾同胞痛癢切，何忍橫斂類剝肌。", "心誠求之若子保，人亦懷之如母慈。", "上饒邇來號凋劇，苟焉稱貸負頼隨。", "况多權官慘剝割，又肆席捲公化私。", "吏奸得售科罰計，等第輸錢與斷詞。", "詞人欲休休不得，充庭塞獄纏纍纍。", "公來憤悱感動處，與認前時已貸貲。", "謂令親民民必及，民固可欺天莫欺。", "民脂民膏供我祿，胡寧又割民膏脂。", "催科僅僅欲逃責，毫分不忍科罰施。", "奉公洗手附庸邑，一孔一粒歸州司。", "請俸有時不給用，月索莊課來助支。", "屢典緡錢代月解，幾回過我同攢眉。", "聽訟元不以憚煩，使之無訟而民宜。", "相安田里閒耆保，懶出市廛謳耄倪。", "日長喧雀堪羅設，星散饑烏靡孑遺。", "花酣滿縣春風遍，草茂虛囹天意滋。", "君之來也蹙頞告，蹈此湯鑊出未期。", "屢效淵明歸去感，不求赫赫聲名馳。", "自甘陽城書考下，誰曰悶悶政術卑。", "隠隠綽有棠陰地，忽乃遽及瓜戍期。", "自上而下有公論，轅轍依依動去思。"]'),
('ae1d4dee-65d2-42a2-b101-9e581097781d','雲錦堂','徐元杰','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖之陽景絕奇，乾坤軒豁呈端倪。',288,'全唐诗/poet.song.208000.json','["太湖之陽景絕奇，乾坤軒豁呈端倪。", "分將一派清漣漪，南宮幻出紅琉璃。", "朝暾未吐烟露垂，碧紗絃裏眠江妃。", "六月火繖張赫曦，姑射山寒冰雪肌。", "妖㛠萬態不敢窺，凈洗却面凝西施。", "欲雨未雨多峰奇，霞生島上乘馮夷。", "來從西蜀江水肥，似絢吳江楓落時。", "水鄉月午舟葉携，何處更覓昆明池。", "問渠爲此堂者誰，人與鷗鷺相忘機。", "丹心緬慕周濂溪，愛其瑩質生淤泥。", "推門清風故人來，一一君子徧追隨。", "六郎姿貌當年非，肝腸染透鉛與脂。", "拈花摘葉兒女癡，弛却蠶絲牽藕絲。", "紛華一掃金飈吹，皮膚剝盡實不虧。", "晝清人靜茶烟飛，觀雲葉葉無停披。", "千綺萬纈古寶遺，底用漫天錦障幃。", "惡其文著尚絅衣，澆灌道義培根基。", "氤氳妙毓山澤姿，膚寸彌滿天地維。"]'),
('423dc0a5-3760-49f6-97ec-2874c8b1e36e','題李氏雲莊','徐元杰','宋','宋诗','song-poetry','','[]','雲本無心出，莊非有意名。',48,'全唐诗/poet.song.208000.json','["雲本無心出，莊非有意名。", "午供雷腹實，曉带月痕耕。", "身世隨舒卷，山村任晦明。", "飯疏浮富貴，畎畝但存誠。"]'),
('787aa63e-7430-41d6-ba6c-9872c191cec9','書安象祖靜軒有感','徐元杰','宋','宋诗','song-poetry','','[]','太極即人極，坤爻德不孤。',48,'全唐诗/poet.song.208000.json','["太極即人極，坤爻德不孤。", "直方真主宰，敬靜實功夫。", "老檜霜中榦，寒梅雪裏株。", "常惺惺法處，收斂物俱無。"]'),
('04e01d69-bde2-4422-a405-1cb2c5beb4df','和袁守','徐元杰','宋','宋诗','song-poetry','','[]','和糴存和氣，春生墾闢時。',48,'全唐诗/poet.song.208000.json','["和糴存和氣，春生墾闢時。", "民庸天上見，歲事臘前知。", "吾諺諸侯度，誰褰使者帷。", "樂民之樂者，犂雨趣耕治。"]'),
('150126b8-34d9-4451-90b8-31d7ccd444ba','和章宰訪祝子壽來青書院韻','徐元杰','宋','宋诗','song-poetry','','[]','文昌因祖餞，郎宿問齋名。',48,'全唐诗/poet.song.208000.json','["文昌因祖餞，郎宿問齋名。", "枉駕一朝款，寒窗千載榮。", "未花梅索賦，堪杖竹經行。", "自得來青句，山泉不可清。"]'),
('dbef28c6-5f41-4f37-87e5-da4ecf0cf889','送尹子潜赴省','徐元杰','宋','宋诗','song-poetry','','[]','吾儕堅世好，心事老天知。',48,'全唐诗/poet.song.208000.json','["吾儕堅世好，心事老天知。", "夢寐符前說，軒翔定此時。", "故家當有後，造物本無私。", "雪裏陽春脚，梅開第一枝。"]'),
('2f1ec83b-9202-4db2-a909-e0428d1abd33','贈臨川胡斗文求叢桂書院字','徐元杰','宋','宋诗','song-poetry','','[]','莫訝書齋小，其中天地寬。',48,'全唐诗/poet.song.208000.json','["莫訝書齋小，其中天地寬。", "毓成岐嶷粹，立取本原端。", "掇拾童科易，恢弘道術難。", "好培叢桂種，休作浪花看。"]'),
('67c0cfc1-496f-49ee-a2ad-d25166e02e9b','贈徐鑑堂','徐元杰','宋','宋诗','song-poetry','','[]','鑑堂均此號，兄與弟相先。',48,'全唐诗/poet.song.208000.json','["鑑堂均此號，兄與弟相先。", "畫以名家顯，神於活法傳。", "雙眸蟾皎潔，兩袖羽蹁躚。", "落筆人人似，柯山本是仙。"]'),
('9d193ba5-34ce-42ad-8629-0e84721eb7ca','又用韻答何上舍','徐元杰','宋','宋诗','song-poetry','','[]','臘雪多爲瑞，豐穰隔歲知。',48,'全唐诗/poet.song.208000.json','["臘雪多爲瑞，豐穰隔歲知。", "林巒銀劔戟，苑囿玉壺池。", "映几孫書飽，卧冰祥母饑。", "疾風看正色，餘事付清詩。"]'),
('c8e41c44-5266-471a-9dd0-d7f690492918','挽克齋陳先生四首  其一','徐元杰','宋','宋诗','song-poetry','','[]','薰炙儒先早，朱門授受親。',48,'全唐诗/poet.song.208000.json','["薰炙儒先早，朱門授受親。", "去尋顔巷樂，歸詠點雩春。", "道妙窮精一，心傳有省循。", "樂天知命者，憂道不憂貧。"]'),
('7b2c0df6-550d-452d-8821-d527148c7e1c','挽克齋陳先生四首  其二','徐元杰','宋','宋诗','song-poetry','','[]','親養九旬餘，先生壽亦如。',48,'全唐诗/poet.song.208000.json','["親養九旬餘，先生壽亦如。", "學充淇澳美，訓釋濟南書。", "諸老經筵送，俞音寵渥疏。", "惜非程子聘，中沮亦時歟。"]'),
('0adab2d6-3ed4-4db5-b3d4-66f42106f540','挽克齋陳先生四首  其三','徐元杰','宋','宋诗','song-poetry','','[]','師承心獨切，於道愧無聞。',48,'全唐诗/poet.song.208000.json','["師承心獨切，於道愧無聞。", "幾載鑽堅歎，前年枉教勤。", "墨車回可贊，晉鄙善潜薰。", "道脈惟其壽，天胡遽喪文。"]'),
('a79c7431-b4ce-4795-8063-5d72a400809c','挽克齋陳先生四首  其四','徐元杰','宋','宋诗','song-poetry','','[]','痛慘哲人痿，愚纏喪母悲。',48,'全唐诗/poet.song.208000.json','["痛慘哲人痿，愚纏喪母悲。", "遡風懷紼路，泣雨寫哀詞。", "學本藏諸用，行皆篤所知。", "惟餘經訓在，交付有孫枝。"]'),
('b5549c12-2efb-42cb-aee2-9a0d26b483f4','挽求志居士王料院二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','奕葉文宗盛，如公罕與俱。',48,'全唐诗/poet.song.208000.json','["奕葉文宗盛，如公罕與俱。", "源流傳紫橐，題品重洪樞。", "淛左清名凜，江南政績殊。", "二難薌共薦，生死亦同塗。"]'),
('92a6434b-35b1-4db5-89b0-cbd6632b5401','挽求志居士王料院二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','身忝蓬萊客，摳衣謁使臣。',48,'全唐诗/poet.song.208000.json','["身忝蓬萊客，摳衣謁使臣。", "麈談頻款曲，樽酒屢殷勤。", "政事欽前蹟，詩書聳舊文。", "話言猶在耳，不忍哭公墳。"]'),
('aa9d2a90-9240-4ee3-bb4c-0c9463667217','挽分寧張少仙二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','貌與心俱古，歲寒松檜蒼。',48,'全唐诗/poet.song.208000.json','["貌與心俱古，歲寒松檜蒼。", "學高眸炯月，吟苦鬢先霜。", "能賦秋賓早，收功晚節香。", "滿門弓冶趣，有鶚待雲翔。"]'),
('9079a7ac-802a-42f1-b7d9-fe1b613ea2f5','挽分寧張少仙二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','當路知公諗，搜揚入剡科。',48,'全唐诗/poet.song.208000.json','["當路知公諗，搜揚入剡科。", "才難行志易，官小及民多。", "北部勞人耳，東皈奈命何。", "郵音嗟忽斷，空有淚滂沱。"]'),
('4cab6e7c-1551-4427-a512-66684fa82efa','挽宜春趙別駕二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','叢桂論文舊，辛酸話早年。',48,'全唐诗/poet.song.208000.json','["叢桂論文舊，辛酸話早年。", "虀鹽朝慣苦，膏火夜無眠。", "一第酬初志，殊勳策步仙。", "激昂英氣宇，緩步赤霄躔。"]'),
('b302d1bd-fe15-4786-b9bb-bef38697b103','挽宜春趙別駕二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','詩債松邊了，鉏荒賸種花。',48,'全唐诗/poet.song.208000.json','["詩債松邊了，鉏荒賸種花。", "雲程衡麓雁，風味仰山茶。", "白玉樓成速，金鑾事可嗟。", "桃源千古恨，寒日慘啼鴉。"]'),
('145158bf-ac83-46d8-bab6-bd1e10a97929','挽辛憲若五首  其一','徐元杰','宋','宋诗','song-poetry','','[]','在昔我先翁，禮廑先正隆。',48,'全唐诗/poet.song.208000.json','["在昔我先翁，禮廑先正隆。", "潭潭带湖府，凜凜玉溪風。", "夜韭觴籌裏，春花唱詠中。", "懷哉秋水去，世好孰如公。"]'),
('42506c78-597a-478d-add8-f3f066322d61','挽辛憲若五首  其二','徐元杰','宋','宋诗','song-poetry','','[]','榮顯宜超躐，威聲憺外陲。',48,'全唐诗/poet.song.208000.json','["榮顯宜超躐，威聲憺外陲。", "邊疆多嶮歷，麾節兩朝推。", "范子甲兵有，張名草木知。", "急流緣底勇，路口峴山碑。"]'),
('f702793d-a5ce-4d57-9c30-ab88de764a02','挽辛憲若五首  其三','徐元杰','宋','宋诗','song-poetry','','[]','十載居間學，瓢泉映潔清。',48,'全唐诗/poet.song.208000.json','["十載居間學，瓢泉映潔清。", "陶潜黄菊趣，杜老白鷗盟。", "雲自無心出，春隨有脚行。", "知非古巴蜀，使指若爲情。"]'),
('acef6096-7814-437f-abac-e81d381c265e','挽辛憲若五首  其四','徐元杰','宋','宋诗','song-poetry','','[]','旌廉優召節，丐佚得臨漳。',48,'全唐诗/poet.song.208000.json','["旌廉優召節，丐佚得臨漳。", "靜退家庭舊，清芬滋味長。", "病中知命見，力上掛冠章。", "了了遺言善，雖亡實不亡。"]'),
('68a4e57f-54cf-4d97-92dc-84fb8b400a18','挽辛憲若五首  其五','徐元杰','宋','宋诗','song-poetry','','[]','眷義門牆舊，交遊手足如。',48,'全唐诗/poet.song.208000.json','["眷義門牆舊，交遊手足如。", "方勤來妣賻，忍寫慰公書。", "繼世多先烈，諸郎總令譽。", "觀音山路黯，飛些重欷歔。"]'),
('4bbec9cf-3296-43e3-99d4-be87c3581a85','挽王迪功','徐元杰','宋','宋诗','song-poetry','','[]','徼好年家後，知公月旦先。',48,'全唐诗/poet.song.208000.json','["徼好年家後，知公月旦先。", "寵榮身外物，孝友性中天。", "趣自怡堂得，詩從猶子傳。", "故園遺蹟恨，月落早無邊。"]'),
('cb8e4858-a044-4a83-8558-1c7101d38633','題方氏綠野園三首  其一','徐元杰','宋','宋诗','song-poetry','','[]','佳景環深院，開門遠俗隣。',48,'全唐诗/poet.song.208000.json','["佳景環深院，開門遠俗隣。", "徑幽通鳥雀，溪迥隔風塵。", "客過宜樽酒，時來與物春。", "好風爲我至，蕭散足怡神。"]'),
('5faa554e-f612-4781-a016-7f9c03b6b45f','題方氏綠野園三首  其二','徐元杰','宋','宋诗','song-poetry','','[]','衆木欣欣茂，扶筇到故家。',48,'全唐诗/poet.song.208000.json','["衆木欣欣茂，扶筇到故家。", "樓高春月曉，池曲暮烟斜。", "物化遷無定，徘徊興自嘉。", "悠然塵外想，隨意樂年華。"]'),
('b2153049-d1e7-4fe1-a16b-a945e5ffd73f','題方氏綠野園三首  其三','徐元杰','宋','宋诗','song-poetry','','[]','春晝情無限，欣看綠野叢。',48,'全唐诗/poet.song.208000.json','["春晝情無限，欣看綠野叢。", "折花紅带露，種竹曉生風。", "自有悠閒趣，何須繪畫工。", "名園多勝致，高詠與誰同。"]'),
('9fc6063b-20e9-43b1-ad56-f86e62fe1fa5','次趙守鹿鳴宴韻','徐元杰','宋','宋诗','song-poetry','','[]','邦侯光價擅文場，密印心胸書傳香。',64,'全唐诗/poet.song.208000.json','["邦侯光價擅文場，密印心胸書傳香。", "鳴鹿載歌苹野什，驕驊羣跨杏園芳。", "陽春有脚葭吹管，生意無邊柳著行。", "已報主人環玉立，與觀賓句遞春坊。"]'),
('5f12e14d-5969-419b-bbd1-0f1e96298ded','次章守鹿鳴宴韻','徐元杰','宋','宋诗','song-poetry','','[]','儒宮新創俯青溪，上挹魁躔踵舊規。',64,'全唐诗/poet.song.208000.json','["儒宮新創俯青溪，上挹魁躔踵舊規。", "鶚薦聯名充賦日，龍飛親策采言時。", "指迷承學雲中路，珍重賢侯席上詩。", "只有梅花知此意，東君著眼是先期。"]'),
('0b899379-4a0f-4434-81c2-f86768588fb1','及第謝恩','徐元杰','宋','宋诗','song-poetry','','[]','聖朝天子薦臨軒，嘉與愚臣究本原。',64,'全唐诗/poet.song.208000.json','["聖朝天子薦臨軒，嘉與愚臣究本原。", "天地兩間扶景運，唐虞三代印微言。", "慙無一德酬清問，猥玷初班誤聖恩。", "一節誓堅忠與孝，立身端不負乾坤。"]'),
('7d8d2ca4-cc3d-46ed-a5ac-5f6e91b6700f','甲辰恭和御製','徐元杰','宋','宋诗','song-poetry','','[]','衮衣日月炳當軒，光逮芻蕘采衆言。',64,'全唐诗/poet.song.208000.json','["衮衣日月炳當軒，光逮芻蕘采衆言。", "內外修攘明治體，憂勤終始養心源。", "英髦瑞列霜中榦，治化春回雪裏根。", "願溥需雲蘇物槁，九垓滂沛洽君恩。"]'),
('e3381f6d-80f9-42ac-aab3-b4a547ae7c51','戊戌恭和御製','徐元杰','宋','宋诗','song-poetry','','[]','明庭親策廣蒐賢，識治朋來誼少年。',64,'全唐诗/poet.song.208000.json','["明庭親策廣蒐賢，識治朋來誼少年。", "肆秩瓊林賓燕衎，載頒寶畫寵光延。", "此時禮樂三千字，他日丹青數百篇。", "螻蟻懷忠賡帝詠，相先事業誓神僊。"]'),
('5c066b9b-a878-46b1-a14a-46cb181c5a56','戊戌館中分韻餞劉祕書','徐元杰','宋','宋诗','song-poetry','','[]','聖明欽恤重皋陶，一日飛星五使軺。',64,'全唐诗/poet.song.208000.json','["聖明欽恤重皋陶，一日飛星五使軺。", "方幸蓬山陪末屬，遽瞻英簜隔層霄。", "諄諄天語扶邦計，念念民生弼教條。", "輕重適權孚簡眷，金雞山色讖雞翹。"]'),
('df5e76af-aad4-4646-a7ba-114ffbfdeaed','瓊林宴恭和御製','徐元杰','宋','宋诗','song-poetry','','[]','丹墀密勿對堯言，忠款拳拳實戀軒。',64,'全唐诗/poet.song.208000.json','["丹墀密勿對堯言，忠款拳拳實戀軒。", "帝學緝熙方顯行，聖心左右已逢原。", "光昭寶畫敷明訓，儀侈瓊林匝異恩。", "百拜賡歌天日皎，報君惟有此心存。"]'),
('ba840a0f-b461-4af8-bbb9-50bda2f3d32a','入講論語二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','溫溫中旨肅傳宣，魯語書陳誦說專。',64,'全唐诗/poet.song.208000.json','["溫溫中旨肅傳宣，魯語書陳誦說專。", "聖意聿宗伊洛訓，愚臣謹繹考亭編。", "寸心普物根源地，百拜承顔咫尺天。", "堯舜吾君持所學，敢陳他道對王前。"]'),
('c747fea9-a764-4895-963a-03633afb2b4f','入講論語二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','躬承清問及年豐，蠶麥今還與舊同。',64,'全唐诗/poet.song.208000.json','["躬承清問及年豐，蠶麥今還與舊同。", "稼穡艱難周聖慮，農桑勸課即田功。", "志民深閔僖公雨，勤業猶存豳國風。", "懇懇召和關主德，我皇心直與天通。"]'),
('77b18ae2-7189-4fae-9170-4203d810220e','直宿禁中','徐元杰','宋','宋诗','song-poetry','','[]','清和時候玉堂宣，愚亦何人厠講筵。',64,'全唐诗/poet.song.208000.json','["清和時候玉堂宣，愚亦何人厠講筵。", "但覺夢回深夜爽，不知身在九霄眠。", "志裨君德從容地，戀切宸恩咫尺天。", "願散輝光燭幽隠，肯專榮耀賁金蓮。"]'),
('6f84aafc-88ac-438a-a729-e5b2200ce5db','部中觀新竹有感','徐元杰','宋','宋诗','song-poetry','','[]','粉署窗前小竹林，子孫蟄蟄得春深。',64,'全唐诗/poet.song.208000.json','["粉署窗前小竹林，子孫蟄蟄得春深。", "土膏肥迸蒼龍角，地髮抽遲紫玉簪。", "簷近十分饒宿溜，牆高終日硋層陰。", "南風昨夜陽和透，放出參天勁節森。"]'),
('cd166434-9f69-4163-bfeb-b46e6717bfcc','早起玉堂窗前俯方池有感','徐元杰','宋','宋诗','song-poetry','','[]','玉堂窗外小池深，香霧朝浮花氣沈。',64,'全唐诗/poet.song.208000.json','["玉堂窗外小池深，香霧朝浮花氣沈。", "樹杪亭亭鴉點墨，萍根發發鯉跳金。", "中涵一勺淵泉定，上有九重天日臨。", "充廣恩波無盡意，敢渝潔白寸丹心。"]'),
('f45aae23-ae76-47a6-8ee4-8fe308c0ca81','供銓部職','徐元杰','宋','宋诗','song-poetry','','[]','愚生何幸聖明遭，官府宮牆上界高。',64,'全唐诗/poet.song.208000.json','["愚生何幸聖明遭，官府宮牆上界高。", "冰雪身心參宿列，日星條令揭天曹。", "二南美意存周召，九德淳風慨禹皋。", "我亦空餐慙汝士，諄諄惟切痛民膏。"]'),
('4ed0a684-afc0-4b3a-8f40-8d70a21c93c6','宿部觀銓法苦蚊','徐元杰','宋','宋诗','song-poetry','','[]','炎方典禮始郊迎，夜宿銓闈暑氣清。',64,'全唐诗/poet.song.208000.json','["炎方典禮始郊迎，夜宿銓闈暑氣清。", "萬物洪纖俱夏長，九天寬大遍春生。", "眼明剔蠹牙籤滑，手倦驅蚊玉箑輕。", "我自黑甜深帳穩，不容形遁曉窗明。"]'),
('a8953e27-70e3-447f-a45a-07161f894b58','題嚴陵瀟灑亭','徐元杰','宋','宋诗','song-poetry','','[]','天遣溪山付客星，翠屏中界玉澄泓。',64,'全唐诗/poet.song.208000.json','["天遣溪山付客星，翠屏中界玉澄泓。", "無邊瀟灑寸心遠，有分登臨雙眼明。", "浄洗胸中參范老，細於詩裏勘元英。", "千年相望神相入，一脈清風要主盟。"]'),
('70d494ff-41a7-4a24-a52c-88f4870f4a7a','題靜軒','徐元杰','宋','宋诗','song-poetry','','[]','主靜非專在靜時，至於動處亦隨之。',64,'全唐诗/poet.song.208000.json','["主靜非專在靜時，至於動處亦隨之。", "聖賢學問惟知止，敬義工夫要夾持。", "所養勿忘由勿助，其中何慮又何思。", "莫教鶻突名軒意，物誘情遷幾坐馳。"]'),
('bccefe44-7464-4c70-8e0e-181856ad22ed','題趙南卿愚山','徐元杰','宋','宋诗','song-poetry','','[]','愚山山上謫仙徒，到底真愚却不愚。',64,'全唐诗/poet.song.208000.json','["愚山山上謫仙徒，到底真愚却不愚。", "山色長供詩料富，山居贏得俗塵無。", "逍遥天地南華子，隠約簞瓢陋巷癯。", "定力不同山不改，一生雙眼不渠孤。"]'),
('e6e44f8a-c371-4cf7-bfb2-a4f3c6814ef2','題金氏三桂堂','徐元杰','宋','宋诗','song-poetry','','[]','見說庭階玉樹芳，薰教書史郁心香。',64,'全唐诗/poet.song.208000.json','["見說庭階玉樹芳，薰教書史郁心香。", "郤詵林峙應難並，燕竇枝繁未足方。", "莫羨三槐森鉅府，且看三桂列華堂。", "多聞直諒成三益，松竹梅花共雪霜。"]'),
('9d4b9c2b-9786-4e2c-9cd2-75c434a11551','次韻何陸二別駕同遊靈山閣三首  其一','徐元杰','宋','宋诗','song-poetry','','[]','平分風月兩悠哉，勝踐春濃花未摧。',64,'全唐诗/poet.song.208000.json','["平分風月兩悠哉，勝踐春濃花未摧。", "蕭寺適今重建閣，蘭亭懷古共流杯。", "典型二老溪山重，唱詠諸公今日開。", "慙我枯腸元蹇澀，底教頭上片雲催。"]'),
('9c1ecb2e-8567-497e-8072-2d55921104b0','次韻何陸二別駕同遊靈山閣三首  其二','徐元杰','宋','宋诗','song-poetry','','[]','聞說精藍頗壯哉，天教傑棟起崔嵬。',64,'全唐诗/poet.song.208000.json','["聞說精藍頗壯哉，天教傑棟起崔嵬。", "簷前山色呈螺髻，檻外溪光獻玉杯。", "對景自應雙眼豁，憂時應得笑顔開。", "喚回忠定遺芳躅，衮衮雲霄步武催。"]'),
('12b329a4-4acd-43d9-8187-7eb68f3b624a','次韻何陸二別駕同遊靈山閣三首  其三','徐元杰','宋','宋诗','song-poetry','','[]','彼美前修亦偉哉，巋然風雨不能摧。',64,'全唐诗/poet.song.208000.json','["彼美前修亦偉哉，巋然風雨不能摧。", "人新人古懷斯閣，春去春來付一杯。", "遊興漫隨流水去，衰眸長對好山開。", "銷凝往事憑欄久，杜宇一聲烟際催。"]'),
('d806ae1b-3874-4ed5-bed5-126376cb611d','登靈鷲千佛閣爲往山野堂紹祖留題','徐元杰','宋','宋诗','song-poetry','','[]','彊支疲薾此躋攀，屈指曾遊十載間。',64,'全唐诗/poet.song.208000.json','["彊支疲薾此躋攀，屈指曾遊十載間。", "方丈喜添千佛閣，雙眸陟豁四圍山。", "可無可有僧衣鉢，隨得隨供佛面顔。", "門外雪深知幾許，只消透得箇重關。"]'),
('292345f6-6d0f-4973-aa86-a29e7de45267','夢神人曰公當以是字名庵覺來賦是庵詩','徐元杰','宋','宋诗','song-poetry','','[]','審是須防自是偏，四通八達路平平。',64,'全唐诗/poet.song.208000.json','["審是須防自是偏，四通八達路平平。", "伊周孔孟是心一，堯舜湯文是道傳。", "善惡正邪書裏月，行藏用舍性中天。", "聖賢萬語千言訂，箇字來從太極先。"]'),
('496d39a4-da6b-47e5-b66e-4d9aa9cfb35a','詠以人與天地萬物爲一體刻印章詩','徐元杰','宋','宋诗','song-poetry','','[]','三才中立囿形均，昧者拘拘利乃身。',64,'全唐诗/poet.song.208000.json','["三才中立囿形均，昧者拘拘利乃身。", "不道有身皆有血，豈應知我不知人。", "其間一物容虧性，是即四肢頑不仁。", "洞洞八荒皆我闥，豁然窺見等天真。"]'),
('9cb9651a-b024-4909-9b0a-7fbffc4811da','贊勉昶道者題經','徐元杰','宋','宋诗','song-poetry','','[]','念佛直須參佛透，看經容易悟經難。',64,'全唐诗/poet.song.208000.json','["念佛直須參佛透，看經容易悟經難。", "聲音未必如來見，盂鉢長教嶺上觀。", "了得貪嗔癡一集，更超戒定慧三般。", "祖師食盡人間蔗，千古留楂咬嚼看。"]'),
('48a1a12f-6a5e-4756-a87b-4b17fe768e4f','席間和周穎齋韻','徐元杰','宋','宋诗','song-poetry','','[]','清泉白石誘登臨，凈瞰軒窗竹一林。',64,'全唐诗/poet.song.208000.json','["清泉白石誘登臨，凈瞰軒窗竹一林。", "雋永如君真有味，膏肓和我不須鍼。", "流行坎止人難必，果育蒙亨力要深。", "一笑相逢邀一勺，喜渠介潔似儂心。"]'),
('e3ee380a-0f40-4b29-8fde-192086209ab8','送畏齋何監簿添倅解替東歸','徐元杰','宋','宋诗','song-poetry','','[]','春風行李萬篇詩，明月歸舟幾片碑。',64,'全唐诗/poet.song.208000.json','["春風行李萬篇詩，明月歸舟幾片碑。", "千載岫雲佳話柄，兩年懷玉淡生涯。", "已聞北闕飛丹詔，早趁南薰度赤墀。", "歷歷口開天下事，直聲元是九重知。"]'),
('02fb19a7-22e6-4e18-b69d-c4ea2c781b91','送紹興葉帥改當塗  其一','徐元杰','宋','宋诗','song-poetry','','[]','八年于外與民宜，徧歷穹臺閫又麾。',64,'全唐诗/poet.song.208000.json','["八年于外與民宜，徧歷穹臺閫又麾。", "襟度乾坤無忤物，鬢髯霜雪却緣誰。", "寬平到底人懷去，廉靖如初帝簡知。", "受善如流聞義勇，真誠端以古求之。"]'),
('155df9c1-8183-4871-abd3-cdc490f0b042','送紹興葉帥改當塗  其二','徐元杰','宋','宋诗','song-poetry','','[]','人言禹會即當塗，上曰蕪湖抵鑑湖。',64,'全唐诗/poet.song.208000.json','["人言禹會即當塗，上曰蕪湖抵鑑湖。", "姑少副公求去爾，匪伊有詔盍歸乎。", "知心霜月渾無滓，回首春風定與俱。", "慙愧蓬萊賓客後，願言陪侍入天衢。"]'),
('6a7c0af8-af58-4906-8b9c-6749c607d731','送陳國珍之官鄱陽','徐元杰','宋','宋诗','song-poetry','','[]','盟締慈恩十四年，匆匆話別戍梅仙。',64,'全唐诗/poet.song.208000.json','["盟締慈恩十四年，匆匆話別戍梅仙。", "便家澤國冰溪壤，得庇皇華刺史天。", "事到直須行己志，官卑最喜近氓編。", "許多靜定清修力，警戒聲名企昔賢。"]'),
('b75aaecf-c281-4b45-af05-1b5e24f404d9','餞上饒推幕葉西澗召爲國子錄二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','魁耀來從古赤城，三年冰水一般清。',64,'全唐诗/poet.song.208000.json','["魁耀來從古赤城，三年冰水一般清。", "蓮池婉婉中流砥，米廩行行要路程。", "悟主讜言須啟沃，康時偉業待恢宏。", "却慙疎窳深知遇，別後音書等弟兄。"]'),
('bf43d466-d002-4206-8d5b-56b9b54490b8','餞上饒推幕葉西澗召爲國子錄二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','客有携來端水珉，天然中界玉圭形。',64,'全唐诗/poet.song.208000.json','["客有携來端水珉，天然中界玉圭形。", "送君早入薇垣紫，結劄先登藜閣青。", "要看濡毫香典籍，直須提筆福生靈。", "端凝正笏如山立，匪石斯心社稷經。"]'),
('32e26ed6-b44c-4cc2-a0a5-1eb3db114539','餞江東繡使庸齋趙玉堂二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','天上玉堂辭寵榮，却持玉節按江城。',64,'全唐诗/poet.song.208000.json','["天上玉堂辭寵榮，却持玉節按江城。", "惟刑之恤民心悅，不怒而威吏膽驚。", "有脚春來陶化日，無心雲出雨蒼生。", "箇中運量常提醒，元氣循環晝夜行。"]'),
('a209b6ce-fd76-4899-8ba9-21342b205159','餞江東繡使庸齋趙玉堂二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','福星分野大江東，道味蓬山聚話中。',64,'全唐诗/poet.song.208000.json','["福星分野大江東，道味蓬山聚話中。", "漠漠暮雲詩興感，依依何日酒樽同。", "虛心無我爰咨度，養氣知言協粹沖。", "望切衮歸基宥密，可能無夢到周公。"]'),
('2c23d960-f7ce-4d58-a278-03a3108c8cfc','餞永豐易丞赴庾檄','徐元杰','宋','宋诗','song-poetry','','[]','世道圓通更直方，松陰庭院亦聲光。',64,'全唐诗/poet.song.208000.json','["世道圓通更直方，松陰庭院亦聲光。", "眼明英簜公題品，身入芙蓉婉贊襄。", "田里歎愁從此達，公私幽枉待君揚。", "更煩好斡東君造，一道奸貪凜雪霜。"]'),
('cf68d857-5cbb-4695-a797-e74567ff3a6a','別旴江易耕道','徐元杰','宋','宋诗','song-poetry','','[]','點勘窗前晝景舒，豁人雙眼綠陰敷。',64,'全唐诗/poet.song.208000.json','["點勘窗前晝景舒，豁人雙眼綠陰敷。", "明方寸地通三極，會一理中該萬殊。", "靜體陽工生意思，密融心匠活工夫。", "丁寧後會秋風鶚，萬里青冥是坦塗。"]'),
('7afab0da-b6e9-4ad3-8ae9-31e66bb01806','贈歐陽奇父偕弟益卿赴省','徐元杰','宋','宋诗','song-poetry','','[]','中朝耆舊半淪亡，憂愛胡爲𤱶畝忘。',64,'全唐诗/poet.song.208000.json','["中朝耆舊半淪亡，憂愛胡爲𤱶畝忘。", "我病不禁心痛折，天災惟有涕流滂。", "救時議論須知體，醫國文章要識方。", "期子聲名相照映，好風天際雁成行。"]'),
('0881b04d-6f02-4465-a065-aa12bc370441','贈方介石','徐元杰','宋','宋诗','song-poetry','','[]','介石翁來契所思，騷吟風雅儘追隨。',64,'全唐诗/poet.song.208000.json','["介石翁來契所思，騷吟風雅儘追隨。", "庾清鮑逸可無酒，島瘦郊寒只有詩。", "原不染塵圭竇適，未能忘世璧雍馳。", "賦違恰限江天雪，說向梅花心事知。"]'),
('c75f2c82-0492-4078-b889-57c14f247e16','贈章酉仲','徐元杰','宋','宋诗','song-poetry','','[]','滿門賢粹鶚橫秋，文藻如君行愈修。',64,'全唐诗/poet.song.208000.json','["滿門賢粹鶚橫秋，文藻如君行愈修。", "道本虛靈天內有，學於平實地中求。", "堅凝力量誠無息，收斂精神外不浮。", "充養腴豐隨用顯，大而敦化小川流。"]'),
('33efecc5-0d5e-4696-ac65-02fd440e5c17','贈香溪留君東上','徐元杰','宋','宋诗','song-poetry','','[]','近代騷人詠性情，隨心而發自分明。',64,'全唐诗/poet.song.208000.json','["近代騷人詠性情，隨心而發自分明。", "吐吞風月咽喉爽，咀嚼江山齒頰清。", "溪邑近聞工比興，君詩端可派宗盟。", "馬頭雪絮吟鞭快，好辦佳篇奏集英。"]'),
('cff1d899-fd9b-4970-acfe-0007a9b581c8','贈談星葉生','徐元杰','宋','宋诗','song-poetry','','[]','至誠之道可前知，知命如君亦甚奇。',64,'全唐诗/poet.song.208000.json','["至誠之道可前知，知命如君亦甚奇。", "二十八星輪指掌，兩三年事印蓍龜。", "春來春去元無盡，花落花開自有時。", "門外青山知此意，只教松柏鎮如斯。"]'),
('f49e83ef-f131-4fdb-ac80-431fa97c5b60','贈日者盧生','徐元杰','宋','宋诗','song-poetry','','[]','相逢未縱談天口，開口便教儂賦詩。',64,'全唐诗/poet.song.208000.json','["相逢未縱談天口，開口便教儂賦詩。", "我語只堪供覆瓿，子行聊贈若爲資。", "忘憂對草閒供詠，濺泪看花重感時。", "何日重來當刮目，只談風月得舒眉。"]'),
('39649d30-dfc5-44f3-9bbd-e6a5d5bd6ddd','又贈日者曰清朝貴官','徐元杰','宋','宋诗','song-poetry','','[]','歆艷清朝作貴官，人人都把命來看。',64,'全唐诗/poet.song.208000.json','["歆艷清朝作貴官，人人都把命來看。", "未言造化窮天理，且據干支鋪卦盤。", "富貴熱中從古有，功名向上每才難。", "榮枯勘破花開落，始識霜松自歲寒。"]'),
('f7f9839c-7af7-47bd-836c-608982474d46','贈日者楊應齋','徐元杰','宋','宋诗','song-poetry','','[]','爛柯山客命能知，人事更番一局棋。',64,'全唐诗/poet.song.208000.json','["爛柯山客命能知，人事更番一局棋。", "甜卦易窮行苦卦，此時相語驗他時。", "窮通任理胡不可，災福緣人要自持。", "我老只堪漁釣隠，衰慵夢不到蒼姬。"]'),
('1e8e5764-d813-45ef-a866-9b877776a5f2','贈日者李成齋','徐元杰','宋','宋诗','song-poetry','','[]','譚天玄徹李成齋，豫訊東風著早梅。',64,'全唐诗/poet.song.208000.json','["譚天玄徹李成齋，豫訊東風著早梅。", "自昔不離三正備，謂予带得五行來。", "窮通於我何加者，演測如君亦偉哉。", "說到常人難說處，靈臺湛處現星臺。"]'),
('5ba2abb9-a6be-4d05-99e8-32166f40f5c1','題金華徐伯光義聚規約  其一','徐元杰','宋','宋诗','song-poetry','','[]','至矣前人惠後人，愛之無不用吾情。',64,'全唐诗/poet.song.208000.json','["至矣前人惠後人，愛之無不用吾情。", "寸心千慮規前定，六世一門家太平。", "愈久愈教同保守，不容不念始經營。", "業爲可繼宜休養，夜夜春雷鼻息鳴。"]'),
('0ff9a890-53cc-4c0f-9bd7-3fd3a4ee4afe','題金華徐伯光義聚規約  其二','徐元杰','宋','宋诗','song-poetry','','[]','每慨人無善後圖，蕩然家檢亦何疎。',64,'全唐诗/poet.song.208000.json','["每慨人無善後圖，蕩然家檢亦何疎。", "眼前漫不知由己，身後誰能管得渠。", "喜見雙溪今軌範，更綿一脈古詩書。", "了知斯聚更斯義，散及宗枝廣義居。"]'),
('2642f2a5-93e6-465c-9f36-7e7dbdefc5dc','挽黄制屬','徐元杰','宋','宋诗','song-poetry','','[]','家傳山谷舊簪纓，志業剛豪早有聲。',64,'全唐诗/poet.song.208000.json','["家傳山谷舊簪纓，志業剛豪早有聲。", "二子學文能紹志，一官拜命竟辭榮。", "琴齋不聽驚人語，鉞閫空留薦剡名。", "借問松坡誰是主，疎梅淡月兩凄清。"]'),
('fef8add7-d3c5-4888-b8a1-aa6447ad1205','挽吳準齋','徐元杰','宋','宋诗','song-poetry','','[]','壯歲能官不厭卑，愴懷霜露蚤知幾。',64,'全唐诗/poet.song.208000.json','["壯歲能官不厭卑，愴懷霜露蚤知幾。", "扣其學問中心得，如此典型今代希。", "天子詔之堅遜避，朝端達者夙瞻依。", "甲辰重晤言前定，痛述生平淚忍揮。"]'),
('2279e7a7-ad78-406c-b736-696e56c732c3','挽前南劍添倅楊料院','徐元杰','宋','宋诗','song-poetry','','[]','泣別監州隔死生，薄雲茲義更何人。',64,'全唐诗/poet.song.208000.json','["泣別監州隔死生，薄雲茲義更何人。", "草青彭蠡湖邊曉，花滿江郎峰畔春。", "每慨共官惟氣直，略無片語不情真。", "西芹香火家家意，所欠箋天澤徙薪。"]'),
('e91d618e-f205-4f20-8f55-218a1a1a70c7','挽都大王郎中二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','魁望西來職祕丘，年家託好敘綢繆。',64,'全唐诗/poet.song.208000.json','["魁望西來職祕丘，年家託好敘綢繆。", "身爲僚友兩三月，公肅皇華百八州。", "列緯載班清劇耀，高風遽勇急中流。", "訃聞落晚呼天咽，涕泗交頤重所憂。"]'),
('3599e359-5fde-4a36-b3a2-b66a4c272a0d','挽都大王郎中二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','一門孝友古難爲，堅苦端凝更自持。',64,'全唐诗/poet.song.208000.json','["一門孝友古難爲，堅苦端凝更自持。", "如此典型今代少，粹然言論滿朝推。", "若人已矣嗟何及，魂氣信乎無不之。", "楚水薌溪生死地，英靈上訴九原知。"]'),
('65d79958-2f32-42d3-b6ca-a94e6fa169e7','送郡守','徐元杰','宋','宋诗','song-poetry','','[]','郎圍師閫重王人，朝績民庸簡帝宸。',384,'全唐诗/poet.song.208000.json','["郎圍師閫重王人，朝績民庸簡帝宸。", "屈此偏州何小小，偉哉仁牧自肫肫。", "下車福十餘萬戶，褒璽朞三百六旬。", "廉恕公勤持四字，癢疴疾痛切吾身。", "顯幽一理初開鎮，撫字丹心肅告神。", "動有發明基學力，略無凝滯見情真。", "智常周物能容物，政每近民深得民。", "居理家庭培玉植，燭臨官吏皎冰輪。", "行其無事州閭靖，急所當先夙夜寅。", "溪以玉名聞瑩潔，巖如日色共晶新。", "吟肩峭若靈峰峙，詩骨清於南澗濱。", "坐嘯中和堂上邃，猶存正始古音淳。", "無心雲出當年岫，有脚陽生此地春。", "不忍一毫傷赤子，了知方寸即蒼旻。", "邦人鏤膽交相語，糴事關心尤至仁。", "往者過征罹暴虐，甚而乾沒啟囂嚚。", "炎天陸運枯膏血，累月肩擔摧骨筋。", "五百里程陪搭斛，四千錢費各沾巾。", "農夫搔動征夫苦，行者攫挐居者嗔。", "所幸天高常耳下，惟公露禱悉言諄。", "一分寬受一分賜，半減誰知半減因。", "問穀幾何先給直，作舟用濟廣通津。", "聽民樂與官爲市，如己隠憂眉輒顰。", "怨氣收聲回逸樂，歡謠鼓腹飽輪囷。"]'),
('ba39d627-aeb4-4357-897c-8c2b577f2ddd','題俞簿梅阜書院','徐元杰','宋','宋诗','song-poetry','','[]','淺清溪滸瘦山巔，凈洗肌膚冰雪天。',32,'全唐诗/poet.song.208000.json','["淺清溪滸瘦山巔，凈洗肌膚冰雪天。", "偏向書窗伴幽獨，不教塵俗滓嬋娟。"]'),
('256285c7-193f-4245-bc54-c8628766cedc','來青書院桃花','徐元杰','宋','宋诗','song-poetry','','[]','塞滿乾坤本是仁，更無一物不洪鈞。',32,'全唐诗/poet.song.208000.json','["塞滿乾坤本是仁，更無一物不洪鈞。", "山桃自不知麤俗，也與梅花鬭早春。"]'),
('e49b206b-9871-4f1e-930d-bf34dd7cb7c7','游鷲峰贈埜堂和尚','徐元杰','宋','宋诗','song-poetry','','[]','目斷天鵝影不留，梵風吹落鷲峰頭。',32,'全唐诗/poet.song.208000.json','["目斷天鵝影不留，梵風吹落鷲峰頭。", "野堂四大無窗壁，散誕當年箇野牛。"]'),
('579ef5a7-97c8-4f66-be43-4ff981651a97','丫頭巖','徐元杰','宋','宋诗','song-poetry','','[]','丫頭不是女丫鬟，把作堅牢擔拄看。',32,'全唐诗/poet.song.208000.json','["丫頭不是女丫鬟，把作堅牢擔拄看。", "撐定東南天半壁，鎮教雙聳碧雲端。"]'),
('0caacbca-3f49-46af-8ad7-bd20901beacd','以琴送郡守二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','詩翁雅鎮玉溪山，褒璽飛來玉節還。',32,'全唐诗/poet.song.208000.json','["詩翁雅鎮玉溪山，褒璽飛來玉節還。", "爲報佳音天日近，南薰殿裏正催班。"]'),
('802867e7-b77c-4114-be4b-79d2bd535b2e','以琴送郡守二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','天朝交口重聲名，公自翛然物外情。',32,'全唐诗/poet.song.208000.json','["天朝交口重聲名，公自翛然物外情。", "氓有焦桐旌往戀，當年靖獻與俱清。"]'),
('5d0083f1-ce25-4766-961f-b3975c1ab160','訊劍浦主簿詹棟齋','徐元杰','宋','宋诗','song-poetry','','[]','竹林饑午隠禪扉，合傍鸞栖亦此栖。',32,'全唐诗/poet.song.208000.json','["竹林饑午隠禪扉，合傍鸞栖亦此栖。", "時一參寮茶供罷，可能無語到雙溪。"]'),
('5e2f44bb-cb08-42fb-8439-9e622f992db8','送俞兄赴省','徐元杰','宋','宋诗','song-poetry','','[]','得雋文場氣勿盈，便如捧玉謹持盈。',32,'全唐诗/poet.song.208000.json','["得雋文場氣勿盈，便如捧玉謹持盈。", "鄉邦畢竟辰年好，冰雪身心上帝京。"]'),
('2c5d7463-6b1b-4c72-8670-47b7af0df47f','餞劉恭父二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','割鐙難留乘馬東，花枝爭看裊長紅。',32,'全唐诗/poet.song.208000.json','["割鐙難留乘馬東，花枝爭看裊長紅。", "衮衣空使斯民戀，綠竹誰歌入相同。"]'),
('1d0606a3-e1e8-4ac9-a4d6-f2f5546ebb62','餞劉恭父二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','樂事遲回致歲豐，幾多遺愛在湘中。',32,'全唐诗/poet.song.208000.json','["樂事遲回致歲豐，幾多遺愛在湘中。", "須知楚水楓林下，不似初聞長樂鐘。"]'),
('76a27747-7c14-4285-ae3e-e38f7ad4ef29','和李文溪送青雲道人歸杭韻','徐元杰','宋','宋诗','song-poetry','','[]','丹成會見君身蛻，我欲從之更問天。',32,'全唐诗/poet.song.208000.json','["丹成會見君身蛻，我欲從之更問天。", "喚醒橫江孤鶴夢，憑君持此叩坡仙。"]'),
('da8441fa-24be-433c-9821-f1f2ce0bab73','和懷玉本老','徐元杰','宋','宋诗','song-poetry','','[]','失脚天台絕頂峰，又來懷玉亂山中。',32,'全唐诗/poet.song.208000.json','["失脚天台絕頂峰，又來懷玉亂山中。", "瓊橋去後無消息，禪月重重有案公。"]'),
('a5553aaa-eecd-4efd-9e08-265af6ad91d9','題日者李成齋所藏李文清幅','徐元杰','宋','宋诗','song-poetry','','[]','相公提筆福蒼生，印得當年命術精。',32,'全唐诗/poet.song.208000.json','["相公提筆福蒼生，印得當年命術精。", "鈞翰珍藏塞翁馬，六丁嚴護不容驚。"]'),
('e6e9e14f-451b-45ce-b889-e5948654682d','和汪君','徐元杰','宋','宋诗','song-poetry','','[]','胸次秋風澗底蘋，坐間那得此嘉賓。',32,'全唐诗/poet.song.208000.json','["胸次秋風澗底蘋，坐間那得此嘉賓。", "詩來香迸宵人屋，笑殺元規塵汙人。"]'),
('c8ebd385-340a-487a-b446-2270f57b2b80','贈毛梅谷','徐元杰','宋','宋诗','song-poetry','','[]','彈琴須會鍾子期，畫梅莫遜楊補之。',32,'全唐诗/poet.song.208000.json','["彈琴須會鍾子期，畫梅莫遜楊補之。", "墨妙坡仙助揮掃，雪晴霜夜月明時。"]'),
('74dbd291-0523-4625-824c-859231eb1dc9','贈風鑒神眼','徐元杰','宋','宋诗','song-poetry','','[]','世道支撐儘要人，閲人多後眼通神。',32,'全唐诗/poet.song.208000.json','["世道支撐儘要人，閲人多後眼通神。", "一朝相去三丞相，今昔同歸識認親。"]'),
('c393fb4a-576c-4246-9204-3ffde446bf19','贈鑑堂','徐元杰','宋','宋诗','song-poetry','','[]','方寸無塵眼有筋，如他圖了幾勳臣。',32,'全唐诗/poet.song.208000.json','["方寸無塵眼有筋，如他圖了幾勳臣。", "更煩提起丹青手，寫出驚天動地人。"]'),
('b0e96868-c202-44a4-aab7-7ad5bedfeeb3','贈刀鑷王誠三首  其一','徐元杰','宋','宋诗','song-poetry','','[]','刀鑷王生勇黜妻，痛憐白髮有親慈。',32,'全唐诗/poet.song.208000.json','["刀鑷王生勇黜妻，痛憐白髮有親慈。", "紛紛世上私妻子，聞有斯人死愧之。"]'),
('beaafa67-de8d-4959-93e2-5948e43fe0a8','贈刀鑷王誠三首  其二','徐元杰','宋','宋诗','song-poetry','','[]','汝家住近里仁坊，不戀妻兒戀侍旁。',32,'全唐诗/poet.song.208000.json','["汝家住近里仁坊，不戀妻兒戀侍旁。", "父子性天非可奪，親親仁也盍揄揚。"]'),
('6da80e9f-790a-49b7-a721-4d1ccfb5c2f7','贈刀鑷王誠三首  其三','徐元杰','宋','宋诗','song-poetry','','[]','婦人蓋亦有仁心，只爲冥頑溺愛深。',32,'全唐诗/poet.song.208000.json','["婦人蓋亦有仁心，只爲冥頑溺愛深。", "今此警之當愧死，何妨重理舊絃琴。"]'),
('891d8d63-22c7-49dd-9066-87f27a859f00','贈日者林雪庵','徐元杰','宋','宋诗','song-poetry','','[]','雪庵笑我頭如雪，雪幹須知立歲寒。',32,'全唐诗/poet.song.208000.json','["雪庵笑我頭如雪，雪幹須知立歲寒。", "會面炎炎朱夏日，門庭雪澹自相看。"]'),
('e8042eca-7c1f-4128-aea9-cc193d8cd873','又贈術士薛鏡臺二首  其一','徐元杰','宋','宋诗','song-poetry','','[]','儒流今以術爲資，滿腹星躔洞隠微。',32,'全唐诗/poet.song.208000.json','["儒流今以術爲資，滿腹星躔洞隠微。", "自號鏡臺須自照，逢人休浪泄天機。"]'),
('8183d186-6015-4b37-a5af-1f04ac073284','又贈術士薛鏡臺二首  其二','徐元杰','宋','宋诗','song-poetry','','[]','始吾爲養喜徼榮，今恨孤孱感慨增。',32,'全唐诗/poet.song.208000.json','["始吾爲養喜徼榮，今恨孤孱感慨增。", "白髮滿頭何所用，只存憂願數年登。"]'),
('3b1046d7-fbaa-4b1f-ac00-49566a14f3e7','大巧','徐元杰','宋','宋诗','song-poetry','','[]','大巧工夫本不全，清光鑿破未教圓。',32,'全唐诗/poet.song.208000.json','["大巧工夫本不全，清光鑿破未教圓。", "豈無妙補蒼穹手，修滿冰輪送上天。"]'),
('a8df7175-91f1-4e64-9197-badfa3c1b81e','畫龍','徐元杰','宋','宋诗','song-poetry','','[]','崢嶸頭角見龍神，畫者微茫畫得真。',32,'全唐诗/poet.song.208000.json','["崢嶸頭角見龍神，畫者微茫畫得真。", "一夜風雷捲將去，沛爲膏澤下於民。"]'),
('4961643f-b402-4f2a-ab15-4263845d9b36','湖上','徐元杰','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5", "\u6625\u6e38", "\u5199\u666f", "\u897f\u6e56"]','花開紅樹亂鶑啼，草長平湖白鷺飛。',32,'全唐诗/poet.song.208000.json','["花開紅樹亂鶑啼，草長平湖白鷺飛。", "風物晴和人意好，夕陽簫鼓幾船歸。"]'),
('054f4137-6034-40c8-9965-5c6aca618825','初夏','徐元杰','宋','宋诗','song-poetry','','[]','橫波淚竹紋鋪簟，疊雪輕羅香剪衣。',32,'全唐诗/poet.song.208000.json','["橫波淚竹紋鋪簟，疊雪輕羅香剪衣。", "清夏槐生風細細，新秋麥漲雨霏霏。"]'),
('2220fe44-44ce-40a4-a53e-69e82c9ba384','荷花','徐元杰','宋','宋诗','song-poetry','','[]','鼓角聲中璧月光，竹輿十里繞橫塘。',64,'全唐诗/poet.song.208000.json','["鼓角聲中璧月光，竹輿十里繞橫塘。", "碧摇仙子凌波襪，紅散天絲織錦裳。", "彷彿若耶溪上路，棲迷太華井邊凉。", "入城不覺東方白，吹散一身風露香。"]'),
('c00cea75-4a42-46e4-9f14-b389deef7f6c','雪','徐元杰','宋','宋诗','song-poetry','','[]','瓦聲初聽響疏疏，頃刻庭除百斛珠。',32,'全唐诗/poet.song.208000.json','["瓦聲初聽響疏疏，頃刻庭除百斛珠。", "寒雀不知來啄米，群雞粥粥亦相呼。"]'),
('699b2ed3-6258-4e36-b69b-dca6f95ff68f','村家','徐元杰','宋','宋诗','song-poetry','','[]','疏烟落日路三叉，敗葉乾風屋數家。',32,'全唐诗/poet.song.208000.json','["疏烟落日路三叉，敗葉乾風屋數家。", "場圃畢工梁月出，傍簷紅女績絲麻。"]'),
('5661d7d8-df96-413a-9130-db6ecb226e67','郊行','徐元杰','宋','宋诗','song-poetry','','[]','百花只被一晴催，一出郊行花盡開。',32,'全唐诗/poet.song.208000.json','["百花只被一晴催，一出郊行花盡開。", "携杖奚奴趁先去，路迷青草却回來。"]'),
('11a5fa6a-e0e7-4a0a-a1f1-67811a8fc67f','山行','徐元杰','宋','宋诗','song-poetry','','[]','步繞青秧綠水間，春畦交錯路回環。',32,'全唐诗/poet.song.208000.json','["步繞青秧綠水間，春畦交錯路回環。", "老翁牽得牛當路，恐礙人行却復還。"]'),
('2e572d9a-caf0-40e0-a916-7da9e542a0bb','旅舍燈','徐元杰','宋','宋诗','song-poetry','','[]','荒居雨醒已昏黄，敗壁張燈四散光。',64,'全唐诗/poet.song.208000.json','["荒居雨醒已昏黄，敗壁張燈四散光。", "相待村炊同坐久，更陪幽夢入更長。", "屋頭雞唱驚孤枕，門外馬嘶催曉裝。", "僮僕告行吾亦去，空房留爾重凄凉。"]'),
('e98c686d-f222-46f2-8d95-63862faf789d','蜘蛛','徐元杰','宋','宋诗','song-poetry','','[]','倦倚闌干小院東，蜘蛛驚雀墮虛空。',64,'全唐诗/poet.song.208000.json','["倦倚闌干小院東，蜘蛛驚雀墮虛空。", "細看縷縷掛枝上，旋復絲絲收腹中。", "偶爾得生誠險道，幸而不墮頼無風。", "如何薄相才安迹，便欲經營網衆蟲。"]'),
('7e96a33b-3203-442c-8605-c8f440d6765c','登仙人掌山','徐元杰','宋','宋诗','song-poetry','','[]','山名仙掌足盤桓，未醉黄花半日閒。',32,'全唐诗/poet.song.208000.json','["山名仙掌足盤桓，未醉黄花半日閒。", "更上一層高著眺，此身擬可透天關。"]'),
('a3354f05-c34d-40ec-b10c-bd7660ef6f52','張司法寓齋','唐士恥','宋','宋诗','song-poetry','','[]','玄錄五千言，妙在不敢先。',48,'全唐诗/poet.song.208000.json','["玄錄五千言，妙在不敢先。", "留侯獨得之，帝師赤松仙。", "孰知百世下，乃有雲孫焉。", "扁齋以爲寓，空谷音跫然。"]'),
('d0f6b28a-32ae-4665-9769-9b7a537fce4d','送臨江交代張司理','唐士恥','宋','宋诗','song-poetry','','[]','子房帝王師，溢慶流裔孫。',132,'全唐诗/poet.song.208000.json','["子房帝王師，溢慶流裔孫。", "朅來之蕭灘，快覩芝眉溫。", "亭亭起黄氣，中有陰德存。", "宜哉孔融表，輻輳排天閽。", "通籍何足道，履聲還青氈。", "嗟我一何幸，夤緣踵符文。", "自顧菲且愚，續貂誠所難。", "承顔一甲子，夙昔披晤言。", "柳濃烟冥冥，鷁舟江吐吞。", "順流急如箭，催鼓且勿喧。", "爲語徒作惡，且盡沙頭尊。"]'),
('87533dbf-9ff3-405c-85cf-0dff262c0149','古意','唐士恥','宋','宋诗','song-poetry','','[]','天公與世人，幽明分懸隔。',48,'全唐诗/poet.song.208000.json','["天公與世人，幽明分懸隔。", "無口難得言，欲言但以臆。", "以臆或未喻，寄之夜簷滴。", "懇款語世人，世人還不識。"]'),
('b014a41b-f016-4ed6-bb87-60806e31fc8a','寄題蠲流亭','唐士恥','宋','宋诗','song-poetry','','[]','烏傷仇覽仙，一弓扁蠲流。',48,'全唐诗/poet.song.208000.json','["烏傷仇覽仙，一弓扁蠲流。", "清流從誰蠲，濁流石之幽。", "石之幽定可，齒齒翻成憂。", "君看得失珠，象罔無全牛。"]'),
('d57b1b66-5f6a-40ca-907a-9d9a39d911f9','時賢明鑒裁','唐士恥','宋','宋诗','song-poetry','','[]','時賢明鑒裁，鑒裁信奇歟。',260,'全唐诗/poet.song.208000.json','["時賢明鑒裁，鑒裁信奇歟。", "識此希世寶，謂其曾區區。", "未冠已溢聲，賢書上宸庭。", "不一而止足，竟壓四海英。", "直入九華招隠遁，化工尤物殊不吝。", "文章光焰勝燃犀，遠至牛渚爥無盡。", "歸來紀事滿縑帛，却屑米鹽繁密訊。", "天公終不屈大器，稱表直上幾晝晉。", "倚伏之機真叵測，庖丁全牛有餘刃。", "先生道大何所容，顔淵今用退爲進。", "一以涵養使莫折，一以淑我邦之俊。", "然而鑒裁還合明，孔席未暖五鶚并。", "此時廟謨正陶鬰，驅屏塵翳須昇平。", "驅屏塵翳須昇平，要當迅召文武卿。", "時來時來烏可禦，譬如南海雲鵬程。", "他年功業就，縑冊傳永久。", "劣哉魏無知，僅此遮拙醜。", "皇家褒舉者，曠典華衮右。"]'),
('4e9c4993-df60-41d9-8c82-40ed8cfabe4b','庭下青書带','唐士恥','宋','宋诗','song-poetry','','[]','庭下青書带，書带瑞康成。',260,'全唐诗/poet.song.208000.json','["庭下青書带，書带瑞康成。", "康成還遁世，行藏理則明。", "六經具縑冊，儒先效勳績。", "誰知百世下，其功明且亟。", "易首純乾稱六龍，六龍御天風雲從。", "書始唐堯大中世，蕩蕩如天莫可蹤。", "詩則二南淵且奧，春秋賞罰王道通。", "禮樂灰於秦火酷，然其遺意和且雍。", "漢儒掇拾無遺力，兀守章句非從容。", "二京之末康成出，六經將出逢此翁。", "然而本無超俗姿，猶寄視聽於盲聾。", "豈如先生一理貫，洞照六籍羅心胸。", "歷數帝王如一二，天地由我方全功。", "仲尼春秋欲成日，麟出魯郊殊超軼。", "孔道大哉雖不用，所感亦大非凡質。", "區區一康成，書带瑞已形。", "先生非此比，況茲道既行。", "當使麟鳳輩，雜沓更縱橫。"]'),
('8ae1ae48-5d90-4a96-b716-f9c30792b5ed','六月望日月堂老禪示僕衆偈隨喜愧甚','唐士恥','宋','宋诗','song-poetry','','[]','江月主人清冰壺，以月名堂月不如。',96,'全唐诗/poet.song.208000.json','["江月主人清冰壺，以月名堂月不如。", "門前船泊五湖客，兩眼歷照心與俱。", "我來追凉暑云徂，牛腰大軸開我愚。", "萬口一辭贊歎月，還贊堂中老苾芻。", "歸塗昏鴉夜氣作，東方擁出玉蟾車。", "月堂著語何可已，金屑落眼成嗟吁。"]'),
('d47598e3-d0fe-42ff-ba1f-d6f9fd54a1ab','綠槐陰','唐士恥','宋','宋诗','song-poetry','','[]','槐陰似尼父，軼軌追前蹤。',244,'全唐诗/poet.song.208000.json','["槐陰似尼父，軼軌追前蹤。", "絕塵非學步，所産夐無雙。", "今此于越東，鍾孕亦鴻龐。", "朅來于越西，掌教開羣迷。", "羣迷於今正有頼，肯使玉佩從他之。", "昔人種槐根細細，坐閲日月蟬已棲。", "歷聘轍環嗟不遇，豈若今日廊廟歸。", "要俾六經日益明，俗還唐虞熙又熙。", "槐陰雖異道則一，彼不見用吾登躋。", "宇宙雖云宏且邈，理焉所在成均齊。", "槐陰槐陰異今昔，一則不用一明陟。", "道在六經道固存，道出六經道還得。", "洪哉尼父懷此道，今日誰知歸探討。", "探討既力道不殊，三都遂隳陳常討。", "天驕立可傾，神州立可清。", "一祖八宗地，教化登升平。", "先生爲黄髮，自可七六經。"]'),
('34f9f3ca-b042-4034-9196-4c7b1e728a3e','兩溪','唐士恥','宋','宋诗','song-poetry','','[]','矧今兩溪間，溪間足風物。',276,'全唐诗/poet.song.208000.json','["矧今兩溪間，溪間足風物。", "水清石泚泚，林橫山兀兀。", "春日鳴倉庚，夏夜風月清。", "秋畆金穎秀，冬洲暮雪平。", "比爲二皇所旁薄，赤松屹立羊縱橫。", "叱石而興真戯耳，可羨人家好弟兄。", "西則三洞足仙靈，奇哉石穴聲鏗鏗。", "瀑泉噴寫資照耀，儼如冰蠶之所成。", "夕陽斜带九華度，何媿芙蓉崢且嶸。", "鼎湖遥望在其東，翠氣鬰鬰初日爭。", "或資登覽逸杖屨，或供睇望煩留情。", "山川如此足所産，所産足以冠羣英。", "聖明常重育才地，遴選鴻儒爲博士。", "儻膺是選真出羣，禮樂詩書四不悖。", "有如孔門來不拒，迪以至理滋無外。", "將見吳邦如魯國，魯多君子非虛僞。", "我公未期年，弦歌溢民編。", "論其淑吾邦，不爲淹巨賢。", "旦夕會詔至，四大豈在邊。"]'),
('3e146c00-452b-4549-9c61-ea0a2be56b7e','詠史','唐士恥','宋','宋诗','song-poetry','','[]','明皇固英主，開元天下昌。',76,'全唐诗/poet.song.208000.json','["明皇固英主，開元天下昌。", "如何林甫輩，得産無盡殃。", "國色真國色，多惑四海慝。", "華清宮裏人如玉，解喚胡雛起東北。", "以此策明妃，遠嫁猶爲遲。", "冤哉毛延壽，盡忠人不知。"]'),
('a9b3dc35-094e-4ce7-b1ac-c5ef0e800f6a','題彭紹墨','唐士恥','宋','宋诗','song-poetry','','[]','彭紹之墨玄又玄，問誰得法託之仙。',112,'全唐诗/poet.song.208000.json','["彭紹之墨玄又玄，問誰得法託之仙。", "凌烟膠漆有三昧，魯直之什曹洞禪。", "我欲大振獅子吼，直恐驚翻龍象筵。", "紛紛是事但且置，一言爲語千金廉。", "唐人五字魂遶天，箕歛四大歸新篇。", "空餘句法落寰海，豆萁不覺相熬煎。", "中原可復墨可黔，鬢絲白髮知何年。"]'),
('86fb92f5-89f4-4578-90a5-754e8e736597','代人上謝丞相生朝','唐士恥','宋','宋诗','song-poetry','','[]','聞說中元生上相，萊公勳業無以尚。',80,'全唐诗/poet.song.208000.json','["聞說中元生上相，萊公勳業無以尚。", "陰爲月兮月爲臣，清光欲滿銀蕩蕩。", "銀光蕩蕩翻未奇，未若新弦初上時。", "堯蓂鼎來方十枝，韜藏萬斛冰雪輝。", "萊公比公應少歉，初度差公四日期。"]'),
('3f3400e7-a141-4b41-aa82-d4bc18a283d2','鳳山逸士周遇仙謠','唐士恥','宋','宋诗','song-poetry','','[]','信雲步謁洞霄宮，飯罷從游西復東。',384,'全唐诗/poet.song.208000.json','["信雲步謁洞霄宮，飯罷從游西復東。", "唇笛嘯時吹白日，詩腸開處嚼清風。", "兀兀騰騰心了足，灣灣屈屈水欹曲。", "玲瓏綠影萬株松，瀟灑清空二畝竹。", "天風吹泉飛雪花，溪石漱玉磨銀牙。", "白雲破碎漏天碧，青靄牽連遮日華。", "玉溜幾聲鳴綠薺，金藤千尺走青蛇。", "羊腸蟠路上天去，鹿角枯槎連日墜。", "一雙素足已昇騰，萬頃紅霞留不住。", "擘破青空見太清，飛連寶殿非凡成。", "水晶樓閣奏金韻，翡翠簾櫳振佩聲。", "白雪翩翻霜鶴舞，綵雲縹緲花鸞鳴。", "中有真人鼎玉立，晴光閃電瓊波溢。", "笑整霓裳曳絳霞，紅雲影裏輕相挹。", "琳琅清徹語希夷，嚼玉吐瓊聲不移。", "素手擘開碧玉匣，青空飛出丹虹蜺。", "蟠摇活走遶天闕，衝透太虛光皎潔。", "須臾直上紫霄中，寶篆飛騰羅日月。", "影摇六合金色光，丹鳳對躍蒼龍驤。", "回頭指點青空裏，玉籙丹臺已籍紀。", "低頭招手令向前，漏泄天機歛不已。", "等閒贈我赭丹砂，行滿功成歸我家。", "天上逍遥多快樂，人間紛擾無垠涯。", "丹砂接得便吞了，回首雲軿俱杳杳。"]'),
('8527c849-d003-487a-b5d7-3c573c98a130','送許寺丞五十韻','唐士恥','宋','宋诗','song-poetry','','[]','漢家循吏傳，表表是龔黄。',288,'全唐诗/poet.song.208000.json','["漢家循吏傳，表表是龔黄。", "奏最承恩寵，高才躐廟堂。", "身隨名不朽，功與賞相當。", "汗簡時逾久，攀轅事莫詳。", "何如身際幸，合有頌揄揚。", "維古蕭州上，騰精斗度旁。", "國初新畫壤，餉目舊如岡。", "昨歲乾仍潦，頻年儉且霜。", "幾成炊易子，那恃黍登場。", "饑饉連千屋，焦勞自一王。", "深仁推惻隠，遴選及慈祥。", "捐廩雖蒙澤，安貧亦振綱。", "腸空朝息怒，骨立暮生光。", "盡反三農業，交騰五袴章。", "誠通俄頃刻，雩應不尋常。", "原表猶多穫，人間亟小康。", "何門無囷積，有土盡金穰。", "薄試爲霖手，聊施活國方。", "一豐能造次，再稔更芬芳。", "將見紅囷粟，全登白粲檣。", "飭儒殫富教，考課冠循良。", "出入操脩並，淵源學問長。", "躬修香寢旨，驩奉綵衣觴。", "坐嘯庭多暇，行軒樂未央。"]'),
('b1dd2118-8c47-4b3c-b914-b41a9a7ab6fb','代趙守上韓平原生辰五十韻','唐士恥','宋','宋诗','song-poetry','','[]','天佑升平主，時生不世賢。',288,'全唐诗/poet.song.208000.json','["天佑升平主，時生不世賢。", "源流多柱石，勳業滿雲烟。", "昔者謀深幄，今茲壓細氈。", "三登裨聖化，八表仰英躔。", "初度光輝發，重侯鼎鼐傳。", "台符明炳炳，壽秩啟綿綿。", "良月初弦上，珍蓂八葉鮮。", "門弧喬木茂，床笏慶枝連。", "芝玉更麟鳳，干戈雜豆籩。", "食牛增氣概，卜弁借騰鶱。", "會遇真神比，亨通正吉先。", "龍翔雲五色，璧合歷千年。", "密借留侯策，端同仲父權。", "鉞旄交粲爛，師揆却蟬聯。", "輦轂殊庭暇，圭茅錫祉堅。", "圖回無間隟，運用獨周旋。", "生息寧屯澤，才猷入大甄。", "十年如一日，廣照及重淵。", "物在由儀詠，人懷頌德篇。", "汗編深以刻，銀筆大如椽。", "慶歷并元祐，商高若漢宣。", "開禧仍酌古，堯舜欲無前。", "幾許彌縫力，初無緩急弦。", "有年偏總總，束帛倍戔戔。"]'),
('c16058c0-0f6f-4a17-8598-b7a6c659ee0c','代人次韻曹郎中雷字二首  其一','唐士恥','宋','宋诗','song-poetry','','[]','駢羅瑟玉盡珍材，須女輝躔色爲開。',64,'全唐诗/poet.song.208000.json','["駢羅瑟玉盡珍材，須女輝躔色爲開。", "并合鄭鄉如旦月，鏗宏唐律過春雷。", "共驚高義摩雲表，定上夷庚握斗魁。", "鵬鷃逍遥俱有適，亨衢端是匝天回。"]'),
('9d245a35-1b1b-4077-9983-c48dac31f17d','代人次韻曹郎中雷字二首  其二','唐士恥','宋','宋诗','song-poetry','','[]','計偕方此媿非材，先達仍勞綺席開。',64,'全唐诗/poet.song.208000.json','["計偕方此媿非材，先達仍勞綺席開。", "已喜摳衣披密霧，還將雅什助驚雷。", "定須勁翮摩雲舞，各是清班重哲魁。", "任昉龍門如細許，直須早早借春回。"]'),
('a84345b7-de59-4acd-8c29-bbf4732984df','效進退律賦水鄉三實  其一','唐士恥','宋','宋诗','song-poetry','','[]','根荄七竅倍玲瓏，産爾亭亭曲渚風。',64,'全唐诗/poet.song.208000.json','["根荄七竅倍玲瓏，産爾亭亭曲渚風。", "勇退霞衣香故在，駢生玉子味仍鍾。", "人言太華標奇種，藕大如船想碧蓬。", "何待非常誇世俗，祇今盤露已能穠。"]'),
('1f9a60d4-f764-4777-890e-89f0b9240460','效進退律賦水鄉三實  其二','唐士恥','宋','宋诗','song-poetry','','[]','冰雪胸懷七澤姿，纖纖舞袖學雙飛。',64,'全唐诗/poet.song.208000.json','["冰雪胸懷七澤姿，纖纖舞袖學雙飛。", "袢襟應念人間世，灌頂何如山上芝。", "荷葉巧偷鸚鵡背，蓴絲密綴燕雛衣。", "回塘相伴薰風裏，爭看臙脂黛綠施。"]'),
('ea71d218-97d2-4571-b537-37ae3fd4e5df','效進退律賦水鄉三實  其三','唐士恥','宋','宋诗','song-poetry','','[]','明珠久合蚌中生，何事鴻頭亦炳靈。',64,'全唐诗/poet.song.208000.json','["明珠久合蚌中生，何事鴻頭亦炳靈。", "襟護重重殊襲復，星分顆顆倍晶明。", "一車奇謗嗟成誤，十斛平量換合成。", "珍重櫻桃樊素口，致渠磊落更歌聲。"]'),
('0e4f38de-6b2b-482d-9b2b-a2a3e7476bd8','丙寅孟夏聞捷和陳宰','唐士恥','宋','宋诗','song-poetry','','[]','朝家遵養自三宗，一旦吾皇定一戎。',64,'全唐诗/poet.song.208000.json','["朝家遵養自三宗，一旦吾皇定一戎。", "近事長庚偏入月，清詩太白又先功。", "天聲地界光今古，帝邑王京共會同。", "延喜樓前新冠带，應多黄髮頌歸忠。"]'),
('58dfb568-075a-4777-b535-aedb2c597a81','癸酉旴江鹿鳴燕和羅守','唐士恥','宋','宋诗','song-poetry','','[]','倫魁玉季樂羣英，更有新醅屬步兵。',64,'全唐诗/poet.song.208000.json','["倫魁玉季樂羣英，更有新醅屬步兵。", "飫勉茂才爭賈勇，盡從擊楫不留行。", "共酬露冕吹鐃意，好近氈書淡墨榮。", "北海清樽今勸駕，夢回池草倍知名。"]'),
('166d1a26-2ca5-4ff8-bcbb-f97eb65ed327','送傑老住仙遊  其一','唐士恥','宋','宋诗','song-poetry','','[]','肉譜知何從，塗高流亦深。',24,'全唐诗/poet.song.208000.json','["肉譜知何從，塗高流亦深。", "漢相似堯相，奕蘭端至今。"]'),
('ef448470-d69c-4157-80a7-32b464af9937','送傑老住仙遊  其二','唐士恥','宋','宋诗','song-poetry','','[]','至生恰平生，一萬八千日。',24,'全唐诗/poet.song.208000.json','["至生恰平生，一萬八千日。", "頭白無所成，唯堪伴幽逸。"]'),
('4bc875af-aa1e-4dc5-b3f3-ba6e9010a6b1','送傑老住仙遊  其三','唐士恥','宋','宋诗','song-poetry','','[]','差入栴檀林，自古只公選。',24,'全唐诗/poet.song.208000.json','["差入栴檀林，自古只公選。", "迺知天定時，丹成骨自換。"]'),
('97cdfb4e-fce1-4c24-b94c-a09f87741af8','送傑老住仙遊  其四','唐士恥','宋','宋诗','song-poetry','','[]','仙遊知幾年，晨香梵古佛。',24,'全唐诗/poet.song.208000.json','["仙遊知幾年，晨香梵古佛。", "人移境亦移，高風日披拂。"]'),
('0d3893d6-0416-4717-a4d8-51237e63a420','送傑老住仙遊  其五','唐士恥','宋','宋诗','song-poetry','','[]','一瓶還一鉢，作戯且逢場。',24,'全唐诗/poet.song.208000.json','["一瓶還一鉢，作戯且逢場。", "會看走鶴書，橫寶今道傍。"]'),
('805848cd-8c3b-45df-b91e-e9fb6c81d0c3','送傑老住仙遊  其六','唐士恥','宋','宋诗','song-poetry','','[]','白雲每亭亭，其出亦何心。',24,'全唐诗/poet.song.208000.json','["白雲每亭亭，其出亦何心。", "賢侯考之天，無謂由蹄涔。"]'),
('d2e3755e-f734-4882-9ef8-9831752f2efb','送傑老住仙遊  其七','唐士恥','宋','宋诗','song-poetry','','[]','飛錫破曉色，紅葉弄吳楓。',24,'全唐诗/poet.song.208000.json','["飛錫破曉色，紅葉弄吳楓。", "聞名且見面，清明豁長空。"]'),
('bef63c2e-b827-40c6-8b95-4fb7c53aa425','送傑老住仙遊  其八','唐士恥','宋','宋诗','song-poetry','','[]','方期秋氣高，遍閲山水窟。',24,'全唐诗/poet.song.208000.json','["方期秋氣高，遍閲山水窟。", "青鞋此蜚動，幽意那可及。"]'),
('c66b3952-dadf-436c-ae9f-83d2cb68196f','送傑老住仙遊  其九','唐士恥','宋','宋诗','song-poetry','','[]','端坐閲四時，爛然各有第。',24,'全唐诗/poet.song.208000.json','["端坐閲四時，爛然各有第。", "新篇敵島可，郵筒當數寄。"]'),
('cca7a859-1812-4a05-a74b-02d83b810a65','送傑老住仙遊  其一○','唐士恥','宋','宋诗','song-poetry','','[]','中庭可明月，況此方揚輝。',24,'全唐诗/poet.song.208000.json','["中庭可明月，況此方揚輝。", "霏譚隔千里，使我幾忘歸。"]'),
('88719c49-6b92-4a56-a58f-e4627658d8ee','上余倅生辰唐律十章  其一','唐士恥','宋','宋诗','song-poetry','','[]','暫握侯章乘五馬，馬頭秋色轉分明。',32,'全唐诗/poet.song.208000.json','["暫握侯章乘五馬，馬頭秋色轉分明。", "麻源起應精純禱，一雨增添玉宇清。"]'),
('90b8be84-c69b-45b0-885e-f33f30698557','上余倅生辰唐律十章  其二','唐士恥','宋','宋诗','song-poetry','','[]','此事人惟歸厚德，那知天意箇中明。',32,'全唐诗/poet.song.208000.json','["此事人惟歸厚德，那知天意箇中明。", "君看略掃妖狐窟，喚得傾盆雨自生。"]'),
('f6e26482-9748-421f-80c7-4669a6451844','上余倅生辰唐律十章  其三','唐士恥','宋','宋诗','song-poetry','','[]','雨餘非霧縈瓊斚，正是長庚初度時。',32,'全唐诗/poet.song.208000.json','["雨餘非霧縈瓊斚，正是長庚初度時。", "千里歡聲和氣滿，祝公椿算壽齊箕。"]'),
('0d07f792-6242-4e49-b36f-4a0a3f1a9558','上余倅生辰唐律十章  其四','唐士恥','宋','宋诗','song-poetry','','[]','諶旴二母畢從姑，各獻蟠桃曳紫裾。',32,'全唐诗/poet.song.208000.json','["諶旴二母畢從姑，各獻蟠桃曳紫裾。", "共把我公游詠處，從頭善頌滿階除。"]'),
('3dac00df-d32d-4656-9501-4e10c09d7247','上余倅生辰唐律十章  其五','唐士恥','宋','宋诗','song-poetry','','[]','牢盤白雪是丹媒，解活民生富國財。',32,'全唐诗/poet.song.208000.json','["牢盤白雪是丹媒，解活民生富國財。", "巨浸無邊歸掌握，共知陰德鼎方來。"]'),
('63bac11f-c9a6-4ce6-b61c-1365586be9c6','上余倅生辰唐律十章  其六','唐士恥','宋','宋诗','song-poetry','','[]','惠山山下有名泉，少煮鎗旗兩腋便。',32,'全唐诗/poet.song.208000.json','["惠山山下有名泉，少煮鎗旗兩腋便。", "不是圜扉足公暇，誰能祛睡一盃煎。"]'),
('885b30d1-89cc-4e08-bf21-306212f91b54','上余倅生辰唐律十章  其七','唐士恥','宋','宋诗','song-poetry','','[]','瀕淮土厚樂何窮，近接升平昔日風。',32,'全唐诗/poet.song.208000.json','["瀕淮土厚樂何窮，近接升平昔日風。", "更得于公來郡掾，自然囹圄致頻空。"]'),
('450560f9-7be7-4244-8c32-5f5477d7e1c4','上余倅生辰唐律十章  其八','唐士恥','宋','宋诗','song-poetry','','[]','大漢鍾官周府圜，賓寮入幕地行仙。',32,'全唐诗/poet.song.208000.json','["大漢鍾官周府圜，賓寮入幕地行仙。", "人心天意俱從我，何慮不如劉晏錢。"]'),
('68c45a85-b4eb-4d5b-96b2-0b6a6867c373','上余倅生辰唐律十章  其九','唐士恥','宋','宋诗','song-poetry','','[]','閩嶺西來只一山，歡聲百里想當年。',32,'全唐诗/poet.song.208000.json','["閩嶺西來只一山，歡聲百里想當年。", "今逢行客應須說，好在甘棠影正圓。"]'),
('81797329-6726-4f71-b772-51b911da95e8','上余倅生辰唐律十章  其一○','唐士恥','宋','宋诗','song-poetry','','[]','亭亭采棒足流傳，太末官勳壓此年。',32,'全唐诗/poet.song.208000.json','["亭亭采棒足流傳，太末官勳壓此年。", "感德銜恩知有自，定應亦致爛柯僊。"]'),
('f688fc3d-e6e5-4861-9c2e-f9184d0a3dab','笋乾','唐士恥','宋','宋诗','song-poetry','','[]','此君風味殊不薄，莫笑當年煮簀人。',32,'全唐诗/poet.song.208000.json','["此君風味殊不薄，莫笑當年煮簀人。", "坐使普寧增譜字，遥知端是壓前新。"]'),
('7c409ca5-c3ca-4ef6-8185-7fddf267d8c3','毛文子遣贈萼綠華','唐士恥','宋','宋诗','song-poetry','','[]','飛仙姑射不通塵，更倚晴空瑟瑟雲。',32,'全唐诗/poet.song.208000.json','["飛仙姑射不通塵，更倚晴空瑟瑟雲。", "從此櫻唇倍尋俗，唯須么鳳粲成羣。"]'),
('9d01584b-f46b-4d2b-af15-db547d85343f','贈浩然觀胡道士','唐士恥','宋','宋诗','song-poetry','','[]','只爲丹霄足羽軿，且將奇法驗人寰。',32,'全唐诗/poet.song.208000.json','["只爲丹霄足羽軿，且將奇法驗人寰。", "從他血肉并煙火，自有仙家九轉丹。"]'),
('d09d3a96-8f1f-4efd-9d72-1d485fad2433','比目','唐士恥','宋','宋诗','song-poetry','','[]','夷吾深旨人須識，解使封山意不行。',32,'全唐诗/poet.song.208000.json','["夷吾深旨人須識，解使封山意不行。", "當日魚鹽如靡密，已無林放小關情。"]'),
('0d4c8d6d-6e47-46ae-9a25-f21d8deb1eda','失題','唐士恥','宋','宋诗','song-poetry','','[]','老仙絕鮮尋常外，一笑閩川綠荔枝。',32,'全唐诗/poet.song.208000.json','["老仙絕鮮尋常外，一笑閩川綠荔枝。", "坐斷世間滋味徹，阿誰翻欲語凡飴。"]'),
('e818082e-dd22-430e-9972-f88f37644802','有懷','詹初','宋','宋诗','song-poetry','','[]','閒居忽有懷，悵然令心恫。',84,'全唐诗/poet.song.208000.json','["閒居忽有懷，悵然令心恫。", "世人尚浮沉，君子難苟同。", "是以蓋世賢，飄然返山中。", "棲遲竹林下，明道善其躬。", "如何彼之子，居常起波風。", "屈原泣澤畔，仲尼悲道窮。", "賢聖尚如此，吾身那可容。"]'),
('ef5d8566-a9d8-4a0e-8124-a33f93d57d75','春日','詹初','宋','宋诗','song-poetry','','[]','白雲冉冉度南園，綠柳明花處處然。',32,'全唐诗/poet.song.209000.json','["白雲冉冉度南園，綠柳明花處處然。", "雲物無心心自適，優游無我我忘年。"]'),
('1c43ffe4-e43e-4f38-807c-3f478e95414c','新春','詹初','宋','宋诗','song-poetry','','[]','歲月新更又一春，迎春還是舊年人。',32,'全唐诗/poet.song.209000.json','["歲月新更又一春，迎春還是舊年人。", "願除舊妄生新意，端與新年日日新。"]'),
('86616bef-eb68-4125-93fc-09c97634ba16','秋至','詹初','宋','宋诗','song-poetry','','[]','方趁夏日永，不知秋已清。',24,'全唐诗/poet.song.209000.json','["方趁夏日永，不知秋已清。", "秋清歲即晚，吾道終何成。"]'),
('0b2f4955-d209-4f28-8298-7c65ab403e0b','訓子','詹初','宋','宋诗','song-poetry','','[]','呼爾羣兒，示爾兒知。',120,'全唐诗/poet.song.209000.json','["呼爾羣兒，示爾兒知。", "儉則本立，學則智資。", "時逐勿逐，古聖是規。", "守道安貧，我所慕思。", "競勢趨豪，我心實悲。", "毋謂放巧，毋謂謹癡。", "毋謂惡小，乃以自欺。", "毋謂善小，棄而不爲。", "爲善去惡，奮志乘時。", "少壯不力，老大何追。", "爾父雖昧，所言則宜。", "永以爲訓，無爲我遺。"]'),
('f0dc80ab-7fb5-4a01-a968-767b337582a6','求心齋','詹初','宋','宋诗','song-poetry','','[]','生生天地心，吾人秉其真。',120,'全唐诗/poet.song.209000.json','["生生天地心，吾人秉其真。", "虛靈無一物，純然惟元仁。", "如何彼放失，物欲共沉淪。", "客感乃爲主，本主翳埃塵。", "鑒此去物欲，而求我真純。", "求之真即見，端然還在身。", "祗恐物與欲，乘間復來侵。", "念茲心益奮，日夜終惟寅。", "戒懼與謹獨，式用存吾神。", "于焉生生意，始與天地倫。"]'),
('97d86ffa-3dad-45da-94fd-ca53bbfb1c85','有感','詹初','宋','宋诗','song-poetry','','[]','世道已趨末，人心覺更殊。',120,'全唐诗/poet.song.209000.json','["世道已趨末，人心覺更殊。", "逐逐在勢利，權勢競吹噓。", "忠言翻爲怨，成風在諂諛。", "諂諛勢立至，勢去還躊躇。", "小人誇得志，君子思歸歟。", "不忍同世濁，深山高結廬。", "閉門守吾拙，勢利安可居。", "勢利一時榮，時過禍反予。", "不如守貧賤，履道常坦如。", "所以介然志，三公不易諸。"]'),
('024630ae-c764-4e1d-8f1f-deb1de1e9ddd','聞杵','詹初','宋','宋诗','song-poetry','','[]','靜夜無人語，何處送杵聲。',48,'全唐诗/poet.song.209000.json','["靜夜無人語，何處送杵聲。", "米以杵而出，杵以多而精。", "小事尚如此，况於吾性成。", "所以古聖賢，寢食不遑寧。"]'),
('36ea1913-5134-430c-b1dc-26a4d29f2ce8','讀李敬業傳','詹初','宋','宋诗','song-poetry','','[]','閒笑唐明主，深憐李勣忠。',48,'全唐诗/poet.song.209000.json','["閒笑唐明主，深憐李勣忠。", "如何一諂獻，便使百年恫。", "武后興唐亂，英公奮義戎。", "那知成禍者，禍慘亦歸躬。"]'),
('0f1a754f-8a9f-4e61-a99e-ce496ac251f6','惜日','詹初','宋','宋诗','song-poetry','','[]','吾聞古君子，發憤競分陰。',48,'全唐诗/poet.song.209000.json','["吾聞古君子，發憤競分陰。", "漫以一朝逸，終辜百歲心。", "嫌秋晝短入，愛夏刻長臨。", "三省吾身過，專誠學子參。"]'),
('4c58520c-ec7b-4526-8848-28bc9f6f0b70','窗樹','詹初','宋','宋诗','song-poetry','','[]','雨過窗前樹，天然生意新。',48,'全唐诗/poet.song.209000.json','["雨過窗前樹，天然生意新。", "枝條枯昨日，萌蘗長今晨。", "根本原無改，濡滋自有神。", "靜看微物理，應識養心真。"]'),
('fc23eca4-1431-40de-a6f0-0e5f683e2062','書懷  其一','詹初','宋','宋诗','song-poetry','','[]','小谿流水自悠悠，策杖南林入早秋。',32,'全唐诗/poet.song.209000.json','["小谿流水自悠悠，策杖南林入早秋。", "隨地人生俱可樂，浮雲富貴復何求。"]'),
('b381b2a8-6d65-44a2-8176-9571aae2b9b2','書懷  其二','詹初','宋','宋诗','song-poetry','','[]','獨坐終日閉寒廬，回首生年五十初。',32,'全唐诗/poet.song.209000.json','["獨坐終日閉寒廬，回首生年五十初。", "歲月不知垂老至，惟從憤樂自如如。"]'),
('605321c0-b304-43c2-bf89-c661817b82e2','偶成','詹初','宋','宋诗','song-poetry','','[]','何須身外更求榮，榮在吾身爾自輕。',32,'全唐诗/poet.song.209000.json','["何須身外更求榮，榮在吾身爾自輕。", "但得仁榮真尊爵，榮華世上總虛名。"]'),
('43e97097-2589-4427-9d6a-ba7e6213425f','桃花','詹初','宋','宋诗','song-poetry','','[]','桃花灼灼鬭春芳，一見如雲滿目光。',32,'全唐诗/poet.song.209000.json','["桃花灼灼鬭春芳，一見如雲滿目光。", "不識冬來霜雪徧，芳意爭似竹松長。"]'),
('59479169-f862-46f5-907b-274465bb5ca9','梅','詹初','宋','宋诗','song-poetry','','[]','萬木枯歲晚，寒梅獨不移。',24,'全唐诗/poet.song.209000.json','["萬木枯歲晚，寒梅獨不移。", "幽香對白雪，清景月明時。"]'),
('abb53a1c-dd98-472b-86c0-0b43858e2a1d','心如穀種','詹初','宋','宋诗','song-poetry','','[]','人心如穀種，生生本無時。',48,'全唐诗/poet.song.209000.json','["人心如穀種，生生本無時。", "雖然有生意，培養貴自知。", "不耘誠爲昧，揠苗良可悲。", "戒病復有事，苗秀實可期。"]'),
('ee47bada-43e2-4f15-b0e4-34f1e97022e7','鑿流塘二首  其一','詹初','宋','宋诗','song-poetry','','[]','門前鑿三塘，流水常不息。',24,'全唐诗/poet.song.209000.json','["門前鑿三塘，流水常不息。", "逝者誠如斯，間斷伊誰忒。"]'),
('e5e6f163-6414-4c25-9edf-bd3fe9b6e128','鑿流塘二首  其二','詹初','宋','宋诗','song-poetry','','[]','舊爲沙泥場，今爲流水域。',72,'全唐诗/poet.song.209000.json','["舊爲沙泥場，今爲流水域。", "混混固有源，開導吾爲德。", "人心凝物欲，已有猶當克。", "已去心源澄，活潑自無塞。", "萬彙當其前，水鑒真明極。", "徘徊此塘濱，永爲立心則。"]'),
('58b9315d-9fd8-49ec-b0a2-8733f208f5c0','田居','詹初','宋','宋诗','song-poetry','','[]','南開數畝田，妻子共鋤耕。',48,'全唐诗/poet.song.209000.json','["南開數畝田，妻子共鋤耕。", "比歲頗豐稔，仰天歌治弘。", "憂貧本匪念，忘物自怡情。", "遥憶執輿者，問津來上平。"]'),
('65e1a966-04b7-4589-96b3-268e09769951','登聖山','詹初','宋','宋诗','song-poetry','','[]','摳衣上聖山，徘徊四望通。',72,'全唐诗/poet.song.209000.json','["摳衣上聖山，徘徊四望通。", "下視小區邑，上視高蒼穹。", "小者吾誠高，高者吾何從。", "渾渾道無極，求之不可窮。", "而欲窮其際，亦曰執一中。", "一中苟在斯，卑高大小同。"]'),
('3890d948-f6e9-4911-af48-f89d8ae71104','理氣','詹初','宋','宋诗','song-poetry','','[]','理本無象，氣爲有形。',50,'全唐诗/poet.song.209000.json','["理本無象，氣爲有形。", "氣爲理載，理以氣乘。", "匪理氣粗，匪氣理冥。", "氣以理神，理以氣弘。", "二者相須，其道分明。"]'),
('5e159700-8136-4698-ae17-cd909f4ff542','月  其一','詹初','宋','宋诗','song-poetry','','[]','天上一輪影萬輪，一輪方是月明真。',32,'全唐诗/poet.song.209000.json','["天上一輪影萬輪，一輪方是月明真。", "祗尋天上一輪月，水裏萬千何足論。"]'),
('26f5269b-eb18-4413-9221-9455eb95c03b','月  其二','詹初','宋','宋诗','song-poetry','','[]','水中月影還是影，天上一真影萬川。',32,'全唐诗/poet.song.209000.json','["水中月影還是影，天上一真影萬川。", "水裏月影人共識，一真誰復見先天。"]'),
('3f0bf31c-bbfc-45d4-9e05-dcd7506d95cd','新荷','詹初','宋','宋诗','song-poetry','','[]','青荷小小初凌水，梗直中虛不著塵。',32,'全唐诗/poet.song.209000.json','["青荷小小初凌水，梗直中虛不著塵。", "爲道人心本然處，直虛原與物爲同。"]'),
('f9fe06a9-a13b-4757-8092-76669c5db5c8','寒松草閣','詹初','宋','宋诗','song-poetry','','[]','數椽草閣構新成，四面蒼松入戶清。',32,'全唐诗/poet.song.209000.json','["數椽草閣構新成，四面蒼松入戶清。", "霜雪須教長不改，後凋端與爾爲盟。"]'),
('c95f5287-afa6-43d5-bcbf-dbfe4f43462a','讀易','詹初','宋','宋诗','song-poetry','','[]','先天本無言，有言即後天。',24,'全唐诗/poet.song.209000.json','["先天本無言，有言即後天。", "欲知先天易，須在無言前。"]'),
('9c7fd059-963c-49e5-a96a-4c0c57b076ba','聞胡人入寇','詹初','宋','宋诗','song-poetry','','[]','老來不忍聞征戰，征戰偏從老歲聞。',32,'全唐诗/poet.song.209000.json','["老來不忍聞征戰，征戰偏從老歲聞。", "靜裏追思生亂者，令人無語對斜曛。"]'),
('b99c9ce0-7814-4e50-983e-2e62aca7f17b','出心原','詹初','宋','宋诗','song-poetry','','[]','行行涉南原，遥望北山岑。',108,'全唐诗/poet.song.209000.json','["行行涉南原，遥望北山岑。", "上有千尺崖，下有高樹林。", "高林轉幽隩，戛然啼雙禽。", "流水自迅逝，白雲澹無心。", "策杖者誰子，閒來坐春陰。", "相逢擇林下，携手谿水濱。", "對之兩無言，悠然鳴素琴。", "素琴清且越，暢以披沖襟。", "沖襟良自爾，那知春已深。"]'),
('fd7e1093-9248-43fa-980b-ba43869396ad','中道','詹初','宋','宋诗','song-poetry','','[]','聖賢自古執其中，允執此中萬理通。',32,'全唐诗/poet.song.209000.json','["聖賢自古執其中，允執此中萬理通。", "萬理由來心自得，心同方是理大同。"]'),
('68d0f316-e39d-4595-87d8-7902122c1d0f','聞鶑','詹初','宋','宋诗','song-poetry','','[]','忽爾聞鶑語，語巧真如簧。',60,'全唐诗/poet.song.209000.json','["忽爾聞鶑語，語巧真如簧。", "呼童逐之去，不使鳴我傍。", "語巧是非亂，語拙道吾常。", "守道由拙得，不仁爲巧亡。", "吾寧道吾拙，翻爲巧者傷。"]'),
('0e679f01-bcf5-4fb3-bc6e-1b622bae12d5','題岱山水雲幽居','詹初','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','幽居避俗氛，世事那復聞。',48,'全唐诗/poet.song.209000.json','["幽居避俗氛，世事那復聞。", "閒浴池塘水，靜看山嶺雲。", "雲自無心出，水從有本分。", "水雲真自得，吾與爾爲羣。"]'),
('6355b59e-6f89-4d8d-9bc7-44a32c4c398e','寄柳塘汪叔畊三首  其一','詹初','宋','宋诗','song-poetry','','[]','不聞爾言久，因覺我言非。',24,'全唐诗/poet.song.209000.json','["不聞爾言久，因覺我言非。", "欲得爾之善，真期爾指歸。"]'),
('beeeb203-53fe-4193-980e-4ed1b1a361c0','寄柳塘汪叔畊三首  其二','詹初','宋','宋诗','song-poetry','','[]','久未從君行，出門無可去。',24,'全唐诗/poet.song.209000.json','["久未從君行，出門無可去。", "思爾行之善，秉燭坐至曙。"]'),
('d9568360-d72b-4377-9d97-ee8fea5b9d1b','寄柳塘汪叔畊三首  其三','詹初','宋','宋诗','song-poetry','','[]','數月未論心，此心覺還真。',24,'全唐诗/poet.song.209000.json','["數月未論心，此心覺還真。", "矢以惺惺法，始終奉此身。"]'),
('71f2a5bb-06bf-499b-bd15-c42365bc4907','歸田','詹初','宋','宋诗','song-poetry','','[]','歸田漫云苦，田野樂有餘。',48,'全唐诗/poet.song.209000.json','["歸田漫云苦，田野樂有餘。", "忙去一犂黍，閒來萬卷書。", "食贍忘帝力，理見識心虛。", "隨地平生意，從今可自如。"]'),
('59eead9c-248f-40cf-972b-60bba2e5591a','奉寄體仁宗叔一首','詹初','宋','宋诗','song-poetry','','[]','一從示至教，日覺舊行非。',48,'全唐诗/poet.song.209000.json','["一從示至教，日覺舊行非。", "但恨範模遠，終爲物欲欺。", "有知無取正，積惑總成疑。", "獨有依歸念，端然未改移。"]'),
('7e710397-d01c-4e90-9046-75574f6d5a8b','漫興','詹初','宋','宋诗','song-poetry','','[]','秋風獨坐野塘前，水上遊鱼自有天。',32,'全唐诗/poet.song.209000.json','["秋風獨坐野塘前，水上遊鱼自有天。", "真意更須何處覓，知音從古在無絃。"]'),
('2086313f-16d7-4ad4-a24b-40fab299bd69','春歸','詹初','宋','宋诗','song-poetry','','[]','生意無端綠滿枝，閉門高卧日遲遲。',32,'全唐诗/poet.song.209000.json','["生意無端綠滿枝，閉門高卧日遲遲。", "一編周易年年把，門外春歸總不知。"]'),
('cdb170fe-ad83-4637-8944-3d8336c29456','題程棲竹居士卷','詹初','宋','宋诗','song-poetry','','[]','此翁日日對脩竹，竹上風清心亦清。',64,'全唐诗/poet.song.209000.json','["此翁日日對脩竹，竹上風清心亦清。", "高節有常原自勁，中虛無物本來成。", "美淇君子詩爲咏，貫歲聖人禮作盟。", "林裏七賢真浪跡，憐君不慕七賢名。"]'),
('a6d24c99-c0ba-4851-a924-85d64565800f','雲掩月  其一','詹初','宋','宋诗','song-poetry','','[]','遊雲紛擾混太清，蒼茫萬里晦月明。',146,'全唐诗/poet.song.209000.json','["遊雲紛擾混太清，蒼茫萬里晦月明。", "豈是貞明能爲改，却緣外面縱且橫。", "縱橫雲靄盡能撥，一輪即見當天發。", "當天皎皎月照人，今古何曾人照月。", "千江萬江月盡圓，千人萬人誰知焉。", "李白江頭捉月死，盡笑李白醉而顛。", "江中那有月可捉，舉首獨立空茫然。", "空茫然，月在天，古來祗有一心傳。", "休教心外便便言，當時豈啻李白醉江邊。"]'),
('3b39cc2a-e941-4cc6-a087-715b94ae7bbc','雲掩月  其二','詹初','宋','宋诗','song-poetry','','[]','心如明月物如雲，心放應爲物所分。',32,'全唐诗/poet.song.209000.json','["心如明月物如雲，心放應爲物所分。", "欲反此心須去物，原來還自在天君。"]'),
('d8377826-c337-4071-989e-5ab7157fc464','沐浴  其一','詹初','宋','宋诗','song-poetry','','[]','暮春河水暖春暉，浴罷悠悠自坐磯。',32,'全唐诗/poet.song.209000.json','["暮春河水暖春暉，浴罷悠悠自坐磯。", "弄柳乘風興未盡，高歌一曲日西歸。"]'),
('b8dda058-b0af-45e8-ac75-7203b62317c3','沐浴  其二','詹初','宋','宋诗','song-poetry','','[]','閒浴谿頭靜自居，此身已濯心何如。',32,'全唐诗/poet.song.209000.json','["閒浴谿頭靜自居，此身已濯心何如。", "此心欲濯靜中去，靜定由來物自除。"]'),
('0443dddb-cdab-4150-a60e-6923cef46cad','感嘆','詹初','宋','宋诗','song-poetry','','[]','歲月蹉跎六十乘，嗟予德業竟何能。',64,'全唐诗/poet.song.209000.json','["歲月蹉跎六十乘，嗟予德業竟何能。", "善無一得過恒有，力盡千般志尚弘。", "學易一編終法孔，反身三省死如曾。", "漫嘲吾老成衰朽，定舉全仁重任勝。"]'),
('a7db5462-b731-4339-b4f5-6ee709ac548d','寄黄直卿','詹初','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶昔年猶壯，廬山侍讀書。',48,'全唐诗/poet.song.209000.json','["憶昔年猶壯，廬山侍讀書。", "叨爲三友末，相隔廿年餘。", "君道多朋合，余非獨索居。", "緣茲君日益，余昧愈成愚。"]'),
('957bcc7c-9bbb-4011-ad75-404a302b9e69','觀春','詹初','宋','宋诗','song-poetry','','[]','萬木春來花滿枝，忽來忽去迭無時。',32,'全唐诗/poet.song.209000.json','["萬木春來花滿枝，忽來忽去迭無時。", "此中還有此中意，說向傍人人不知。"]'),
('3c145066-5be4-4126-9905-ed31d06bdddf','書白樂天琵琶行後','詹初','宋','宋诗','song-poetry','','[]','潯陽夜泊送客船，船上誰人白樂天。',56,'全唐诗/poet.song.209000.json','["潯陽夜泊送客船，船上誰人白樂天。", "坐聞一曲琵琶奏，青衫何用涕泗漣。", "豈知通窮良有命，君子當之無怨焉，虛使歌行世上傳。"]'),
('bb3b2d7a-2e38-44b5-9c56-12ca6770b464','松竹','詹初','宋','宋诗','song-poetry','','[]','青翠春來未見奇，麗紅正是夭夭時。',32,'全唐诗/poet.song.209000.json','["青翠春來未見奇，麗紅正是夭夭時。", "霜寒十月花開盡，祗有松筠秀舊枝。"]'),
('e9fa217f-26cf-4af9-b82a-d481599056ae','夾漈草堂','鄭寅','宋','宋诗','song-poetry','','[]','地隔一區石，山高兩漈深。',48,'全唐诗/poet.song.209000.json','["地隔一區石，山高兩漈深。", "弓旌已陳迹，泉石高餘音。", "若不登茲境，何由見古心。", "遺編湮沒久，思與共追尋。"]'),
('537b31fe-e732-4a00-9285-7344e4052390','連州大雲洞','劉燧叔','宋','宋诗','song-poetry','','[]','試携杖屨作山行，一夜秋風桂子生。',64,'全唐诗/poet.song.209000.json','["試携杖屨作山行，一夜秋風桂子生。", "犀曳千章稠黛綠，鵝兼萬點簇雲英。", "長哦賓客珠璣句，敬仰濂溪日月名。", "我亦黄塵吹鬢者，頻來心跡覺雙清。"]'),
('9b6a673e-dc9d-4787-8992-2fcefb789074','上陳招使','劉煒叔','宋','宋诗','song-poetry','','[]','天戈一指迅雷轟，涌雪公應記洗兵。',64,'全唐诗/poet.song.209000.json','["天戈一指迅雷轟，涌雪公應記洗兵。", "伊洛風烟想如舊，江淮草木轉知名。", "爭先識面今裴度，孰與論心昔孔明。", "文水萬家惟擊壤，得無軍餉盡歸耕。"]'),
('375d2eca-8b15-44a6-bbd3-7bc38a43def9','別朱子大蘇名叟','趙汝唫','宋','宋诗','song-poetry','','[]','薄宦塵埃易滿襟，問盟猶喜盍朋簪。',64,'全唐诗/poet.song.209000.json','["薄宦塵埃易滿襟，問盟猶喜盍朋簪。", "只今風月一杯酒，他日雲山千里心。", "楊柳陰疎秋館靜，芙蓉香冷暮江深。", "潮回一信西興渡，爲寄相思別後吟。"]'),
('d4247ac4-01f1-488a-8fb4-6fc3d9937399','送梅窗兄','趙汝唫','宋','宋诗','song-poetry','','[]','離歌休再疊，我亦不堪聞。',48,'全唐诗/poet.song.209000.json','["離歌休再疊，我亦不堪聞。", "山接詩愁去，雲隨別袂分。", "官閒寧問祿，命薄謾能文。", "悵望梅邊屋，花開更憶君。"]'),
('4987a04b-f846-4c2b-8fe7-c217a433ac09','棲真洞','趙汝唫','宋','宋诗','song-poetry','','[]','幅巾灑松露，雙袖抖衣塵。',48,'全唐诗/poet.song.209000.json','["幅巾灑松露，雙袖抖衣塵。", "可耐人間暑，來尋洞裏春。", "座分雲骨冷，屐隠甃紋新。", "鶴近清尊舞，如留欲去賓。"]'),
('d4461a35-7f26-4016-97bd-6b5d6eae22f5','遊洞霄  其一','趙汝唫','宋','宋诗','song-poetry','','[]','細雨吹凉客袂分，青燈夢短苦思君。',32,'全唐诗/poet.song.209000.json','["細雨吹凉客袂分，青燈夢短苦思君。", "洞仙應快登臨眼，盡向山邊掃白雲。"]'),
('9c577ace-65de-4c32-af87-44d1ff1851b7','遊洞霄  其二','趙汝唫','宋','宋诗','song-poetry','','[]','九鎖扃仙窟，棲真隔茂林。',48,'全唐诗/poet.song.209000.json','["九鎖扃仙窟，棲真隔茂林。", "地靈泉石祕，巖古薜蘿侵。", "屐踐東山勝，樽傾北海深。", "主人娛客興，喚起玉龍吟。"]'),
('5f7963b7-a6f0-4221-8283-701aaccd3842','遊洞霄  其三','趙汝唫','宋','宋诗','song-poetry','','[]','昨日始騎馿，今朝共跨魚。',48,'全唐诗/poet.song.209000.json','["昨日始騎馿，今朝共跨魚。", "一官塵坎壈，三逕木扶疎。", "童返還知白，身輕繼寢虛。", "道傳傳便得，元乏枕中書。"]'),
('748de207-af00-461a-8de2-797fb08cad07','山','趙汝唫','宋','宋诗','song-poetry','','[]','茅屋初寒夜，衾裯整未成。',48,'全唐诗/poet.song.209000.json','["茅屋初寒夜，衾裯整未成。", "烹泉沙鼎快，讀易紙窗明。", "菊上霜偏力，梅邊日最清。", "孤吟誰與和，落葉上階鳴。"]'),
('0de5605f-0179-4b4f-8129-27c43c6a0f27','朝山','趙汝唫','宋','宋诗','song-poetry','','[]','犬入五雲音信絕，鳳樓凝碧悄無聲。',32,'全唐诗/poet.song.209000.json','["犬入五雲音信絕，鳳樓凝碧悄無聲。", "焚香古洞步虛夜，露濕松花空月明。"]'),
('1345c43a-7c1e-4629-97e9-a84ddaeb022c','居苦','趙汝唫','宋','宋诗','song-poetry','','[]','去郭近一里，結茅纔數間。',48,'全唐诗/poet.song.209000.json','["去郭近一里，結茅纔數間。", "紅塵飛不到，幽事頗相關。", "鑿石分流水，移松補斷山。", "棲禽忙似我，日落未知還。"]'),
('e1bda9cd-5b5f-4d7c-8495-5fddad36248c','存目','趙汝唫','宋','宋诗','song-poetry','','[]','詩題：離越首句：東關寒水深。',14,'全唐诗/poet.song.209000.json','["詩題：離越首句：東關寒水深。"]'),
('cf130da4-1af2-4969-8bd0-d0f354f7444d','寄題四明張氏南園','魏汝賢','宋','宋诗','song-poetry','','[]','修篁曲折繞牆東，風景輞川孰與同。',64,'全唐诗/poet.song.209000.json','["修篁曲折繞牆東，風景輞川孰與同。", "過雨凉生千樹外，亂山青入一樓中。", "高人爾日聯吟社，逐客當年作寓公。", "別後新詩又多少，雙魚應許寄郵筒。"]'),
('3f79203f-0da0-4b65-a891-2d8ca42264c4','題淵明愛菊圖','吳梅卿','宋','宋诗','song-poetry','','[]','秋菊由來美，願言愛者誰。',48,'全唐诗/poet.song.209000.json','["秋菊由來美，願言愛者誰。", "聞道陶彭澤，嗜彼獨孜孜。", "嗟嗟兮秋菊，何入淵明思。", "我今忽解得，不肯告人知。"]'),
('4d815f11-8720-46af-bc9b-100afac4f9c2','游金精山','黄昇','宋','宋诗','song-poetry','','[]','曳履江城北，逍遥訪仙鄉。',120,'全唐诗/poet.song.209000.json','["曳履江城北，逍遥訪仙鄉。", "掃却千里恨，愛此六月凉。", "雲根埋宿雨，木末酣斜陽。", "峭崖列巖竇，老樹攀穹蒼。", "地坼三關暗，天開一隙光。", "青霄麗太白，應此金之芒。", "雙桃幾日熟，冷笑癡吳王。", "洞開人已去，剛風舞霓裳。", "仙凡本相近，此理自可量。", "學詩未學仙，凡骨生慚惶。"]'),
('bf34278f-84f1-44ae-b0fa-4afd6b34d7c4','鳴雞行','時少章','宋','宋诗','song-poetry','','[]','三里寥落秋夜長，老雞望星初引吭。',144,'全唐诗/poet.song.209000.json','["三里寥落秋夜長，老雞望星初引吭。", "一聲二聲天沆漭，客夢初回猶惚恍。", "三聲四聲天漸明，道上行人馬蹄響。", "嗟爾行人人有心，心長面短誰能尋。", "薛君脫走窘思慮，劉牧起舞豪精神。", "勿言咿喔纔滿座，中有歎悲千萬箇。", "君知種種在此雞，只合雞聲塞天破。", "吳中老翁百不忙，殺雞釀酒酬年光。", "黄紬輭暖蒲薦穩，日出三竿猶在牀。"]'),
('3cb14250-8aea-45fa-b7ea-098a0fc48fee','書事七首  其一','時少章','宋','宋诗','song-poetry','','[]','諸將紛然各自雄，面前全隔馬牛風。',32,'全唐诗/poet.song.209000.json','["諸將紛然各自雄，面前全隔馬牛風。", "尚衣已辦通天带，何日臨門送晉公。"]'),
('b9664304-3e5b-4529-9253-07747784aec6','書事七首  其二','時少章','宋','宋诗','song-poetry','','[]','共說曾公有府城，殿前數日浄邊塵。',32,'全唐诗/poet.song.209000.json','["共說曾公有府城，殿前數日浄邊塵。", "白麻宣受人爭看，寶馬高秋報主身。"]'),
('533a87c1-c202-4b91-9722-70a1183d3d00','書事七首  其三','時少章','宋','宋诗','song-poetry','','[]','特地今年荷主恩，儲胥百萬給諸屯。',32,'全唐诗/poet.song.209000.json','["特地今年荷主恩，儲胥百萬給諸屯。", "張彝自向河南死，懷朔驚翻賀六渾。"]'),
('ce50011f-d6aa-4c8c-9ef9-e13ef9b1d397','書事七首  其四','時少章','宋','宋诗','song-poetry','','[]','莫爲蒲騷舉高趾，邊情轉眼又千迴。',32,'全唐诗/poet.song.209000.json','["莫爲蒲騷舉高趾，邊情轉眼又千迴。", "吳房小敗寧非計，防後飛軍雪裏來。"]'),
('ce431424-bb3f-4534-9d4b-a155a6cdca06','書事七首  其五','時少章','宋','宋诗','song-poetry','','[]','高帝神靈未可誣，至今陵柏尚扶疎。',32,'全唐诗/poet.song.209000.json','["高帝神靈未可誣，至今陵柏尚扶疎。", "小臣眼有一石淚，準擬北來都破除。"]'),
('f7bdef25-d732-4a67-a12d-151d7fcf33bc','書事七首  其六','時少章','宋','宋诗','song-poetry','','[]','北引黄河入宿河，下栽鹿角起層波。',32,'全唐诗/poet.song.209000.json','["北引黄河入宿河，下栽鹿角起層波。", "城中待哺一萬戶，咫尺南船那得過。"]'),
('9c622d16-1949-42e9-86ce-a7c61cc7671a','書事七首  其七','時少章','宋','宋诗','song-poetry','','[]','瑪瑙遺基尚未斜，兩京風物使人嗟。',32,'全唐诗/poet.song.209000.json','["瑪瑙遺基尚未斜，兩京風物使人嗟。", "先皇月出曾遊歷，空見春風發落花。"]'),
('1224ca92-8054-4dea-87d5-c4d0a4a2f983','題園門','時少章','宋','宋诗','song-poetry','','[]','林花落處憶初妍，半折妖紅似隔年。',32,'全唐诗/poet.song.209000.json','["林花落處憶初妍，半折妖紅似隔年。", "今日綠陰還漲眼，却思花落又茫然。"]'),
('1228aee9-b13d-412b-89f7-60393b2ae12a','大節堂碑引','時少章','宋','宋诗','song-poetry','','[]','天降疢疾殄我民，鴟鶹奮怒豺虎獰。',256,'全唐诗/poet.song.209000.json','["天降疢疾殄我民，鴟鶹奮怒豺虎獰。", "掩道赤鴉蔽陽精，夜羅鬼火塞要津。", "當塗大吏腰纏金，撓膕稽顙泪滿膺。", "嗢咿軟語若稚嬰，欺賣宗祏傾皇靈。", "有勇三子心稜稜，扳弧援甲憑孤城。", "城頺兵折氣益振，目光如炬鑠成羣。", "或從辟雍曳長紳，欲拄八極遮帝輧。", "有偉三子辭轟轟，危立高駡聲吐霆。", "頸血濺天天爲昏，斷屍峙立不仆傾。", "神扶鬼挾赫可驚，坐朝不與燕不賓。", "寸武不踏黄金屏，性忠內發孰使令。", "英氣挺挺曠古今，朅來柯山訪厥孫。", "彷彿毅狀衝杳冥，築堂泮宇夐深明。", "悲風苦雨凄棘林，魂兮來歸肅泠泠。", "寥哉曠宇疇非臣，登茲堂兮企風神。", "鬚毛磔立心膽森，勿俾三子專修名。"]'),
('3ff3d3ed-c28f-4176-8189-d9124cc0adf7','過玉林','魏慶之','宋','宋诗','song-poetry','','[]','一步離家是出塵，幾重山色幾重雲。',32,'全唐诗/poet.song.209000.json','["一步離家是出塵，幾重山色幾重雲。", "沙溪清淺橋邊路，折得梅花又見君。"]'),
('cb34a8a4-18b2-472a-941f-c9e76e3c0a8a','答玉林示','魏慶之','宋','宋诗','song-poetry','','[]','一吟一咏一相思，滿紙銀鈎滿紙詩。',64,'全唐诗/poet.song.209000.json','["一吟一咏一相思，滿紙銀鈎滿紙詩。", "深院沈沈人悄悄，落花片片雨垂垂。", "蹉跎二月還三月，點檢新枝□□□。", "愁絕問春春不語，見君何地會何時。"]'),
('9a53bc8b-db84-4ed1-9758-31e518eba132','題張敬仲寒巖瀑泉','魏慶之','宋','宋诗','song-poetry','','[]','朱絃莫余和，落指空琅然。',24,'全唐诗/poet.song.209000.json','["朱絃莫余和，落指空琅然。", "天風遠送將，去作碧巖泉。"]'),
('6dcaac7c-6952-4826-9eed-ed446357bf2c','偶題','魏慶之','宋','宋诗','song-poetry','','[]','庭夜酣紅杏，牆陰染碧苔。',24,'全唐诗/poet.song.209000.json','["庭夜酣紅杏，牆陰染碧苔。", "吟翁醉未醒，啼鳥去還來。"]'),
('a135ad0a-cb33-4ca9-afde-01f55ed65e74','句','魏慶之','宋','宋诗','song-poetry','','[]','今宵方對月，何日結忘年。',12,'全唐诗/poet.song.209000.json','["今宵方對月，何日結忘年。"]'),
('fcd9efde-7747-4441-83bf-fdeadd28f66d','句','宋詡','宋','宋诗','song-poetry','','[]','未得草茅封下事，少從桃李徑中行。',16,'全唐诗/poet.song.209000.json','["未得草茅封下事，少從桃李徑中行。"]'),
('5738a3cc-2a5a-4d74-bb8b-ede940d337c8','遊永福方廣巖','吳錡','宋','宋诗','song-poetry','','[]','曾訪神仙巖洞來，人言偉觀似天台。',64,'全唐诗/poet.song.209000.json','["曾訪神仙巖洞來，人言偉觀似天台。", "藤蘿足下猨猱嘯，鐘鼓聲邊日月開。", "燈續佛光凝紫翠，雲將蜃氣作樓臺。", "最憐貫石神龍尾，猶带天東雨露回。"]'),
('71aed111-74fa-463e-85b6-34ba50effb75','遊{若/山}山寺','常令孫','宋','宋诗','song-poetry','','[]','薝蔔花中燕子飛，旌旗小隊到招提。',64,'全唐诗/poet.song.209000.json','["薝蔔花中燕子飛，旌旗小隊到招提。", "客車陸續氈重席，僧饌雍客藿間藜。", "文奕已先元墅奪，詩壇漸壓魯山低。", "歸來醉步誰扶杖，月在牛欄西復西。"]'),
('edcab3d0-ab84-4a3d-b2d9-0c49bad084d2','題西湖水閣','常顓孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','倚湖松竹擁樓臺，景物招人得得來。',32,'全唐诗/poet.song.209000.json','["倚湖松竹擁樓臺，景物招人得得來。", "誰識我身非俗物，洞門深鎖不容開。"]'),
('dd75e184-4fa7-4bfe-8d9e-bc4544e61195','鶴林寺次岳侍郎韵','朱承祖','宋','宋诗','song-poetry','','[]','鶴林古竹院，馬素舊松關。',48,'全唐诗/poet.song.209000.json','["鶴林古竹院，馬素舊松關。", "草合門前路，雲埋寺後山。", "花神千載去，僧話片時閑。", "滿壁瑰奇句，慙窺豹一斑。"]'),
('89e02451-c119-4b18-922e-20c99ec0292f','自贊','孟珙','宋','宋诗','song-poetry','','[]','老拙愛游戲，忙裏放癡憨。',132,'全唐诗/poet.song.209000.json','["老拙愛游戲，忙裏放癡憨。", "正當恁麽持，無處見無庵。", "混沌庵之基，大朴庵之梁。", "大始庵之柱，大極庵之枋。", "西儀庵之戶，三才庵之房。", "四象庵之壁，八卦庵之窗。", "白雲庵之頂，清風庵之牆。", "誰人運斤斧，大匠曰羲黄。", "明月爲伴侶，萬古共如常。", "欲知我富貴，秋水接天長。", "水雲不到處，一片玉壺光。"]'),
('2ae432ac-6564-49c4-99a1-524aeb3ee58c','自頌','孟珙','宋','宋诗','song-poetry','','[]','有生必有滅，無庵無可說。',24,'全唐诗/poet.song.209000.json','["有生必有滅，無庵無可說。", "踢倒玉崑崙，夜半紅日出。"]'),
('333f971f-b921-4268-bd2a-c025d5a5970f','自詠','蔡權','宋','宋诗','song-poetry','','[]','故居廌山東，十載去不還。',132,'全唐诗/poet.song.209000.json','["故居廌山東，十載去不還。", "故人廬峰北，一念長周旋。", "風波既渺藐，歲月空推延。", "園地益新好，亭館故依然。", "憶昔紫陽翁，沉醉春風前。", "登覽意有會，携提筆如椽。", "銀鈎並鐵畫，燦爛疑蛇蜒。", "至今雕梁上，日夕生雲煙。", "觸事多思遠，撫景良獨妍。", "秀色可覽結，嵐光渺無邊。", "斯文與斯亭，千古垂不刊。"]'),
('f47dba9d-c389-4df5-84bf-75737da9a4ec','夜嘆','蔡權','宋','宋诗','song-poetry','','[]','不寐中宵發嘆歌，無聞見惡竟如何。',64,'全唐诗/poet.song.209000.json','["不寐中宵發嘆歌，無聞見惡竟如何。", "堪嗟歲月蹉跎久，却悔塵寰錯誤多。", "事業分明卑管晏，源流直上接丘軻。", "衰顔皓髮雄心在，蓄艾從今起宿疴。"]'),
('7444108a-5021-4ddb-98d5-ee731742dcf8','和鵝湖三先生韵','蔡權','宋','宋诗','song-poetry','','[]','朱陸豪雄夙所欽，本仁祖義渾同心。',64,'全唐诗/poet.song.209000.json','["朱陸豪雄夙所欽，本仁祖義渾同心。", "高明頓足先登岸，邃密爲山漸到岑。", "易簡支離爭誚切，禪關俗學互浮沉。", "撐眉拏眼來葱嶺，公論昭明在古今。"]'),
('3573ffc5-b9ff-4095-941e-59b6abc45d23','遊西山','蔡權','宋','宋诗','song-poetry','','[]','洞天杳杳白雲低，古木叢陰路欲迷。',64,'全唐诗/poet.song.209000.json','["洞天杳杳白雲低，古木叢陰路欲迷。", "晝永並無人跡混，夜深惟有鳥聲啼。", "雨昏草色寒侵院，風入松聲響亂溪。", "隔宿尋幽心未愜，馬回山下日將西。"]'),
('f5826d21-c93e-434f-9cec-e0bdbbb4104b','夜坐','蔡權','宋','宋诗','song-poetry','','[]','露冷風高天氣清，中秋月色更分明。',64,'全唐诗/poet.song.209000.json','["露冷風高天氣清，中秋月色更分明。", "捫懷永夜心同照，抱膝孤燈興自傾。", "漏盡欣無塵客坐，鐘鳴恍有老仙迎。", "歸來最愛天機靜，莫遣紛紛混世情。"]'),
('e7a104e8-267a-4dd4-8ecb-51a3c3fe20f0','掩扉','蔡權','宋','宋诗','song-poetry','','[]','院靜秋深晝掩扉，倦遊園圃坐忘歸。',64,'全唐诗/poet.song.209000.json','["院靜秋深晝掩扉，倦遊園圃坐忘歸。", "休驚白髮催顔瘦，且看黄鸝繞樹飛。", "翠竹受風生遠韵，碧梧竟夕含清暉。", "此間標格誰能會，唯有孤星入少微。"]'),
('ebb75e67-5af5-4a55-8a6c-f3939d0370ce','喜雨歌','吳潛','宋','宋诗','song-poetry','','[]','南州六月天不雨，千里川原成赤土。',160,'全唐诗/poet.song.209000.json','["南州六月天不雨，千里川原成赤土。", "禾黍盈疇强半枯，桔槹遍野民勞苦。", "望雲仰見日在天，旱魃肆虐如焚煎。", "馮夷匿淵恐波竭，夸娥走海愁山然。", "天外悠然片雲起，倏忽走騰八埏裏。", "猛風驚電白晝昏，霹靂一聲蛟蜃起。", "馬上誰把天瓢傾，須臾陸地波濤生。", "禾黍芃芃復故秀，羣黎載道生歡聲。", "秋來尚見時豐阜，會須售粲三錢斗。", "官家燮理當有人，太史還看書大有。"]'),
('ed80dcc3-c650-495f-959d-ff1234cdcced','宿省','吳潛','宋','宋诗','song-poetry','','[]','襥被趨省宿，披襟對晚凉。',48,'全唐诗/poet.song.209000.json','["襥被趨省宿，披襟對晚凉。", "古心知老樹，生意見新篁。", "鐘鼓鳴將合，蜩蟬咽更長。", "靜中觀物化，誰與共平章。"]'),
('475a74e4-9aa5-40a8-9692-4fa00c354e7a','睡起行北園','吳潛','宋','宋诗','song-poetry','','[]','睡起卸冠簪，園行獨自吟。',48,'全唐诗/poet.song.209000.json','["睡起卸冠簪，園行獨自吟。", "山昏知雨到，樹密覺春深。", "竹外童相報，門前客見尋。", "歸來即敗意，誰者是知心。"]'),
('ac00ada0-db02-432d-975d-e9a1260ad908','郡城晚望','吳潛','宋','宋诗','song-poetry','','[]','秋老逢天晚，孤城倚碧空。',48,'全唐诗/poet.song.209000.json','["秋老逢天晚，孤城倚碧空。", "升沈當此際，悵望與誰同。", "遠樹沒歸鳥，寒莎泣候蟲。", "所懷無晤處，彈指向西風。"]'),
('47cf431c-873f-4087-ae85-89289f8313ca','寧川道中','吳潛','宋','宋诗','song-poetry','','[]','十日爲山客，今朝問水程。',48,'全唐诗/poet.song.209000.json','["十日爲山客，今朝問水程。", "沙橫疑港斷，灘迅覺舟輕。", "遠近村舂合，高低漁火明。", "回頭忽蒼莽，一望一關情。"]'),
('3e4481d5-c673-45ea-a8d1-6d50fa90a810','幽居','吳潛','宋','宋诗','song-poetry','','[]','竹院秋逾靜，柴門晝不開。',48,'全唐诗/poet.song.209000.json','["竹院秋逾靜，柴門晝不開。", "病先携老去，懶漸逐衰來。", "莫遣新緣結，都將舊念灰。", "川魚與雲鳥，從此莫驚猜。"]'),
('ee904434-7e03-4b65-becf-efe6de16e2fd','送何錫汝','吳潛','宋','宋诗','song-poetry','','[]','風雨一樽酒，此懷誰得知。',48,'全唐诗/poet.song.209000.json','["風雨一樽酒，此懷誰得知。", "三春花老後，千里客歸時。", "浩浩人間事，悠悠身外思。", "君能袪物役，林下早相期。"]'),
('9a93df34-ede2-4d97-a2ca-4fe80f4875fe','宋山掃墓書所見','吳潛','宋','宋诗','song-poetry','','[]','松楸長夜夢，風露作晨征。',48,'全唐诗/poet.song.209000.json','["松楸長夜夢，風露作晨征。", "山近却無色，葉枯偏有聲。", "架禾知歲熟，種麥得天晴。", "到底農桑好，營營誤此生。"]'),
('e8aa77fe-aae6-4f93-9837-fbeb90c21c4f','山樓枕上','吳潛','宋','宋诗','song-poetry','','[]','山近寒偏早，愁多夢不濃。',48,'全唐诗/poet.song.209000.json','["山近寒偏早，愁多夢不濃。", "鴉啼半夜月，鶴唳五更風。", "曉接殘燈裏，吟成落葉中。", "塵埃今已厭，懶聽上方鐘。"]'),
('cf87c03c-b43b-4e3c-9749-40670379622b','桐川道中','吳潛','宋','宋诗','song-poetry','','[]','伊軋籃輿拂面風，桃花倚路笑相逢。',64,'全唐诗/poet.song.209000.json','["伊軋籃輿拂面風，桃花倚路笑相逢。", "鶑鶑交囀春榆密，燕燕于飛烟樹濃。", "日午暫休欹客枕，年饑忽喜聽村舂。", "鄉音到耳知家近，尚及鋤犂伴老農。"]'),
('427089e7-92c7-47f7-b757-554b04a4eb35','送曾阿宜往戍','吳潛','宋','宋诗','song-poetry','','[]','幾年西戍暫歸田，又向澄江買去船。',64,'全唐诗/poet.song.209000.json','["幾年西戍暫歸田，又向澄江買去船。", "劍閣山巒雄蔽日，昆明池水闊浮天。", "故園此際同明月，蠻域明朝隔瘴烟。", "此去須期剿胡虜，丈夫勳業在安邊。"]'),
('b21d7774-4c0b-470a-ac0a-63dfa5ce543c','和章子美閲武見貽','吳潛','宋','宋诗','song-poetry','','[]','事業諸公鬭長雄，謭才惟願課田功。',64,'全唐诗/poet.song.209000.json','["事業諸公鬭長雄，謭才惟願課田功。", "誰知絃管江南地，漸有弓刀塞北風。", "大獮未須搜猛獸，先驅聊用習驕驄。", "還知武備資文事，要在人心可即戎。"]'),
('ffffc2e1-4fc5-4d3e-8a56-ea5ed865b545','走馬燈賡張樞副韻','吳潛','宋','宋诗','song-poetry','','[]','半勺蘭膏暖焰生，恍疑赤壁夜鏖兵。',64,'全唐诗/poet.song.209000.json','["半勺蘭膏暖焰生，恍疑赤壁夜鏖兵。", "騎乘猛燎奔馳疾，人運長鎗轉戰輕。", "旗影靜移雲母帳，劍鋩微掣水晶營。", "何人幻此圓機妙，獨向元宵策美名。"]'),
('46337193-d678-4c77-b610-447834eb00b0','古劍','吳潛','宋','宋诗','song-poetry','','[]','何年神物爲堙幽，時見虹光射斗牛。',64,'全唐诗/poet.song.209000.json','["何年神物爲堙幽，時見虹光射斗牛。", "出匣試來霜刃暗，倚天立處土花浮。", "鸊膏新淬冰泉潔，錦带橫懸鬼魅愁。", "不是張華能博物，黄塵滿眼欲何求。"]'),
('597eb51c-8a2f-4e68-8bb4-b56633f0a946','春日雜詠','吳潛','宋','宋诗','song-poetry','','[]','門前春水滑，柳外夕陽斜。',24,'全唐诗/poet.song.209000.json','["門前春水滑，柳外夕陽斜。", "欲識春風面，滿城桃李花。"]'),
('9d261891-5f0e-4dc0-8e41-27bcf733ff49','偶題','吳潛','宋','宋诗','song-poetry','','[]','濃淡烟村碧，淺深霜葉紅。',24,'全唐诗/poet.song.209000.json','["濃淡烟村碧，淺深霜葉紅。", "蓬窗今夜客，蘆岸晚來風。"]'),
('5e664f5c-c97d-4f6a-b1bd-2e706cb93a2e','游白紵山','吳潛','宋','宋诗','song-poetry','','[]','信馬來游白紵山，僧窗容我片時閒。',32,'全唐诗/poet.song.209000.json','["信馬來游白紵山，僧窗容我片時閒。", "人生自古少行樂，試爲春風一解顔。"]'),
('ef00b143-c2fe-43b7-be96-25f273b362d2','即事','吳潛','宋','宋诗','song-poetry','','[]','春陰漠漠護輕寒，春晝無聊午夢閒。',32,'全唐诗/poet.song.209000.json','["春陰漠漠護輕寒，春晝無聊午夢閒。", "幽鳥不知人意改，銜花飛傍小闌干。"]'),
('6686a741-62ed-404d-be9d-773272cb9808','陪陳立道中書泛湖二首  其一','吳潛','宋','宋诗','song-poetry','','[]','幽幽池館鎖蒼苔，萬朵芙蓉取次開。',32,'全唐诗/poet.song.209000.json','["幽幽池館鎖蒼苔，萬朵芙蓉取次開。", "却似昭陽舊宮女，含嬌只待翠華來。"]'),
('b6a42a91-1b31-405f-9b8a-16724923a5dd','陪陳立道中書泛湖二首  其二','吳潛','宋','宋诗','song-poetry','','[]','絃管叢中畫舫行，都人一一賀昇平。',32,'全唐诗/poet.song.209000.json','["絃管叢中畫舫行，都人一一賀昇平。", "飛鴻不識人間事，猶作窮邊腸斷聲。"]'),
('26dcd5cb-ef71-4afb-9f5b-83192fde05d1','送率翁歸狼山','吳潛','宋','宋诗','song-poetry','','[]','孤雲住處是狼山，雲本無心山自閒。',32,'全唐诗/poet.song.209000.json','["孤雲住處是狼山，雲本無心山自閒。", "老率似雲雲似率，等閒飛去又飛還。"]'),
('e88e82f0-9dc5-40df-87a4-75777d0796f3','吳波亭二首  其一','吳潛','宋','宋诗','song-poetry','','[]','吳波亭下繫扁舟，輕雨輕烟又麥秋。',32,'全唐诗/poet.song.209000.json','["吳波亭下繫扁舟，輕雨輕烟又麥秋。", "烏兔銜將日月去，江山管定古今愁。"]'),
('61af0fef-a76b-466d-b0ff-ddb92805024a','吳波亭二首  其二','吳潛','宋','宋诗','song-poetry','','[]','雲收烟歛遠山明，時有漁歌度晚晴。',32,'全唐诗/poet.song.209000.json','["雲收烟歛遠山明，時有漁歌度晚晴。", "綠葉青枝生意思，白鷗蒼鳥野心情。"]'),
('7689eba8-1de0-4602-8fc8-e6319d04b6c6','謝世頌三首  其一','吳潛','宋','宋诗','song-poetry','','[]','夫子曳杖逍遥，曾子易簀兢戰。',28,'全唐诗/poet.song.209000.json','["夫子曳杖逍遥，曾子易簀兢戰。", "聖賢樂天畏天，吳子中通一線。"]'),
('7bca271c-f2e9-4789-8598-400cf09e7f58','謝世頌三首  其二','吳潛','宋','宋诗','song-poetry','','[]','大带深衣，緇冠素履。',40,'全唐诗/poet.song.209000.json','["大带深衣，緇冠素履。", "籍以紙衾，覆以布被。", "一物不將，歛形而已。", "其人伊何，履齋居士。"]'),
('6db67d66-c22a-40f1-9a9a-e34fb3229c6f','謝世頌三首  其三','吳潛','宋','宋诗','song-poetry','','[]','生在湖州新市上，死在循州貢院中。',32,'全唐诗/poet.song.209000.json','["生在湖州新市上，死在循州貢院中。", "一場雜劇也好笑，來時無物去時空。"]'),
('0d84cae4-a2fc-454d-9cec-36abaf19acbd','愛山臺','吳潛','宋','宋诗','song-poetry','','[]','直殿風流間世才，乞恩監郡築高臺。',64,'全唐诗/poet.song.209000.json','["直殿風流間世才，乞恩監郡築高臺。", "杖遊便覺開懷抱，石甃何須辟草萊。", "奎壁九重文運煥，烟巒千里畫圖開。", "愛山必欲斯民愛，沛澤行看早晚來。"]'),
('2a1fc2bc-966f-403e-8d62-228a51675403','秋風歎四首  其一','吳潛','宋','宋诗','song-poetry','','[]','長鯨海上來，壯士田間起。',24,'全唐诗/poet.song.209000.json','["長鯨海上來，壯士田間起。", "登城復何悲，禾稼秋風裏。"]'),
('50960e8f-042a-41fc-a659-e97b026093d8','秋風歎四首  其二','吳潛','宋','宋诗','song-poetry','','[]','誰將訟風伯，謂天懲雨師。',24,'全唐诗/poet.song.209000.json','["誰將訟風伯，謂天懲雨師。", "天閽幾萬里，聵聵安得知。"]'),
('42444e8f-300d-462c-a086-7e8779308e31','秋風歎四首  其三','吳潛','宋','宋诗','song-poetry','','[]','軍書督戰急，縣吏催租還。',24,'全唐诗/poet.song.209000.json','["軍書督戰急，縣吏催租還。", "力盡將何訴，浮雲深九關。"]'),
('c98f0a49-6480-4d1c-ae94-fb9397aea199','秋風歎四首  其四','吳潛','宋','宋诗','song-poetry','','[]','嘗聞海客談，白浪海風惡。',24,'全唐诗/poet.song.209000.json','["嘗聞海客談，白浪海風惡。", "祗是欺舴艋，那見摧蛟鱷。"]'),
('7f9fc211-013f-4efd-9a88-51d1e9a249c8','題舒蓼瞻嘯圃獨吟圖二首  其一','吳潛','宋','宋诗','song-poetry','','[]','丹厓白雲往來，絕岸流潮吞吐。',28,'全唐诗/poet.song.209000.json','["丹厓白雲往來，絕岸流潮吞吐。", "我所思兮何人，莽悠悠兮太古。"]'),
('de0d376b-c462-42cb-a9ad-411d644124c8','題舒蓼瞻嘯圃獨吟圖二首  其二','吳潛','宋','宋诗','song-poetry','','[]','江口寒潮自至，山間明月誰招。',28,'全唐诗/poet.song.209000.json','["江口寒潮自至，山間明月誰招。", "自可歸來坐嘯，何須世上折腰。"]'),
('9936b1fe-087a-47ce-8d4f-860abfcb2fb5','聽琴客周信民彈秋泉二首  其一','吳潛','宋','宋诗','song-poetry','','[]','雁湖龍井久知名，總入君家匣裏清。',32,'全唐诗/poet.song.209000.json','["雁湖龍井久知名，總入君家匣裏清。", "客舍試彈三兩曲，恍疑飛沫濺塵纓。"]'),
('5d4e6756-ab85-48dd-aa70-e5067af397fc','聽琴客周信民彈秋泉二首  其二','吳潛','宋','宋诗','song-poetry','','[]','故里泉聲不可聞，携琴相約鮑參軍。',32,'全唐诗/poet.song.209000.json','["故里泉聲不可聞，携琴相約鮑參軍。", "山瓢只繫經行處，落葉空山好覓君。"]'),
('5f281030-0daf-4c97-b268-135223cc65a5','陸宣公祠','吳潛','宋','宋诗','song-poetry','','[]','凜凜清規百世師，功名僅見奉天時。',64,'全唐诗/poet.song.209000.json','["凜凜清規百世師，功名僅見奉天時。", "忠謀任起姦邪忌，感泣寧無士卒思。", "落日桑榆存舊蹟，西風蘆葦護荒祠。", "忠宣流落何遺恨，留得良方與後醫。"]'),
('6ac5564a-a206-4ad4-86dd-fc4d46b42a1d','錢塘江三首  其一','吳潛','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江頭風雨弄輕寒，小艇輕蓑把釣竿。',32,'全唐诗/poet.song.209000.json','["江頭風雨弄輕寒，小艇輕蓑把釣竿。", "日暮滄浪歌漸遠，延緣應自避塵冠。"]'),
('92849b15-f7ab-4495-9a66-6604345c9ef5','錢塘江三首  其二','吳潛','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','扁舟東下白雲鄉，一水牽愁萬里長。',32,'全唐诗/poet.song.209000.json','["扁舟東下白雲鄉，一水牽愁萬里長。", "多謝白鷗閒不去，知余機事近來忘。"]'),
('ddc1616d-743b-403f-8805-a0b386e29eb3','錢塘江三首  其三','吳潛','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','秋光漠漠草青青，日落江流雁下汀。',32,'全唐诗/poet.song.209000.json','["秋光漠漠草青青，日落江流雁下汀。", "世路風波今始半，爲余遥謝草堂靈。"]'),
('2f2ae683-3c12-49f9-9099-65f155e67f60','登鎮海樓','吳潛','宋','宋诗','song-poetry','','[]','鄮山深處古明州，新有江南客倚樓。',64,'全唐诗/poet.song.209000.json','["鄮山深處古明州，新有江南客倚樓。", "鳳闕天連便望日，蛟門海晏不驚秋。", "頭顱已迫殘年景，身口聊爲卒歲謀。", "蕭颯西風吹敗葉，滿眶清淚自難收。"]'),
('d5fe9fa9-d753-4b75-9611-b1f6848caac3','對黄花','吳潛','宋','宋诗','song-poetry','','[]','當年脫却戲衫回，又被官差喚出來。',64,'全唐诗/poet.song.209000.json','["當年脫却戲衫回，又被官差喚出來。", "疾惡念輕緣練歷，好名心懶爲衰摧。", "莫愁白髮家千里，且對黄花酒一杯。", "信美江山非我土，倚空凝竚更徘徊。"]'),
('5b699058-608f-4e42-ac42-139fb5e6b248','呈蕭山知縣','吳潛','宋','宋诗','song-poetry','','[]','八年兩喚浙江船，吳越青山相對妍。',64,'全唐诗/poet.song.209000.json','["八年兩喚浙江船，吳越青山相對妍。", "長媿主恩難報答，不知人事幾推遷。", "香浮菊桂秋將暮，景迫桑榆歲可憐。", "荒縣今宵孤館夢，四千里外楚雲邊。"]'),
('ca5bf0c8-3118-4844-a32f-084e74c04daa','分定','吳潛','宋','宋诗','song-poetry','','[]','丁年曾授此東州，懇懇牋天得罷休。',64,'全唐诗/poet.song.209000.json','["丁年曾授此東州，懇懇牋天得罷休。", "七上八下忽九閏，十洲三島終一遊。", "人言官貴體當重，自笑兒癡病未瘳。", "只爲君恩深莫報，明年春盡得歸不。"]'),
('3aeb3431-5b78-45d4-930f-dc33df64b0f3','自嘆','吳潛','宋','宋诗','song-poetry','','[]','門槌拍板久收藏，又向棚頭弄一場。',64,'全唐诗/poet.song.209000.json','["門槌拍板久收藏，又向棚頭弄一場。", "束縛冠裳新上舍，經營粥飯舊街方。", "亂鴉啼處客回首，落雁聲邊人斷腸。", "堆案文書銷永日，誰云燕寢凝清香。"]'),
('58a874c6-ee14-4d91-8b93-438aa85673ad','曉兒輩','吳潛','宋','宋诗','song-poetry','','[]','諸兒憐我太焦熬，我把真機告汝曹。',64,'全唐诗/poet.song.209000.json','["諸兒憐我太焦熬，我把真機告汝曹。", "外白內黄常抱守，出朱入墨任紛撓。", "治齊固有曹參逸，理蜀寧無諸葛勞。", "畢竟食焉而怠事，天刑人禍恐難逃。"]'),
('baffbde9-556f-41af-bc3a-5803eb6939fe','閲城壁','吳潛','宋','宋诗','song-poetry','','[]','內江外海四周圍，正是綢繆戶牖時。',64,'全唐诗/poet.song.209000.json','["內江外海四周圍，正是綢繆戶牖時。", "北瞰登萊山不礙，東漸倭麗汛難期。", "未須鷂鷁增威勢，已覺狌鼯受指麾。", "敢謂虛名彈壓得，多應一念老天知。"]'),
('12be0ab3-0289-41cc-8d78-98942ca2a7af','歲晏無聊收叔氏訊','吳潛','宋','宋诗','song-poetry','','[]','豢成凋郡力難任，雪上加霜兩鬢侵。',64,'全唐诗/poet.song.209000.json','["豢成凋郡力難任，雪上加霜兩鬢侵。", "四五更頭猿鶴夢，數千里外鶺鴒心。", "老來倍覺光陰促，休去方知意味深。", "陶白邵詩消遣具，晚窗無事且微吟。"]'),
('2d663d71-889e-40aa-9033-20947841f69b','朝謁歸省文書','吳潛','宋','宋诗','song-poetry','','[]','面擁旌旗鼓樂隨，誰知錦被裹瘡痍。',64,'全唐诗/poet.song.209000.json','["面擁旌旗鼓樂隨，誰知錦被裹瘡痍。", "吏那秋斂充春賦，兵待朝輸作暮炊。", "縮手判支窮措大，攢眉書準老沙彌。", "此是履翁新活計，雁書多報故人知。"]'),
('b3b461d7-b2cd-4ec8-8bca-1d544923e2ff','喜雪二首  其一','吳潛','宋','宋诗','song-poetry','','[]','黄竹歌中百姓歡，去天近處雪花乾。',64,'全唐诗/poet.song.209000.json','["黄竹歌中百姓歡，去天近處雪花乾。", "蔡洄事業方歸度，剡曲風流欲訪安。", "便覺光輝生萬里，定知潤澤被三韓。", "衰頹老守煨殘芋，白戰猶堪上將壇。"]'),
('ec569db1-a44c-4518-91bf-6250be844805','喜雪二首  其二','吳潛','宋','宋诗','song-poetry','','[]','玄冥去歲失其官，今歲誰云補過難。',64,'全唐诗/poet.song.209000.json','["玄冥去歲失其官，今歲誰云補過難。", "謝院撒鹽飛瑣瑣，隋堤翦帛散戔戔。", "簷儲宿肉喧山鵲，路沒遺蹤走野豻。", "管取明年書大有，飽抄雲子飯加餐。"]'),
('4334b33f-4088-408a-879a-135e76dc64d4','再賦喜雪二首  其一','吳潛','宋','宋诗','song-poetry','','[]','黑風翦水作瑰琦，散落人閒賤似泥。',64,'全唐诗/poet.song.209000.json','["黑風翦水作瑰琦，散落人閒賤似泥。", "萬象直教還朴素，千岐何幸盡平夷。", "征人奔路昏投店，戍士乘城夜守陴。", "不識艱難惟党二，銷金帳底飲羔兒。"]'),
('6568ab96-e263-4994-bd72-6f708231508f','再賦喜雪二首  其二','吳潛','宋','宋诗','song-poetry','','[]','夜深如水潑衣衾，曉看皚皚冒碧岑。',64,'全唐诗/poet.song.209000.json','["夜深如水潑衣衾，曉看皚皚冒碧岑。", "以潔藏污窺物理，由仁行義見天心。", "但教南畝多呈瑞，何必東夷屢獻琛。", "麥熟吾時歸印綬，不能者止念周任。"]'),
('4f343c7a-6e2f-4a60-809a-00cec8358e09','喜雨二首  其一','吳潛','宋','宋诗','song-poetry','','[]','雷使巡行徧五方，夾秋不怕旱爲殃。',64,'全唐诗/poet.song.209000.json','["雷使巡行徧五方，夾秋不怕旱爲殃。", "人閒祥瑞三伏雨，枕上吟哦終夕凉。", "已卜晚青催出穗，且將早赤急舂糧。", "有司不損應言損，隨分蠲租助蓋藏。"]'),
('88300b51-169b-4d2a-ade0-ca0fa82e3d60','喜雨二首  其二','吳潛','宋','宋诗','song-poetry','','[]','莫嫌暴涷勢如噴，此是家家老飯盆。',64,'全唐诗/poet.song.209000.json','["莫嫌暴涷勢如噴，此是家家老飯盆。", "雨足蛟龍應得謝，秋登雞犬亦蒙恩。", "頻年已喜稼無賊，今歲尤欣禾有孫。", "回首江南田谷口，西風颯颯倍消魂。"]'),
('ae1bea2d-4578-43c0-9029-39852f7d8c47','再用前韻二首  其一','吳潛','宋','宋诗','song-poetry','','[]','行雨龍公屢易方，魃妖誰敢扇餘殃。',64,'全唐诗/poet.song.209000.json','["行雨龍公屢易方，魃妖誰敢扇餘殃。", "田疇接得三年熟，枕簟供來幾夜凉。", "更喜征夫無減竈，定應行旅不賫糧。", "寄聲鄞土黄承事，有粟何須更窖藏。"]'),
('64d952f2-16d6-4e55-b365-ea480a447d14','再用前韻二首  其二','吳潛','宋','宋诗','song-poetry','','[]','不假焦仙把酒噴，須臾澍雨若翻盆。',64,'全唐诗/poet.song.209000.json','["不假焦仙把酒噴，須臾澍雨若翻盆。", "官應可了劭農事，天豈終慳及物恩。", "無復絕糧憂魯叟，何須進食念王孫。", "只愁撩得秋聲動，老客他鄉易斷魂。"]'),
('63713d1a-2079-4cd5-8e5d-2cbc4eb0197d','再用前韻各賦三解  其一','吳潛','宋','宋诗','song-poetry','','[]','九天膏澤沛羣方，盡掃螟蝗蝥𧎬殃。',64,'全唐诗/poet.song.209000.json','["九天膏澤沛羣方，盡掃螟蝗蝥𧎬殃。", "即刻焦煩成爽塏，何時繁富換荒凉。", "滌場定是多遺秉，棲畝爰知有剩糧。", "却笑蓽門窮措大，瓶罌脫粟正深藏。"]'),
('7001bf81-1bff-436a-b293-9cf1c0b113ec','再用前韻各賦三解  其二','吳潛','宋','宋诗','song-poetry','','[]','神虬捲水向空噴，溝澮充盈到盎盆。',64,'全唐诗/poet.song.209000.json','["神虬捲水向空噴，溝澮充盈到盎盆。", "天上只消些少力，人閒知受幾多恩。", "江沱樂意魚夫婦，淇澳生涯龍子孫。", "無限槁枯皆被澤，阿香一擊尚驚魂。"]'),
('cf77580c-2a07-47c3-85cb-ee994af30572','再用前韻各賦三解  其三','吳潛','宋','宋诗','song-poetry','','[]','密雲能雨自西方，不假巫{八/几王}解息殃。',69,'全唐诗/poet.song.209000.json','["密雲能雨自西方，不假巫{八/几王}解息殃。", "地産固應滋物産，天凉那更挾心凉。", "未憂懸釜供蘇爨，何事量沙作糗糧。", "臨得顔公乞米帖，從今歲歲只珍藏。"]'),
('d39e93a3-f3bb-4d3d-b4ec-4c33cf601d09','再用前韻各賦三解  其四','吳潛','宋','宋诗','song-poetry','','[]','赤米炊香兩鼻噴，白鹽不用置牢盆。',64,'全唐诗/poet.song.209000.json','["赤米炊香兩鼻噴，白鹽不用置牢盆。", "家家已了收藏計，物物何知造化恩。", "衣褐寬來姑喚婦，垣墉補處祖將孫。", "江鄉此際雞豚社，俚舞村歌入夢魂。"]'),
('b3264590-2267-4e02-8eba-bd0788807582','再用前韻各賦三解  其五','吳潛','宋','宋诗','song-poetry','','[]','先生粗有辟邪方，不怕鱄魚解降殃。',64,'全唐诗/poet.song.209000.json','["先生粗有辟邪方，不怕鱄魚解降殃。", "今雨收功真溥博，早秋得勢已淒涼。", "豳場栗栗方登穀，漢甬陳陳可峙糧。", "此是邊籌居第一，賈生表餌且韜藏。"]'),
('9b476c61-983f-4411-9b19-081fd1b514fb','再用前韻各賦三解  其六','吳潛','宋','宋诗','song-poetry','','[]','牀頭酒熟氣烝噴，嘉飯何妨置瓦盆。',64,'全唐诗/poet.song.209000.json','["牀頭酒熟氣烝噴，嘉飯何妨置瓦盆。", "醉飽不知身世事，思量難報后皇恩。", "垂髫牧子行牽父，戴白山翁坐擁孫。", "却笑東征西討客，龍堆萬里欲飛魂。"]'),
('0709038a-dc04-46da-8b45-e26f94d9b10f','喜雨三首  其一','吳潛','宋','宋诗','song-poetry','','[]','古佛爐前一炷香，神龍夭矯掛空蒼。',64,'全唐诗/poet.song.209000.json','["古佛爐前一炷香，神龍夭矯掛空蒼。", "人閒祥瑞六月雨，枕上吟哦終夕凉。", "不待白渠紛畚鍤，俄驚赤鹵屹倉箱。", "自慚太守無功德，帝力惟知荷聖皇。"]'),
('bb0275cf-e659-4b97-903a-d61ca5b75fac','喜雨三首  其二','吳潛','宋','宋诗','song-poetry','','[]','西抹東塗老不禁，芙蓉洲畔更浮沈。',64,'全唐诗/poet.song.209000.json','["西抹東塗老不禁，芙蓉洲畔更浮沈。", "數莖半黑半絲髮，一寸憂晴憂雨心。", "烏糤且欣將淅玉，紅蓮何翅已抽簪。", "小臣獻穀秋嘗了，深密山林可訪尋。"]'),
('9e776aa5-38f3-4cb4-b41f-716ef2c97626','喜雨三首  其三','吳潛','宋','宋诗','song-poetry','','[]','晚上危樓望碧岑，雲煙開闔弄晴陰。',64,'全唐诗/poet.song.209000.json','["晚上危樓望碧岑，雲煙開闔弄晴陰。", "見前鷗鷺移心法，何處鴟梟過耳音。", "好雨十分催暑駕，凉風一宿動秋砧。", "誰憐老子思鄉淚，滴向鄞江未是深。"]'),
('38160df0-edac-4b38-8c8c-9b199ddbddc9','再用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','古說雲香雨亦香，天工豈是色蒼蒼。',67,'全唐诗/poet.song.209000.json','["古說雲香雨亦香，天工豈是色蒼蒼。", "寸瓢假手何煩靖，斗酒開眉不換凉。", "𥣬{禾散}已欣登杵臼，綌絺漸可納巾箱。", "擬賡周雅魚麗什，堆案文書未暇皇。"]'),
('242d256b-f888-48b0-83ba-ca553d2b9022','再用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','熱惱煩蒸正不禁，火輪忽向半空沈。',64,'全唐诗/poet.song.209000.json','["熱惱煩蒸正不禁，火輪忽向半空沈。", "屯中信有雲雷象，復處方知天地心。", "便擬新秋先上印，何須晚歲始投簪。", "江山信美非吾土，栗里時從蝶夢尋。"]'),
('7e4dd1fe-5ffa-4611-9e68-6290b7cd1a32','再用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','雨脚如奔冒遠岑，須臾六合變層陰。',64,'全唐诗/poet.song.209000.json','["雨脚如奔冒遠岑，須臾六合變層陰。", "坐回物物昭甦意，想見村村喜笑音。", "翁詫稻粱營米棧，婦思裘褐拂衣砧。", "定知一熟酬諸願，擊壤歌中此感深。"]'),
('86d4582a-4f55-4017-9609-aad4c865f997','三用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','雨缶雲瓶剖阿香，瀰漫何處辨玄蒼。',64,'全唐诗/poet.song.209000.json','["雨缶雲瓶剖阿香，瀰漫何處辨玄蒼。", "衰翁顦顇憂三伏，古佛慈悲賜一凉。", "但願有緣乘款段，豈應無夢駕偏箱。", "西風谷口秋田熟，休問奇章與贊皇。"]'),
('789bcf09-23b1-40c6-a1cc-5b7e013d13d9','三用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','虬龍未必要呵禁，久暍無緣便陸沈。',64,'全唐诗/poet.song.209000.json','["虬龍未必要呵禁，久暍無緣便陸沈。", "未遂明農歸老計，且寬憂國願豐心。", "披襟雅稱琉璃簟，散髮何銷玳瑁簪。", "只怕門前多褦襶，文書銜袖苦相尋。"]'),
('0c113254-c326-4c5a-bbfe-b2f87268cca6','三用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','電掣金蛇跨列岑，秋陽翕忽轉秋陰。',64,'全唐诗/poet.song.209000.json','["電掣金蛇跨列岑，秋陽翕忽轉秋陰。", "俄驚石鼓無停響，坐聽簷花不斷音。", "玉秫已堪供甕釀，紫螯漸可付庖砧。", "一年好處相將近，分外鄉情此際深。"]'),
('8faa7842-e91b-40d2-a8f0-48c7a4f198f1','四用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','園林過雨宿荷香，猶掛輕綀佩水蒼。',64,'全唐诗/poet.song.209000.json','["園林過雨宿荷香，猶掛輕綀佩水蒼。", "老去只應休去好，秋來方是晚來凉。", "倦翎網已離三面，病顙車難服兩箱。", "多幸時和歲豐美，只將心念報虛皇。"]'),
('ed386081-bc97-4466-ad42-34ba48dfba37','四用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','背人歲月苦難禁，烏兔相追互起沈。',64,'全唐诗/poet.song.209000.json','["背人歲月苦難禁，烏兔相追互起沈。", "點檢平生如夢事，保全晚節是真心。", "圍腰減削那勝带，種髮蕭疎不上簪。", "久悟盈虛消息理，香山蓮社擬追尋。"]'),
('42011fd1-8003-4b00-9aa1-a8070376063c','四用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','北岑飛雨過南岑，遠嶂晴明近嶂陰。',64,'全唐诗/poet.song.209000.json','["北岑飛雨過南岑，遠嶂晴明近嶂陰。", "老檜婆娑方午色，孤桐摇落忽秋音。", "庭稀雁鶩飛符檄，海絕鯨鯢伏斧砧。", "此是老臣聊報國，仁聲敢謂入人深。"]'),
('9399c71b-20ba-420e-8e78-08c3edae1d05','五用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','暗雲潑雨土生香，不假琮黄與璧蒼。',64,'全唐诗/poet.song.209000.json','["暗雲潑雨土生香，不假琮黄與璧蒼。", "天道從來關感應，人閒此際換炎凉。", "青燈可近聊凭案，緗帙堪翻謾啟箱。", "窗外候蟲聲更急，坐看斜月照堂皇。"]'),
('0c2449c7-8b29-4fbd-ac78-711359762dd3','五用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','癡風盲雨驟難禁，撼壁掀窗夜向沈。',64,'全唐诗/poet.song.209000.json','["癡風盲雨驟難禁，撼壁掀窗夜向沈。", "百種已灰當世念，一團都是故鄉心。", "伏鴽撲墮牀頭幔，饑鼠銜翻鏡上簪。", "閑打無爲坐空寂，譙樓五鼓已侵尋。"]'),
('c42dfdc6-faa7-4b11-89d2-3ac7c296d249','五用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','家家穫稻積如岑，不問山椒與谷陰。',64,'全唐诗/poet.song.209000.json','["家家穫稻積如岑，不問山椒與谷陰。", "沽去村醪醽醁味，吹來隴笛筦絃音。", "餔兒喜笑迎郎罷，饁婦讙欣就藁砧。", "雨玉雨珠無此景，須知造物用情深。"]'),
('cb999cea-4192-490e-b125-a5e518eda408','六用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','午窗隨分理殘香，掃地關門付小蒼。',64,'全唐诗/poet.song.209000.json','["午窗隨分理殘香，掃地關門付小蒼。", "連夜月無昨夜色，今朝雨有幾朝凉。", "白頭凝望家千里，黄耳寄歸書一箱。", "徧問西疇全熟否，還鄉百口免憂皇。"]'),
('26f53e97-b557-4eba-a38a-1c37988ca15e','六用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','毋煩符祝不祥禁，并遣商羊旱魃沈。',64,'全唐诗/poet.song.209000.json','["毋煩符祝不祥禁，并遣商羊旱魃沈。", "自詭何關太守力，誰知最切老婆心。", "苦身見說湯誅髮，沾體曾聞禹墮簪。", "乾溢兩無年大有，君王德澤海千尋。"]'),
('97e9c0b5-19b4-4c9c-9aef-fdd0e37ffca7','六用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','雲霾幾日障危岑，戶牖綢繆要背陰。',64,'全唐诗/poet.song.209000.json','["雲霾幾日障危岑，戶牖綢繆要背陰。", "又是撩空孤雁唳，那堪穴壁亂蛩音。", "潘郎寂寞嗟輕箑，楚女淒涼起斷砧。", "大抵人生嫌老大，一回秋思一回深。"]'),
('8b3a663e-b8af-46be-a4a1-d6f336472e49','七用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','鼻觀初聞九里香，小山幽桂老尤蒼。',64,'全唐诗/poet.song.209000.json','["鼻觀初聞九里香，小山幽桂老尤蒼。", "縱然有少殘零熱，自是無緣頓段凉。", "似覺衣襦嫌楚葛，便教牀榻卷巴箱。", "虬龍雨足當休謝，誰與飛牋叩玉皇。"]'),
('927b443c-980b-4c78-bd03-841ae783fe3d','七用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','頹年寒暑不能禁，休較玄枵與實沈。',64,'全唐诗/poet.song.209000.json','["頹年寒暑不能禁，休較玄枵與實沈。", "自古難銷兒輩口，從來幸契老天心。", "農登稼穡多儲寶，盜息萑蒲罕竊簪。", "持此效君强曝背，庶幾三徑許歸尋。"]'),
('ae70a19e-8fce-46f8-9ed5-b6ef72bb4f9d','七用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','闌干小倚望遥岑，曉霽朝朝換午陰。',64,'全唐诗/poet.song.209000.json','["闌干小倚望遥岑，曉霽朝朝換午陰。", "越鶩已收天外影，吳鳩尚带雨中音。", "海瀕客子秋銜袖，塞上征人夜拊砧。", "都是一般無意緒，閔勞爭柰主恩深。"]'),
('fa00971c-6dca-4c1c-8f0b-edd558b50b11','八用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','飯抄雲子得能香，秋賽村村答上蒼。',64,'全唐诗/poet.song.209000.json','["飯抄雲子得能香，秋賽村村答上蒼。", "雀集田疇營宿飽，牛閒籬落卧新凉。", "棲棲底用干鄰粟，翼翼惟應詠我箱。", "一稔居然寬百慮，不須禹稷更皇皇。"]'),
('66ef8c9c-3f54-4c16-aec3-e2b679008c9f','八用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','殘暑如烝尚不禁，坐鄰三鼓斗杓沈。',64,'全唐诗/poet.song.209000.json','["殘暑如烝尚不禁，坐鄰三鼓斗杓沈。", "雨調可是月離畢，時熟元來歲在心。", "筋力不堪凭几案，頭顱惟便卸冠簪。", "呼童火燎焦冥種，投隙藏虛未易尋。"]'),
('f4a1ad3c-5577-4dd7-9e9c-34283c3e59ad','八用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','礫石何分埠與岑，神功且幸景多陰。',64,'全唐诗/poet.song.209000.json','["礫石何分埠與岑，神功且幸景多陰。", "願聞慶義空中語，喜聽子期巖下音。", "南圃壁懸居士杖，西鄰牀撼女郎砧。", "消磨鄉思憑杯酒，力不能任莫放深。"]'),
('cf1d5e1a-703d-410b-9b65-d7f37acd6700','九用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','何消黍稷薦馨香，三尺擡頭即昊蒼。',64,'全唐诗/poet.song.209000.json','["何消黍稷薦馨香，三尺擡頭即昊蒼。", "雨缶决來如此溢，風車輸與自然凉。", "問他金玉堆成塢，更使珠璣積在箱。", "逢却年饑堪煮否，移民移粟定旁皇。"]'),
('b56ffb93-4d36-4cf6-84f3-3a2300ef4727','九用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','倒甕翻盆勢莫禁，旱灘焦磧盡低沈。',64,'全唐诗/poet.song.209000.json','["倒甕翻盆勢莫禁，旱灘焦磧盡低沈。", "定知此喜非常喜，只是將心去比心。", "人樂和豐方賣劍，誰貪遺滯忽亡簪。", "村翁曳杖前山去，丁祝孫來酒戶尋。"]'),
('47f355c2-2e52-42e3-80bf-7e7fd2fd8c0d','九用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','家鄉千里隔千岑，想見飛鳴鶴在陰。',64,'全唐诗/poet.song.209000.json','["家鄉千里隔千岑，想見飛鳴鶴在陰。", "留滯又煩山寄檄，平安且幸竹傳音。", "謾誇齋靜香凝寢，但覺簷高響發砧。", "若把悲愁情緒較，蚤秋不似暮秋深。"]'),
('2998a7ef-9f28-49ae-9c80-085ba3e31b11','十用喜雨韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','江南九月菊花香，獵子牽黄與臂蒼。',64,'全唐诗/poet.song.209000.json','["江南九月菊花香，獵子牽黄與臂蒼。", "歲幸豐登連楚越，地非磽薄比渠凉。", "雨收甘澤歸三印，雷歛神功入五箱。", "作解工夫都了畢，不須赤子更回皇。"]'),
('ebcf8068-a5b7-4d20-92aa-2c2f470f3489','十用喜雨韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','喜極夫何恨不禁，五更霜角夜聲沈。',64,'全唐诗/poet.song.209000.json','["喜極夫何恨不禁，五更霜角夜聲沈。", "滴殘塞北征夫淚，點碎江南遊子心。", "久客情懷愁似織，休官時候夢非簪。", "寶陀老子相憐否，苦海應援綆萬尋。"]'),
('f5db5520-edee-4ceb-9893-2293445bf642','十用喜雨韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','覽輝儀鳳下高岑，有道朝廷夬决陰。',64,'全唐诗/poet.song.209000.json','["覽輝儀鳳下高岑，有道朝廷夬决陰。", "宣室禮成熙洽象，明堂樂奏治安音。", "嘉祥已慶連金穎，盛事還祈獻石砧。", "只道太平無以報，誰知堯德舜功深。"]'),
('fc3ee434-22dd-4e0f-a516-d263d4e1ed2a','劭農三首  其一','吳潛','宋','宋诗','song-poetry','','[]','朝廷差下勸農官，同向郊原點檢看。',64,'全唐诗/poet.song.209000.json','["朝廷差下勸農官，同向郊原點檢看。", "場圃事興杷扒穴，田疇功畢桔槔殘。", "上租郎主丘丘定，輸米官司粒粒乾。", "雖是太平今有象，願陳七月述艱難。"]'),
('f54581cc-3a8a-4f55-8aec-2d903022683a','劭農三首  其二','吳潛','宋','宋诗','song-poetry','','[]','因見他鄉黍稷收，令人鄉思轉悠悠。',64,'全唐诗/poet.song.209000.json','["因見他鄉黍稷收，令人鄉思轉悠悠。", "新篘白酒雞豚社，旋摘絲蓴鱸雁洲。", "好處光陰長是客，老來情緒更逢秋。", "堯夫六十三休致，前輩風流可繼不。"]'),
('997cf33b-441b-44b8-9de9-5b7c8e655603','劭農三首  其三','吳潛','宋','宋诗','song-poetry','','[]','名園乘興小留連，洛社風光在眼前。',64,'全唐诗/poet.song.209000.json','["名園乘興小留連，洛社風光在眼前。", "突兀樓臺多占水，陰翳花竹小窺天。", "建封已去悲春燕，樊素何之咽暮蟬。", "人事廢興渾若此，憑欄對景一淒然。"]'),
('af7ee5e2-0e1e-4774-a52b-092745b97240','出郊用劭農韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','連檣載米去輸官，只得將爲樂土看。',64,'全唐诗/poet.song.209000.json','["連檣載米去輸官，只得將爲樂土看。", "餉互豚蹄秋願了，飽均雞犬午舂殘。", "門前掃刮犁鋤浄，屋上鋪添槀秸乾。", "識字田夫充長吏，了知圖易在思難。"]'),
('421a12f4-94ff-4ff1-8066-19c3eb85f298','出郊用劭農韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','水光山色盡兜收，老子穿林興尚悠。',64,'全唐诗/poet.song.209000.json','["水光山色盡兜收，老子穿林興尚悠。", "眼底有詩皆錦野，心頭無事即瀛洲。", "鷃鳩豈較物和我，蟪蛄何知春與秋。", "所謂人生行樂耳，如斯逝者可追不。"]'),
('8aecfc3a-a2ff-422c-b747-c4ad76f498fe','出郊用劭農韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','怕見書空雁字連，可堪清淚落尊前。',64,'全唐诗/poet.song.209000.json','["怕見書空雁字連，可堪清淚落尊前。", "謾因上澣休閑日，出見初秋瑩浄天。", "人正慕羶爭似蟻，誰能換骨蛻如蟬。", "細思回客吾徒爾，而我何爲獨不然。"]'),
('d144afcc-5b9a-443d-9c6d-23bdf5ca9f66','聞同官會碧沚用出郊韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','碧沚堂前瞰水官，只應喚作玉壺看。',64,'全唐诗/poet.song.209000.json','["碧沚堂前瞰水官，只應喚作玉壺看。", "頗聞秩秩玳筵展，莫遣匆匆銀燭殘。", "酒付別腸寧怕窄，詩由廣舌不憂乾。", "老夫孤坐三更月，欲往從之良獨難。"]'),
('35ff1fa6-e957-4ec6-a792-6bb6c5123a1d','聞同官會碧沚用出郊韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','萬頃蟾光浩不收，花汀竹嶼思悠悠。',64,'全唐诗/poet.song.209000.json','["萬頃蟾光浩不收，花汀竹嶼思悠悠。", "黄公所隠知何地，賀監宜歸乞此洲。", "良夜最佳惟午夜，今秋偏好是中秋。", "舉杯酒露月同吸，仰面青天可問不。"]'),
('ba9b3ce9-d810-454c-93e4-0e3efc133b13','聞同官會碧沚用出郊韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','暝色偏宜水色連，橫陳好景向尊前。',64,'全唐诗/poet.song.209000.json','["暝色偏宜水色連，橫陳好景向尊前。", "是人享用無遮月，誰子裝褫不染天。", "細閲人生幻泡影，了知世事雀螗蟬。", "賞心樂事休空擲，邂逅相逢不偶然。"]'),
('eac80017-554d-4e43-8a7d-f4ac90843773','出郊再用韻賦三解  其一','吳潛','宋','宋诗','song-poetry','','[]','此時尉候迭專官，木落郊空最好看。',64,'全唐诗/poet.song.209000.json','["此時尉候迭專官，木落郊空最好看。", "海檜不爲時節改，巖花未覺色香殘。", "明堂柱下捐樗散，清廟籩中薦豆乾。", "天地無私能物物，飛蚊終是負山難。"]'),
('61935860-5ab5-412e-b78a-6e162a682dcd','出郊再用韻賦三解  其二','吳潛','宋','宋诗','song-poetry','','[]','山朋水友訊頻收，怪我明農事轉悠。',64,'全唐诗/poet.song.209000.json','["山朋水友訊頻收，怪我明農事轉悠。", "南墅麋猿專一壑，東溪鳬鶩據三洲。", "人閒顛倒舟移夜，客裏淒涼坐閲秋。", "六十餘翁何所戀，金雞赦了可歸不。"]'),
('c7218ff9-efa2-46b0-9cea-9d9aac05a5ea','出郊再用韻賦三解  其三','吳潛','宋','宋诗','song-poetry','','[]','見說蓬瀛上界連，誰知只在眼睛前。',64,'全唐诗/poet.song.209000.json','["見說蓬瀛上界連，誰知只在眼睛前。", "但須牢踏脚根地，更要放開心裏天。", "世事可憐旋磨蟻，人情爭慕集冠蟬。", "若教禁臠曾知味，不似魚羹飯泰然。"]'),
('9bec2a8c-7ea2-496b-a84a-2c610fbc131f','出郊再用韻賦三解  其四','吳潛','宋','宋诗','song-poetry','','[]','平生慣作牧民官，不作朱幡畫戟看。',64,'全唐诗/poet.song.209000.json','["平生慣作牧民官，不作朱幡畫戟看。", "惟有寸心存惻隠，誰憐隻手補創殘。", "樹蔬人要畦畦潤，種麥農便隴隴乾。", "乍雨乍晴都恰好，老天誰道叫呼難。"]'),
('4115af23-7bbc-4956-9351-d704337772fc','出郊再用韻賦三解  其五','吳潛','宋','宋诗','song-poetry','','[]','空綃圖畫幾曾收，樓外蒼林遠更悠。',64,'全唐诗/poet.song.209000.json','["空綃圖畫幾曾收，樓外蒼林遠更悠。", "日莫羣烏投櫟社，天長數雁落蘆洲。", "爲諳世上空花景，最喜山中落葉秋。", "官事漸稀農事了，携壺挈榼可容不。"]'),
('8dd72e10-b977-4414-8ef6-20ac1e787975','出郊再用韻賦三解  其六','吳潛','宋','宋诗','song-poetry','','[]','水聚山環旺氣連，榮華富貴各攙前。',64,'全唐诗/poet.song.209000.json','["水聚山環旺氣連，榮華富貴各攙前。", "劫從無始認爲我，數到有終還是天。", "曉月園林空唳鶴，晚風亭樹謾鳴蟬。", "寄言世上耽迷者，所美當知非美然。"]'),
('6c0be0b9-541f-45f4-8494-95664518aef0','出郊再用韻賦三解  其七','吳潛','宋','宋诗','song-poetry','','[]','老大頭皮捉出官，轉頭重九又看看。',64,'全唐诗/poet.song.209000.json','["老大頭皮捉出官，轉頭重九又看看。", "莫愁客裏黄花負，只恐尊前白日殘。", "喜得賜封天燧息，願他入塞帝巴乾。", "豐年喜色眉尖上，一笑相携肯作難。"]'),
('3f6f128f-3cff-48f8-bc6e-113bfb45aba7','出郊再用韻賦三解  其八','吳潛','宋','宋诗','song-poetry','','[]','午香一縷篆煙收，欹枕方牀此景悠。',64,'全唐诗/poet.song.209000.json','["午香一縷篆煙收，欹枕方牀此景悠。", "便覺夢尋桃葉渡，不知身在菊花洲。", "簿書堆裏挨排日，砧杵聲中斷送秋。", "坏戶蟄蟲猶識候，人生知覺似渠不。"]'),
('c55adf9b-08dc-4b51-87ab-9e0f15f902be','出郊再用韻賦三解  其九','吳潛','宋','宋诗','song-poetry','','[]','窗草池蓮樂意連，一帆直到太虛前。',64,'全唐诗/poet.song.209000.json','["窗草池蓮樂意連，一帆直到太虛前。", "拈來瓦礫無非道，觸處鳶魚共此天。", "鶉固珍羞元是鼠，蜣雖穢物却爲蟬。", "神奇臭腐相更禪，妙理誰知所以然。"]'),
('0404f44e-d6d9-4056-b4a0-d1b9a7468249','再用出郊韻似延慶老三首  其一','吳潛','宋','宋诗','song-poetry','','[]','菩提只在攝心官，日觀元同月觀看。',64,'全唐诗/poet.song.209000.json','["菩提只在攝心官，日觀元同月觀看。", "萬種因緣都是結，一花根蒂幾曾殘。", "祖師曾誓瘡膿壞，講主能參屎橛乾。", "百碩麻油攤樹上，得來元不見難難。"]'),
('51ba4de7-edd6-4226-8eb7-1158817fdd0b','再用出郊韻似延慶老三首  其二','吳潛','宋','宋诗','song-poetry','','[]','工夫全在放時收，鷂過新羅路太悠。',64,'全唐诗/poet.song.209000.json','["工夫全在放時收，鷂過新羅路太悠。", "世網愛河千渤泡，人寰苦海一浮洲。", "要知坐卧并行住，只在春冬與夏秋。", "昨日亭前柏樹子，分明說法聽聞不。"]'),
('5f1b0c99-4364-496d-82de-b10dcb38288b','再用出郊韻似延慶老三首  其三','吳潛','宋','宋诗','song-poetry','','[]','普殊難葉一鈎連，勘到釋迦文佛前。',64,'全唐诗/poet.song.209000.json','["普殊難葉一鈎連，勘到釋迦文佛前。", "口裏巴巴緣十地，眼中盼盼是諸天。", "泥涂爛處藏頭鼈，高樹梢頭脫殻蟬。", "各自身軀各自性，誰知各自本同然。"]'),
('c6236e18-8088-4fa8-8c9f-57d425d73ba5','登延慶佛閣用出郊韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','東西南北幸同官，休作班荆解后看。',64,'全唐诗/poet.song.209000.json','["東西南北幸同官，休作班荆解后看。", "一笑喜逢粳秫賤，相攀莫待菊茱殘。", "沙鷗點點投波沒，簷鵲聲聲带日乾。", "美景良辰同賞樂，四并誰道古來難。"]'),
('17864036-6837-457b-ae1e-57407a7b2b9d','登延慶佛閣用出郊韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','高閣都將萬象收，凭欄睇望興何悠。',64,'全唐诗/poet.song.209000.json','["高閣都將萬象收，凭欄睇望興何悠。", "張郎遯世誰家谷，孫子成仙何處洲。", "風雨喜無臨九日，江山幸有答三秋。", "年豐市井多歡笑，老子婆婆亦可不。"]'),
('b8e02af7-c080-44d0-873a-015fb0373ab3','登延慶佛閣用出郊韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','遠峰近嶂似環連，擁翠排青到面前。',64,'全唐诗/poet.song.209000.json','["遠峰近嶂似環連，擁翠排青到面前。", "可聖可賢桑落酒，不寒不暖菊花天。", "吐吞湖海酎金兕，批判煙雲揮玉蟬。", "此客坐中應不欠，逢場何惜一跫然。"]'),
('08650086-047b-46f7-9a35-55181cae8cc9','再用出郊韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','父老休驚作長官，只將田畯一般看。',64,'全唐诗/poet.song.209000.json','["父老休驚作長官，只將田畯一般看。", "汝應西墅功將畢，我亦南柯夢向殘。", "夕照拖雲楓影亂，秋風掃地葉聲乾。", "瀛仙島客知何處，策杖相從正不難。"]'),
('e747e92e-837f-4769-89bd-6d2cea035c2d','再用出郊韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','遠山空處斷雲收，一段秋光野思悠。',64,'全唐诗/poet.song.209000.json','["遠山空處斷雲收，一段秋光野思悠。", "鷹隼不妨侵碧落，魚鳬自覺得滄洲。", "桑榆晚景能多日，桂菊他鄉又一秋。", "聊把清尊澆眊矂，茲遊還可再尋不。"]'),
('5ede7e14-c1e9-4be6-ad49-7e2812f227e9','再用出郊韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','屈曲蜂房蟻戶連，秦箏羯鼓綠窗前。',64,'全唐诗/poet.song.209000.json','["屈曲蜂房蟻戶連，秦箏羯鼓綠窗前。", "儘教迫窄無餘地，誰道虛空有剩天。", "是處畫堂餘燕雀，幾家高屋畫貂蟬。", "閑階細草蛩聲急，極目煙波正渺然。"]'),
('c57fd2ce-3458-497e-8010-deeb480b7224','三用出郊韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','從來此地出高官，綺屋連雲畫裏看。',64,'全唐诗/poet.song.209000.json','["從來此地出高官，綺屋連雲畫裏看。", "十里湖光多樣好，百年人事幾回殘。", "菰蒲带露枝猶溼，䆉稏逢晴把便乾。", "樂歲何妨歌樂職，簿書纏縛敢辭難。"]'),
('b93f2f57-6934-4017-9c09-72f1e3cd3980','三用出郊韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','高橋第一戰功收，從此江沱歲月悠。',64,'全唐诗/poet.song.209000.json','["高橋第一戰功收，從此江沱歲月悠。", "顧我壯懷成槁木，令人老淚落荒洲。", "西風何處雞豚社，東里此時魚蟹秋。", "一笑回頭便今古，賞心樂事可重不。"]'),
('2432df87-2291-4d30-b03a-b49d7dccd88c','三用出郊韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','金屋無人喚阿連，碧桐依舊綠階前。',64,'全唐诗/poet.song.209000.json','["金屋無人喚阿連，碧桐依舊綠階前。", "境瞞眼處非關物，事換頭時即是天。", "秋水岸邊凝鵲鷺，晚風枝上沸蜩蟬。", "靜中閲動渾如此，描畫何須倩巨然。"]'),
('4353202f-8e45-41ca-af5b-4063666dc97a','四用出郊韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','慚愧曾尸一品官，如今已作倒盆看。',64,'全唐诗/poet.song.209000.json','["慚愧曾尸一品官，如今已作倒盆看。", "但干馳逐心都歇，只有登臨興未殘。", "欲掃雲煙憂筆禿，擬澆塵土怕壺乾。", "傍人莫把衰翁笑，追趁躋攀尚不難。"]'),
('f4c36e6e-5786-479e-a313-465e7098b8e0','四用出郊韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','四望青山宿霧收，白鷗浩蕩意悠悠。',64,'全唐诗/poet.song.209000.json','["四望青山宿霧收，白鷗浩蕩意悠悠。", "紅旗不用穿三市，畫舸何妨訪十洲。", "臺榭裝成多樣景，水雲占却幾分秋。", "洛陽耆舊名園記，般入明州志可不。"]');
